INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rustic Ale', 'GRAIN', 6.9, 75.0, 0.0, 'Double Eagle Malt', 'US', 'Pale Ale malt from 2-Row barley, Rustic is kilned slightly higher than commercial pales to improve flavor and body in finished products. The cereal, slightly nutty flavors are complex and aromatic.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Legacy Wheat', 'GRAIN', 4.9, 75.0, 0.0, 'Double Eagle Malt', 'US', 'Pale wheat malt made from Pennsylvania hard red winter wheat is a light, smooth malt. Adds a slightly sweet, cereal flavor, and promotes yeast activity and contributes mouthfeel and head retention.', 0.0, 0.0, 0.0, 0.0);
