INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Vienna', 'GRAIN', 11.8, 75.0, 0.0, 'Double Eagle Malt', 'US', 'This sweet 2-Row malt has flavors of lightly toasted bread and works well as a base malt or as an an addition to provide a rich aromatic malt profile.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Munich', 'GRAIN', 19.7, 75.0, 0.0, 'Double Eagle Malt', 'US', 'Our traditional 2-Row Munich delivers an amber color and flavors of chewy bread, light toast, and crackers. Adds a deep, slightly sweet malt character to any beer.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Aromunich', 'GRAIN', 78.8, 75.0, 0.0, 'Double Eagle Malt', 'US', 'A unique aromatic, dark Munich that adds light sweetness, deep cracker flavors and amber color without harsh roast taste. Available from 2-Row barley.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Golden', 'GRAIN', 49.3, 75.0, 0.0, 'Double Eagle Malt', 'US', 'Lightly toasted traditional Munich. An excellent addition in moderation, it contributes body/depth and toasty bicuit flavors along with a beautiful copper color.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Dextrin', 'GRAIN', 23.6, 75.0, 0.0, 'Double Eagle Malt', 'US', 'Our 2-Row dextrin malt, made from barley grown on family farms in Pennsylvania and New Jersey, delivers a wonderful golden color and a touch of honey. Also improves body, mouthfeel and head retention.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Caramel 70', 'GRAIN', 147.8, 75.0, 0.0, 'Double Eagle Malt', 'US', 'Medium crystal malt contributes notes of toffee and toasted sugar. Available from 2-Row barley.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Caramel Rye', 'GRAIN', 128.1, 75.0, 0.0, 'Double Eagle Malt', 'US', 'Medium caramel made from winter rye grown on Pennsylvania family farms. Notes of dried plums and raisins. You can eat it like candy (no husk!). Inquire about availability.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Cocoa', 'GRAIN', 443.3, 75.0, 0.0, 'Double Eagle Malt', 'US', 'Our signature chocolate is roasted a bit lighter than commercial examples contributing smooth roasty chocolate flavors without bitterness or astringency. Available from 2-Row barley, wheat or rye.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Cocoa Dark', 'GRAIN', 689.5, 75.0, 0.0, 'Double Eagle Malt', 'US', 'Traditional dark roasted chocolate malt contributes rich, roasty, chocolate flavor. Perfect for stouts or other dark beer styles. Available from 2-Row barley, wheat or rye.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Black Magic', 'GRAIN', 1083.5, 75.0, 0.0, 'Double Eagle Malt', 'US', 'Black roasted malt made from Pennsylvania hard red winter wheat. Adds significant color with less roastiness than husked grains which retain astringency.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Pale Malt', 'GRAIN', 5.4, 75.0, 11.5, 'Gambrinus Malting', 'Canada', 'Our plump 2-row European-style pale ale malt is the base for all beers, and is processed from premium Canadian 2-row barley. Gambrinus Pale Malt is known for its fresh barley and bready character with background notes of biscuit, grain, honey, and hints of nutty and green tea flavor. Use for styles where a rich malt flavor can be shown off, or where a strong malt backbone is needed to balance other strong flavors – IPA, pale ale, brown ale, golden ale, or Scottish and Belgian ales. ', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Organic Pale Malt', 'GRAIN', 5.4, 75.0, 11.5, 'Gambrinus Malting', 'Canada', 'Our plump 2-row European-style pale ale malt is an outstanding base for any craft beer. Processed from premium Canadian 2-row barley. Gambrinus Organic Pale Malt is known for its honey and bready character with background notes of fresh barley, grain, brown sugar, green tea, and graham cracker. Use for styles where a rich malt flavor can be shown off, or where a strong malt backbone is needed to balance other strong flavors – IPA, pale ale, brown ale, golden ale, or Scottish and Belgian ales. ', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus BC Pale Malt', 'GRAIN', 5.4, 75.0, 11.5, 'Gambrinus Malting', 'Canada', 'Made from British Columbia-grown barley, this 2-row European-style pale ale malt is an outstanding base for craft brewers and distillers everywhere. With its characteristic blend of mellow fresh grain, sweet cookie, bread, honey, green tea, and graham cracker flavors, this region-specific malt adds a sense of place to any North American craft ale or malt whisky. ', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus ESB Pale Malt', 'GRAIN', 8.1, 75.0, 13, 'Gambrinus Malting', 'Canada', 'Our ''Extra Special British'' Pale malt is malted for brewers seeking the unique flavor imparted by British Pale Malt. Gambrinus has modified its malting process to give you a distinctive malt traditionally found only on the British Isles. As you’d expect from the name, our ESB Pale Malt is ideal for authentic English-style bitter, pale ale, and IPA. With its robust bread, cereal, caramel, grain, honey, and nutty flavors, it also makes a great base for full-flavored styles like Scottish ales, Imperial IPA, American strong ale, old ale, or barley wine. ', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Pilsner Malt', 'GRAIN', 3.6, 75.0, 11.5, 'Gambrinus Malting', 'Canada', 'Processed from the finest Canadian two-row available, this very low protein base malt is versatile in a wide range of beer styles. Expect delicate flavors of fresh barley, grain, honey, and bread, along with distinctive nutty character and suggestions of vanilla when used as the base for classic Pilsner, Kölsch, pale lager, Belgian ale, session IPA, and blond ale; or as a portion of the grist for Hefeweizen or Witbier.', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Organic Pilsner Malt', 'GRAIN', 3.6, 75.0, 11.5, 'Gambrinus Malting', 'Canada', 'Processed from the finest Canadian 2-row available, this very low protein organic base malt is versatile in a wide range of organic beer styles. Expect delicate flavors of sugar cookie, grain, honey, and bread along with distinctive nutty character and suggestions of fresh barley when used as the base for classic Pilsner, Kölsch, pale lager, Belgian ale, session IPA, and blond ale; or as a portion of the grist for Hefeweizen or Witbier.', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Vienna Malt', 'GRAIN', 14.8, 75.0, 13, 'Gambrinus Malting', 'Canada', 'This mellow kilned malt is the missing link between a Pale and Munich malt. It is ideal for any amber beer, adding a balanced malty character with strong suggestions of honey, toffee, and caramel. Use at up to 100% for traditional Vienna, Märzen, and other amber beer styles, or as a smaller fraction of the grist to add cereal, biscuit, and toasty notes to pale ale or IPA, Kölsch and blonde ales, or Belgian styles. ', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Munich Light 10L', 'GRAIN', 32.1, 75.0, 13, 'Gambrinus Malting', 'Canada', 'Seeking a well-balanced malty beer?  This plump, sweet, and mellow Munich malt delivers impressions of toast, pretzel, toffee, and caramel, with nutty and cereal grain background notes. Ideal as the base malt for amber or red ales, Altbier, Scottish ales, and traditional Bavarian lagers; we also recommend small inclusions for pale ale, IPA, and other styles to intensify color and boost the perception of maltiness without the sweetness of caramel malt.', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Organic Munich Light 10L', 'GRAIN', 32.1, 75.0, 13, 'Gambrinus Malting', 'Canada', 'Seeking a well-balanced malty beer?  This plump, sweet and mellow Munich malt delivers impressions of bread crust, toast, pretzel, toffee, and caramel with woody background notes. Ideal as the base malt for organic versions of amber or red ales, Altbier, Scottish ales, and traditional Bavarian lagers; we also recommend small inclusions for pale ale, IPA, and other styles to boost the perception of maltiness without the sweetness of caramel malt.', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Munich Dark 30L', 'GRAIN', 92.1, 75.0, 13, 'Gambrinus Malting', 'Canada', 'A very deeply-kilned Munich malt that combines the color and flavor characteristics of roasted malt with the mellowness of Munich malt. As up to 30% of the grain bill for dark lagers, Altbier, Doppelbock, dark Belgian beers, and brown or red ales, Gambrinus Munich Dark 30L adds a gorgeous red color with notes of bread crust, toffee, brown sugar, caramel, cereal, and toast.', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Honey Malt', 'GRAIN', 65.4, 75.0, 13, 'Gambrinus Malting', 'Canada', 'Honey malt is the best description for European malt known as ''Brühmalz''. Its intense malty sweetness makes it perfect for any specialty beer. This highly versatile, multifaceted malt brings flavors of honey, bread crust, toast, pretzel, grain, and a hint of tartness. Great for adding depth and complexity to the malt profiles of styles like Märzen/Festbier, Bock, Dunkel, Altbier, Scottish ale, brown ale or mild ale, pale ale, and many more. ', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Wheat Malt', 'GRAIN', 5.4, 75.0, 16, 'Gambrinus Malting', 'Canada', 'Our plump, malted soft white wheat is of low protein. At an inclusion rate of up to 10%, Gambrinus Wheat Malt can be an additional source for body and head retention with minimal flavor contribution in any formulation. When it comprises a higher percentage of the grist for American wheat or blonde ales, Hefeweizens, or Witbiers, it imparts warm flavors reminiscent of bread, dough, and baked goods.', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Organic Wheat Malt', 'GRAIN', 5.4, 75.0, 14.5, 'Gambrinus Malting', 'Canada', 'Our plump, malted soft white wheat is of low protein. At an inclusion rate of up to 10%, Gambrinus Organic Wheat Malt can be an additional source for body and head retention with minimal flavor contribution in any formulation. When it comprises a higher percentage of the grist for American wheat or blonde ales, Hefeweizens, or Witbiers, it imparts warm flavors reminiscent of bread, dough, and baked goods.', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gambrinus Rye Malt', 'GRAIN', 8.1, 75.0, 11, 'Gambrinus Malting', 'Canada', ' Earthy and sweet cereal notes with mild spiciness and suggestions of toast and dough. ', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Ale Malt', 'GRAIN', 5.7, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'This is a base malt with a distinctly English character, suitable for many beer styles.', 3.5, 190, 130, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('American Ale Malt', 'GRAIN', 5, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Base malt for use in hop-forward beers.', 3.5, 200, 135, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Aurora Malt', 'GRAIN', 46, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Aurora Malt adds a rich malt flavour to beers.', 3, 170, 125, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Big O – Malted Oats', 'GRAIN', 4.38, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Big O- Malted oats are a great addition to use instead of a rolled or flaked product. Whole oats are fully modified and kilned to give a rich oat, nutty flavour. Big O -Malted Oats have a few great attributes that make a preferred product for Stouts and Hazy IPAs: They have a large, thick husk which greatly aids in sparging and run-off. They have much more flavour – kilned to enhance the nutty, oaty flavours and bring more to the table than a flaked product. They bring the same silky smoothness to a beer that a rolled oat will. Big O provides a better haze than rolled oats alone in your hazy IPAs. Some brewing notes: The oats and husk will absorb more water so be prepared to increase the amount of your strike water. Mix the oats with the barley during milling to help deliver an even crush.', 1.22, 0.0, 125.61, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Biscuit Malt', 'GRAIN', 80, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Add Biscuit Malt to impact a dry toasted biscuit flavour without adding much additional colour to the final beer.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Black Forest Rye Malt', 'GRAIN', 88, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Think of Shepherds Delight Malt, now open your mind to the possibility to brew a beer with the same great attributes that Shepherds Delight Malt offer (red colour, malty, currant and fruit cake flavours) using, And guess what, no one in the world produces anything like this malt, so you are you in for a treat.   Rye as the grain. The possibilities are huge. Add spiciness to Old Ales, add complexity to ESB, Pale Ales, you name it.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Brown Malt', 'GRAIN', 170, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Brown Malt imparts a rich dry biscuit, nutty, light roasted flavour and gives the beer a deep amber hue. ', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Chit Malt', 'GRAIN', 6, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'The term chit in malting represents the first stage of germination, where the barley has taken up enough moisture from steeping to start the magic process of turning starch into soluble sugars to feed the this adjuncts. The flavour impact in a beer is minimum with subtle green, grassy raw grain flavour. As Chit malts contain mostly high-molecular proteins and sugars and thus retain many of the green, grassy characteristics of raw grain. One of its main purposes is to improve the finished beer’s body and foam stability.   Malt. It will leave long protein chains in the malt that the yeast won’t be able to digest its entirely during fermentation. This malt is a good alternative for raw  particularly high level of inherent starter enzymes, which contribute significantly to improving the conversion of starch, thus increasing the yield. The reason that the Chit Malt can improve body and foam is due to the process of modification of the starches in the grain by the enzymes still in the early stages when we start kilning  yeast during fermentation. Chit malt has a', 10, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Light Chocolate Malts', 'GRAIN', 950, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Gladfield Light Chocolate Malt is a lighter version of our Dark Chocolate Malt. It is produced in a similar way but roasted to a lower temperature and has a lighter colour. This malt gives fantastic roasted and espresso coffee like flavours. A great addition to Stouts and Porters.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Dark Chocolate Malt', 'GRAIN', 1300, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Gladfield Dark Chocolate Malt is dark in colour and light on astringency due to our unique roasting technique. It has lovely coffee/chocolate aromas and is a big hit with Porter and Stout drinkers. This malt must be used fresh.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Light Crystal Malt', 'GRAIN', 50, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Adds mild sweet caramel flavours and body.', 6.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Medium Crystal Malt', 'GRAIN', 105, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Adds full sweet caramel flavours and body ', 6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Dark Crystal Malt', 'GRAIN', 200, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Adds a nutty bittersweet caramel flavour and body.', 6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Eclipse Wheat Malt', 'GRAIN', 1400, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', '1–2% for little to no flavour contribution, minor colour adjustment; 2–6% to add more colour with very smooth roasted coffee and chocolate notes; 7–10% in a larger ratio for more definite colour adjustment, roast character. velvety-smooth subtle', 2.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('German Pilsner Malt', 'GRAIN', 4, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Base malt for any beer style, light in colour with a clean sweet flavour.', 3.5, 250, 140, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gladfield Naked Oats', 'GRAIN', 2.8, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Our take on a well sought after type of malt. Our Golden Naked Oats is made from New Zealand dehulled oats, chitted and then roasted on our roaster “Gabriella”. This malt brings mouthfeel and creaminess to malt forward and hoppy beers, essentially any type of beer can benefit from some amount of Golden Naked Oats.', 4.6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gladiator Malt', 'GRAIN', 8, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'To provide extra foam stability, body and mouth feel to the brewed beer.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Go Nutty -Roasted Oats', 'GRAIN', 9.5, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Go Nutty – Roasted Oats is our newest malt, launched as a limited release in 2020. We used hulled oats which have been roasted in our drum roaster to a lightly nutty, toasted flavour while still retaining a It This malt is a great addition to Stouts, Porters and Brown Ale.  Resembles the flavour of toasted sesame seeds.  light colour in the mash. It could add spiciness to Saisons and Dubble beers too. ', 4.65, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Lager Light Malt', 'GRAIN', 2.7, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'A base malt for any style of beer. This malt is light in colour, with a sweet, clean flavour. ', 3.5, 250, 130, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Maize Malt', 'GRAIN', 2.5, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Maize Malt adds mild less malty flavour to beers. Provides a drier and crisper beer.', 6.28, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Manuka Smoked Malt', 'GRAIN', 3.9, 75.0, 0.0, 'Gladfield Malt', 'New Zealand', 'Suitable for single malt distilling and brewing where a unique Manuka smoke characteristic is required.', 3.8, 250, 135, 0.0);
