INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pilsner Malt', 'GRAIN', 4, 75.0, 11.5, 'Joe White Maltings', 'Australia', ' A light golden colour and smooth clean flavour make this malt a perfect base for any brew, but particularly Pale Ales, Pilseners and I&APAs.', 4.5, 200, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Traditional Ale Malt', 'GRAIN', 7, 75.0, 11.5, 'Joe White Maltings', 'Australia', 'Kilning at a slightly higher temperature than Pilsner Malt results in a slightly darker colour and fuller flavoured base malt, typically found in traditional English Ales.', 4.5, 200, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Vienna Malt', 'GRAIN', 10, 75.0, 11.5, 'Joe White Maltings', 'Australia', 'Kilned at a higher temperature than Pale and Ale malts but still retaining sufficient enzyme activity to be used as a base malt, Vienna imparts a light golden to orange colour and a distinctive nutty aroma.', 5, 150, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Light Munich Malt', 'GRAIN', 15, 75.0, 11.5, 'Joe White Maltings', 'Australia', 'Munich provides a more robust, malty flavour and rich golden colour than Vienna, adding depth and body without excessive sweetness.', 4.5, 150, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Dark Munich Malt', 'GRAIN', 20, 75.0, 11.5, 'Joe White Maltings', 'Australia', 'Munich provides a more robust, malty flavour and rich golden colour than Vienna, adding depth and body without excessive sweetness.', 4.5, 150, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Wheat Malt', 'GRAIN', 5, 75.0, 13, 'Joe White Maltings', 'Australia', 'Premium White Wheat is malted in the same way as barley and is used as a base malt in the production of classic wheat beers. At lower percentages of the grist, wheat malt can also be added to any number of beer styles to enhance foam stability and mouthfeel.', 5.5, 280, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Distillers Malt', 'GRAIN', 5, 75.0, 11.5, 'Joe White Maltings', 'Australia', 'Our Distillers Malt is specifically designed to provide the distiller of whiskys or spirits requiring a majority of raw grains with enough enzyme to convert the large amount of starch in those grain bills.', 5, 250, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Caramalt', 'GRAIN', 70, 75.0, 0.0, 'Joe White Maltings', 'Australia', 'The lightest of the crystal malts with its brilliant golden colour, Caramalt is valued for its full caramel flavour. Caramalt is made from green malt, but is roasted at lower temperatures and for a shorter time than typical Crystal Malt.', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Light Crystal Malt', 'GRAIN', 140, 75.0, 0.0, 'Joe White Maltings', 'Australia', 'With colour varying from a light, honey shade to a deep gold depending on the length of the final roasting stage, Joe White Maltings’ Crystal Malt provides sweet caramel and toffee flavours, as well as contributing to body, foam stability and storage capabilities of beer.', 5.5, 0.0, 0.0, 0.0);
