INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Crystal Wheat Malt', 'GRAIN', 150, 75.0, 0.0, 'Joe White Maltings', 'Australia', 'Producing beautiful dark golden tones, Crystal Wheat Malt provides a smooth nutty profile with mild notes of caramel and biscuit. Used to enhance foam retention and mouthfeel while providing a clean finish to any beer style.', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Amber Malt', 'GRAIN', 70, 75.0, 0.0, 'Joe White Maltings', 'Australia', 'The lightest of the roasted malts, with a biscuity flavour and a subtle ochre colour.', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Chocolate Malt', 'GRAIN', 800, 75.0, 0.0, 'Joe White Maltings', 'Australia', 'Chocolate Malt is a lightly roasted product with subtle notes of coffee, cocoa and chocolate and a rich brown colour.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Light Roasted Malt', 'GRAIN', 1000, 75.0, 0.0, 'Joe White Maltings', 'Australia', 'Roasted malts have varying colour and flavour profiles depending on the temperature and length of the final roasting stage, but will generally impart a smooth roasted flavour without excessive bitterness. Roasted malts can be used in dark beers for flavour or used in small quantities in all styles for colour correction.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Dark Roasted Malt', 'GRAIN', 1400, 75.0, 0.0, 'Joe White Maltings', 'Australia', 'Roasted malts have varying colour and flavour profiles depending on the temperature and length of the final roasting stage, but will generally impart a smooth roasted flavour without excessive bitterness. Roasted malts can be used in dark beers for flavour or used in small quantities in all styles for colour correction.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Black Malt', 'GRAIN', 1600, 75.0, 0.0, 'Joe White Maltings', 'Australia', 'The darkest of the roast products, providing a deep brown-black colour, Black Malt has a mild aroma while still providing a dry, bitter, burnt-coffee flavour.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Roasted Wheat Malt', 'GRAIN', 1600, 75.0, 0.0, 'Joe White Maltings', 'Australia', 'With a milder flavour than both Black Malt and Roasted Barley, Roasted Wheat Malt is used mainly for colouring and improving the body of dark beers.', 4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rosted Barley', 'GRAIN', 1600, 75.0, 0.0, 'Joe White Maltings', 'Australia', 'Roasted Barley provides a beautiful rich red-black colour and a slightly more astringent flavour than Black Malt.', 4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Gateway (Under-modified Wind-Malt)', 'GRAIN', 2.6, 75.0, 11.5, 'Mecca Grade Estate Malt', 'US', '“Wind-malt” is a long-forgotten style of Belgian malt that was allowed to air-dry in the lofts of barns. To our knowledge, it has never been produced commercially in North America. We’ve revived it with “Gateway,” a malt that is bursting with the aroma of fresh-cut hay while being nearly translucent in color. Gateway is perfectly-suited for decoctions, step mashing, and is the missing ingredient when brewing historic styles of beer.', 7.5, 684, 160, 660);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pelton (Pilsner Style)', 'GRAIN', 3.7, 75.0, 11, 'Mecca Grade Estate Malt', 'US', 'The perfect choice for creating premium lagers, light ales, farmhouse, and wild beer. Produces a complex, slightly grassy, and crisp wort through which our terroir is pronounced...rustic, yet refined.', 4.8, 684, 200, 80);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Lamonta (American Pale)', 'GRAIN', 6.5, 75.0, 11, 'Mecca Grade Estate Malt', 'US', 'The new standard for brewing pale ales and British specialty beers; Lamonta is a remarkable and complex North American craft malt that is golden, sweet, and slightly biscuity.', 4, 544, 200, 80);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Vanora (Vienna Style)', 'GRAIN', 14.4, 75.0, 11, 'Mecca Grade Estate Malt', 'US', 'For use in Vienna, Oktoberfest, and Marzen beers, Vanora is a high-kilned malt that is aromatically-rich, contributing slight walnut flavors and deep, golden hues to your beer.', 3.8, 404, 200, 60);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Metolius (Munich Style)', 'GRAIN', 24.2, 75.0, 11, 'Mecca Grade Estate Malt', 'US', 'Imparts a robust and warming malt profile that tastes exactly like a liquid, toasted, graham cracker. With a deep orange & brown color, this malt is the superior choice for brewing traditional styles like Bocks and Munich lagers.', 3.1, 229, 0.0, 60);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Opal 22 (Graham & Cocoa)', 'GRAIN', 49.3, 75.0, 11, 'Mecca Grade Estate Malt', 'US', 'Opal 22 packs in heaps of lightly-toasted, graham and chocolate flavor - just think: S’mores around the campfire minus the marshmallow. Use anywhere from 0-100% to add even more depth to your grain bill.', 3.1, 264, 200, 80);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Opal 44 (Toasted Toffee)', 'GRAIN', 98.5, 75.0, 11, 'Mecca Grade Estate Malt', 'US', 'Opal 44 is your next, secret ingredient. Sweet, moderately-toasted, with hints of chocolate and raisin; it’s wort is reminiscent of homemade almond roca. The typical usage rate is 2.5 - 5%, but at 44 DP, it can be used up to 100%.', 3, 159, 180, 80);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Shaniko (White Winter Wheat)', 'GRAIN', 8.5, 75.0, 12, 'Mecca Grade Estate Malt', 'US', 'The wait is finally over: our white winter wheat “Shaniko,” provides your beer a super-rich and creamy cloud of flavor. Perfect for hazy IPAs and wheat beers, Shaniko tastes like cookie dough right off the spoon.', 4.5, 509, 130, 70);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rimrock (Vienna-style Spring Rye)', 'GRAIN', 12, 75.0, 12.5, 'Mecca Grade Estate Malt', 'US', 'Grassy? Spicy? It’s time to toss those over-used flavor descriptors to the wayside and experience malted rye that is in a class of its own. Rimrock is gently-kilned to a rich orange hue and has a warm bread flavor with notes of graham and honey. This rustic malt has a slight aromatic and herbal character that will remind you of the High Desert frontier.', 4.7, 474, 220, 30);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Wickiup (Hard Red Spring Wheat)', 'GRAIN', 6.9, 75.0, 16.2, 'Mecca Grade Estate Malt', 'US', 'The missing link in creating classic wheat beers; Wickiup provides a deeply rich, "Cream of Wheat" wort with a hint of bread crust and brown sugar.', 4.5, 229, 100, 60);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Super Pale Ale Malt', 'GRAIN', 2, 75.0, 0.0, 'Muntons', 'UK', 'The light colour and clean flavour profile of Super Pale Ale Malt lend themselves to multiple beer styles. Using this exceptional malt, brewers can create extremely low colour beer with reddish and copper hues, a characteristic which also lends itself to the creation of vibrantly coloured fruit-beers. Here, the low colour of the malt allows the colour of the selected fruit of choice to really shine through. Super Pale Ale Malt is our lightest pale malt, and is ideally suited for IPA, bitter, golden ales, and light beers.', 6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pilsner Malt', 'GRAIN', 3.7, 75.0, 0.0, 'Muntons', 'UK', 'A further benefit of our Pilsner Malt is its high level of enzyme activity - both DP and DU. This will increase the speed of starch conversion and increase the attenuation levels of the beer. When brewing, we recommend mashing at 62 - 63°C for a traditional lager. Please keep the gelatinisation temperature of your crop in mind. For more information ask your usual Muntons sales contact.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Lager Malt', 'GRAIN', 4, 75.0, 0.0, 'Muntons', 'UK', 'A further benefit of our Pilsner Malt is its high level of enzyme activity - both DP and DU. This will increase the speed of starch conversion and increase the attenuation levels of the beer. When brewing, we recommend mashing at 62 - 63°C for a traditional lager. Please keep the gelatinisation temperature of your crop in mind. For more information ask your usual Muntons sales contact.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Planet - Pale Ale Malt', 'GRAIN', 6, 75.0, 0.0, 'Muntons', 'UK', 'Planet has a high yield and performs very well in the brewhouse. We recommend a mashing temperature of at least 65°C as this is the average gelatinisation temperature for this variety. Mashing at a lower temperature could cause a slow conversion or even stall as the starch might not fully gelatinise. Planet has a cereal-forward taste complemented with a mild nuttiness, imparted because of its slightly higher attenuation level. It has a lower ‘masking’ effect than Venture or Maris Otter® leading to an increase in the impact of aroma hops and yeast aromas. Care must be taken as this also means that any brewing errors are less easily covered. In our tests, Planet has performed very well and feedback from brewers using this variety has been very positive, particularly with extract levels and flavour profiles. This traditional pale malt is ideal for classic top fermented beers. Suitable for IPA’s, bitters, golden ales and light beers. Pale is slightly darker and “maltier” than lager malt, whilst the extra pale is similar in colour to lager malts but with pale malt qualities', 4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Planet – Extra Pale Ale Malt', 'GRAIN', 4, 75.0, 0.0, 'Muntons', 'UK', 'Planet has a high yield and performs very well in the brewhouse. We recommend a mashing temperature of at least 65°C as this is the average gelatinisation temperature for this variety. Mashing at a lower temperature could cause a slow conversion or even stall as the starch might not fully gelatinise. Planet has a cereal-forward taste complemented with a mild nuttiness, imparted because of its slightly higher attenuation level. It has a lower ‘masking’ effect than Venture or Maris Otter® leading to an increase in the impact of aroma hops and yeast aromas. Care must be taken as this also means that any brewing errors are less easily covered. In our tests, Planet has performed very well and feedback from brewers using this variety has been very positive, particularly with extract levels and flavour profiles. This traditional pale malt is ideal for classic top fermented beers. Suitable for IPA’s, bitters, golden ales and light beers. Pale is slightly darker and “maltier” than lager malt, whilst the extra pale is similar in colour to lager malts but with pale malt qualities', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Craft - Pale Ale Malt', 'GRAIN', 6, 75.0, 0.0, 'Muntons', 'UK', 'Craft is an excellent choice for malty and high-alcohol beers like old ale, strong ales, barley wine, American and British-style amber ales, porters, or stouts. In New England IPAs where a superior malt backbone is desired, Craft is a great choice. Craft’s underlying flavour pairs nicely with London III and Vermont Ale yeasts. It works exceedingly well in malt-forward Blonde Ales that are popular with drinkers new to craft beer. Use this malt with light-coloured specialty malts like Amber Malt and/or Caramalt 30 in a beer with less than 25 IBUs to make an approachable, entry-level Blonde Ale.', 4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Maris Otter® - Pale Ale Malt', 'GRAIN', 6, 75.0, 0.0, 'Muntons', 'UK', 'Brewers looking for extra malt flavour, should consider this traditional malt; this British staple – Maris Otter®. Introducing strong cereal, biscuit and nutty notes in beer, Maris Otter® remains one of the most popular malt varieties available for the serious craft brewer.', 4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Maris Otter® - Extra Pale Ale Malt', 'GRAIN', 4, 75.0, 0.0, 'Muntons', 'UK', 'Brewers looking for extra malt flavour, should consider this traditional malt; this British staple – Maris Otter®. Introducing strong cereal, biscuit and nutty notes in beer, Maris Otter® remains one of the most popular malt varieties available for the serious craft brewer.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Maris Otter® - Pale Blend Malt', 'GRAIN', 6, 75.0, 0.0, 'Muntons', 'UK', 'Brewers looking for extra malt flavour, should consider this traditional malt; this British staple – Maris Otter®. Introducing strong cereal, biscuit and nutty notes in beer, Maris Otter® remains one of the most popular malt varieties available for the serious craft brewer.', 4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Organic Ale Malt', 'GRAIN', 10, 75.0, 0.0, 'Muntons', 'UK', 'We are a member of the Organic Food Federation and ensure that the organic malting barley and the products we make are fully compliant with their guidelines. Our organic malts provide an ideal base for the brewer looking to brew a quality organic beer. As organic malting barley is grown under completely natural conditions the specification may well vary more widely than barley grown using accepted traditional methods, where fertilisers and pesticides may well have been used.   ', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Mild Malt', 'GRAIN', 7, 75.0, 0.0, 'Muntons', 'UK', 'Mild Malt is a great base material for no and low alcohol beer. Also, when used in conjunction with our Cara Malt 10 and our innovative new Muntons Sour Malt Extract, we were able to develop a perfectly  balanced and very drinkable 0.5% ABV Ale. Muntons Mild Malt is ideal for mild ales, stouts and porters. It is slightly sweeter than pale malt and safe to use with high ratios of adjuncts', 4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Dextrin Malt', 'GRAIN', 7, 75.0, 0.0, 'Muntons', 'UK', 'Dextrin malt shows its strength in highly attenuated beers such as Lagers, Brut IPAs, Saisons and Wild fermentations. The high percentage of dextrins and complex sugars add a depth to these beer styles preventing beers becoming too thin or too dry. Try a modest inclusion of 2-3%, and see for yourself how it can enrich your beer.', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Munich Malt', 'GRAIN', 20, 75.0, 0.0, 'Muntons', 'UK', 'Suitable for any beer giving fuller body and rich toasted, biscuit and bready flavours', 8, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Vienna Malt', 'GRAIN', 12, 75.0, 0.0, 'Muntons', 'UK', 'Suitable for lagers and continental beers, in between Pale and Munich, golden and full bodied.', 8, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Cara Malts 10', 'GRAIN', 12, 75.0, 0.0, 'Muntons', 'UK', 'Highly attenuated beers such as Lagers, Brut IPAs, Saisons and Wild fermentations really benefit from the inclusion of some Cara Malt 10, as the high percentage of dextrins and complex sugars bring a depth to these beer styles reducing the chance that the beer might be too thin or too dry. Just a small inclusion of 2 - 3% is ideal', 8, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Cara Malts 30', 'GRAIN', 43, 75.0, 0.0, 'Muntons', 'UK', 'Cara Malt 30 has a slightly darker and more intense flavour profile than Cara Malt 10. It is suitable for IPA, bitter, mild, stout, porters and golden ales. The colour is golden offering a toffee/caramel flavour.', 8, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Crystal Malts 110', 'GRAIN', 110, 75.0, 0.0, 'Muntons', 'UK', 'Suitable beers include IPA, bitter, mild, stouts and porters. Copper/red/amber in colour with sweet toffee, biscuit, nutty, malty flavours that increase as colour increases. Starches are crystallised', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Crystal Malts 150', 'GRAIN', 150, 75.0, 0.0, 'Muntons', 'UK', 'Suitable beers include IPA, bitter, mild, stouts and porters. Copper/red/amber in colour with sweet toffee, biscuit, nutty, malty flavours that increase as colour increases. Starches are crystallised', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Crystal Malts 240', 'GRAIN', 240, 75.0, 0.0, 'Muntons', 'UK', 'Suitable beers include IPA, bitter, mild, stouts and porters. Copper/red/amber in colour with sweet toffee, biscuit, nutty, malty flavours that increase as colour increases. Starches are crystallised', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Crystal Malts 400', 'GRAIN', 400, 75.0, 0.0, 'Muntons', 'UK', 'Suitable beers include IPA, bitter, mild, stouts and porters. Copper/red/amber in colour with sweet toffee, biscuit, nutty, malty flavours that increase as colour increases. Starches are crystallised', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Amber Malt', 'GRAIN', 75, 75.0, 0.0, 'Muntons', 'UK', 'Suitable beer styles include Mild, Bitter, Ales, IPA, Brown Ale, Stout, Porter. Straw/golden in colour with nutty light toast flavours.', 3, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Brown Malt', 'GRAIN', 170, 75.0, 0.0, 'Muntons', 'UK', 'Suitable beer styles include Mild, Bitter, Ales, IPA, Brown Ale, Stout, Porter. Brown/dark amber in colour offering coffee, roast, strong toast flavours.', 3, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Light Chocolate Malt', 'GRAIN', 440, 75.0, 0.0, 'Muntons', 'UK', 'Suitable beer styles include Mild, Bitter, Ale, IPA, Brown Ale, Stout, Porter', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Chocolate Malt', 'GRAIN', 1200, 75.0, 0.0, 'Muntons', 'UK', 'Suitable beer styles include Mild, Bitter, Ale, IPA, Brown Ale, Stout, Porter.  Dark brown/ruby colour, offering burnt coffee/chocolate bean and bitternes', 6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Black Malt', 'GRAIN', 1400, 75.0, 0.0, 'Muntons', 'UK', 'Suitable beer styles include Mild, Bitter, Ales, IPA, Brown Ale, Stout, Porter. ', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Roasted Barley', 'GRAIN', 1500, 75.0, 0.0, 'Muntons', 'UK', 'Beer styles include Mild, Bitter, Ales, IPA, Brown Ale, Stout, Porter. ', 6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Wheat Malt ', 'GRAIN', 5, 75.0, 0.0, 'Muntons', 'UK', 'Wheat Malt is a great addition to any beer requiring a boost in mouthfeel or head retention. This malt is also superb in in Belgian, American and German wheat beer applications. Inclusion can be up to 55% as long as the mash and sparge are adjusted to account for the husk, missing from wheat..', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Melanoidin Wheat Malt', 'GRAIN', 120, 75.0, 0.0, 'Muntons', 'UK', 'Melanoidin Wheat Malt is one of our newer malts. This highly kilned wheat malt is made using a unique kilning profile and is able to add all the protein related benefits of a wheat malt while also adding the colour and flavour of dark Munich and amber style malts.', 6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rye Malt', 'GRAIN', 7, 75.0, 0.0, 'Muntons', 'UK', 'Rye Malt adds a nutty and fruity quality to beers and will significantly increase the mouthfeel when used at high rates. Due to its lack of husk, Rye Malt must be treated in the same way as wheat malt to ensure there are no run-off issues during brewing.  This malt shines in IPAs, golden ales and rye variants of traditional beer styles', 5.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Oat Malt', 'GRAIN', 10, 75.0, 0.0, 'Muntons', 'UK', 'Oat Malt will give the beer typical oat flavours reminiscent of breakfast porridge. The product has high levels of fatty acids which enable this malt to add a fine and stable haze to beers without having to reach for un-malted adjuncts. The protein structure of the oats add a creamy mouthfeel to beers. The strong husk on oat malt enables high inclusions without causing any processing issues.', 6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Torrefied Wheat', 'GRAIN', 6, 75.0, 0.0, 'Muntons', 'UK', 'Adding torrefied wheat to a brew at 2-5% is a well known and reliable way of adding a complex protein matrix to your beer whilst maintaining stable head formation and retention. With the rise of the NEIPA, hazy and smooth beer is becoming more popular. We thought it would be really interesting to try out our torrefied wheat in a NEIPA and it worked really well. At an inclusion of 15- 20% we achieved a stable haze and a solid mouthfeel that pair perfectly with a citrussy hop addition.', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Dark Crystal Rye Malt', 'GRAIN', 230, 75.0, 0.0, 'Muntons', 'UK', 'We offer a wide range of speciality malts ranging from low colour crystals to highly roasted black malts. One of the more unusual amongst our wide range of speciality malts is Dark Crystal Rye Malt which is a particular favourite of ours. It has a colour of 230 EBC so if you want a red colour to your beer this malt is the answer. The addition of 10 - 15% to a pale base will introduce a lovely red hue to your beer. This highly aromatic, caramelised rye is perfect for adding breadcrust notes and bringing a touch of sweetness to any recipe. When incorporated in the grist at high inclusion rates, it delivers flavours reminiscent of hazelnut and toffee. When used in conjunction with extra low colour Ale Malts such as our Super Pale they balance perfectly, as they allow more of the intense copper colour to shine through.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pilsen Malt', 'GRAIN', 5, 75.0, 0.0, 'Patagonia Malt', 'Chile', 'This is the malt we´ve been elaborating for the longest time. It is the base of German influence in our beer culture. Excellent choice for lagers and light ales.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Extra Pale Malt', 'GRAIN', 0.0, 75.0, 0.0, 'Patagonia Malt', 'Chile', 'This malt was developed for craft beer, searching for versatility and unique features. It produces a beer with more character and body, less foam and creamy sensation in mouth.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Caramel 15L / 40EBC', 'GRAIN', 40, 75.0, 0.0, 'Patagonia Malt', 'Chile', NULL, 0.0, 0.0, 0.0, 0.0);
