INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Patagonia Pale Ale', 'GRAIN', 7.5, 75.0, 0.0, 'Patagonia Malt', 'Chile', 'Patagonia Pale ale malt is a light‐colored base malt, is a two‐row malt produced using a specialized kilning process in order to create a fully modified malt appropriate to use as base malt in any beer style. Our malt gives nutty and biscuit flavors while contributing a rich golden hue. Use up to 100% in all beer styles.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Patagonia Munich', 'GRAIN', 35, 75.0, 0.0, 'Patagonia Malt', 'Chile', 'An excellent choice for amber and darker beers. The Munich Malt flavor tends to be a deep, malty, grainy that may also be described as slightly roasty.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Patagonia Wheat Malt', 'GRAIN', 5, 75.0, 0.0, 'Patagonia Malt', 'Chile', 'Patagonia Wheat Malt is made of 100% Chilean wheat, it adds low color and special flavors to wheat based beer styles. It is possible to notice a robust-sweet flavor, with nuts notes.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Patagonia Vienna', 'GRAIN', 7.5, 75.0, 0.0, 'Patagonia Malt', 'Chile', 'An excellent choice for Pilsner, Vienna or Märzen beers. Is a rich, aromatic malt that will lend a light amber to deep orange color, a warm malty flavor, and some body. For heavily-hopped beers adds a great degree of malt character without overshadowing the highlighted hops.', 0.0, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr High DP Distillers Malt', 'GRAIN', 5.9, 75.0, 0.0, 'Rahr Malting Co', 'US', 'Rahr distillers malt is processed using North American barley. The malt is processed to maximize the enzymatic activity to provide the needed functionality for the distiller. This product is extremely high in diastatic power and alpha amylase along with high levels of FAN for yeast nutrition.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr North Star Pils™', 'GRAIN', 3.7, 75.0, 12, 'Rahr Malting Co', 'US', 'A base malt to set your compass by! Rahr North Star Pils™ is crafted to meet the requirements of brewers looking for a domestic pilsner malt with low color and low modification. It is malted to a target of 38-40° Kolbach to facilitate smooth lautering with any mash regimen.  ', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr Old World Pilsner', 'GRAIN', 3.9, 75.0, 11.5, 'Rahr Malting Co', 'US', 'Rahr Old World Pilsner is special because it doesn''t germinate as quickly as other domestic two-rows which means that more of the insoluble protein is left in the kernel. In this, the malt is giving up some extract but delivers greater flavor, yeast nutrients, and some beer foam stability in return. Also, this malt is lower in DP which means that when step-mashing some starch will convert in the higher temperature range.', 4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr Pale Ale', 'GRAIN', 7.9, 75.0, 12, 'Rahr Malting Co', 'US', 'Rahr Pale Ale is an ale-style base malt made from a blend of North American 2-row barleys. It has an excellent color, slightly darker than Rahr Standard or Pilsner malts, good malt flavor, and high extract yield. Well suited to American, English or continental ales, Rahr Pale Ale has become a popular base malt for almost any style of beer.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr Premium Pilsner', 'GRAIN', 3.9, 75.0, 11, 'Rahr Malting Co', 'US', 'Rahr Premium Pilsner is an lager-style base malt made from premium North American 2-row barley. Its light color, neutral flavor, and low protein content make Premium Pilsner an excellent choice for brewing clear, clean-tasting lagers.', 4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr Red Wheat', 'GRAIN', 6.9, 75.0, 12, 'Rahr Malting Co', 'US', 'Rahr Red Wheat is a pale wheat malt made from North American hard spring red wheat. Pale wheat malt has the sweet malty flavor of other malted grains, but with a hint of fruitiness. Wheat malts are high in protein, which helps produce fuller-bodied beers. Wheat malt can improve head formation and retention, depending upon the other grist constituents. Red wheat has a slight tartness to its flavor not present in white wheat. It also has smaller, harder kernels than white wheat, which can require careful milling. Rahr Red Wheat is suitable for all wheat-style beers.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr Standard 2-Row', 'GRAIN', 3.9, 75.0, 11.5, 'Rahr Malting Co', 'US', 'Rahr Standard 2-Row is a light-colored base malt made from a blend of North American 2-Row barley varieties. It is darker than most lager malts, but lighter than most pale ale malts. It has moderate protein levels, and good extract yield. Its neutral characteristics make it extremely versatile, and it is widely used by North American craft breweries as their standard base malt for any beer style.', 4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr Standard 6-Row', 'GRAIN', 4.9, 75.0, 12, 'Rahr Malting Co', 'US', 'Rahr Standard 6-Row is a light-colored base malt made from a blend of North American 6-Row barley varieties. 6-row barley has a much higher protein content and enzymatic power than 2-row barley. Inclusion of Standard 6-Row is therefore very advantageous for recipes calling for large proportions of specialty malts, wheat malts, or adjuncts, which have little or no enzymatic power themselves. 6-row barley is also used to match historical beer styles from settings where 2-row barley was not widely available. High proportions of 6-row barley may necessitate the use of adjuncts or require protein rests in mashing.', 4.2, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr Unmalted Wheat', 'GRAIN', 7.9, 75.0, 11.5, 'Rahr Malting Co', 'US', 'Rahr Unmalted Wheat is a raw wheat grain. Unmalted Wheat has a strong grain flavor, and a very light straw color. It is used in many traditional Belgian styles to add flavor and cloudiness, and improve head formation. The starch in raw grain is not gelatinized and the protein content is high. Depending upon use, a cereal mash and/or protein rest may be required.', 12, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr White Wheat', 'GRAIN', 6.9, 75.0, 12, 'Rahr Malting Co', 'US', 'Rahr White Wheat is a pale wheat malt made from North American soft winter white wheat. Pale wheat malt has the sweet malty flavor of other malted grains, but with a hint of fruitiness. Wheat malts are high in protein, which helps produce fuller-bodied beers. Wheat malt can improve head formation and retention, depending upon the other grist constituents. White wheat is easier to mill than red wheat, and more conducive to the haze characteristic of Belgian white beers. Rahr White Wheat is suitable for all wheat-style beers.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr Kilned Caramel 30', 'GRAIN', 69, 75.0, 13.5, 'Rahr Malting Co', 'US', 'Rahr Kilned Caramel malts give your beer color, aroma, flavor, and body, but without the prominent sweetness of drum-roasted caramel malts. Our Kilned Caramel 30 adds rich golden-red color and notes of bread, honey, and caramel.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr Kilned Caramel 47', 'GRAIN', 98.5, 75.0, 13.5, 'Rahr Malting Co', 'US', 'Rahr Kilned Caramel malts give your beer color, aroma, flavor, and body, but without the prominent sweetness of drum-roasted caramel malts. Our Kilned Caramel 47 is named in honor of 1847, the year William Rahr founded our company. It imparts bronze-red color and nutty, grainy, and mild caramel notes. ', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Rahr Kilned Caramel 80', 'GRAIN', 177.3, 75.0, 13.5, 'Rahr Malting Co', 'US', 'Rahr Kilned Caramel malts give your beer color, aroma, flavor, and body, but without the prominent sweetness of drum-roasted caramel malts. Our Kilned Caramel 80 brings deep red-amber color along with nutty, caramel, bread crust, and grainy character. ', 4.5, 0.0, 0.0, 0.0);
