INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pilsen malt', 'GRAIN', 4, 75.0, 10.9, 'Sekado', 'Czech Republic', 'The standard base for producing Pilsner and Lager type beers. Excellent in many lighter styles such as Pilsner and Lagers. Base for authentic “Czech beer style” such as Bohemian Pilsner.', 5, 0.0, 145, 74);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Vienna malt', 'GRAIN', 10, 75.0, 11.3, 'Sekado', 'Czech Republic', 'Is most frequently used in the production of European style golden brown lagers and also and for all Vienna Beer Style, particularly Eastern European and German style beers, and brings out a pleasant malty taste.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Munich malt', 'GRAIN', 25, 75.0, 11.3, 'Sekado', 'Czech Republic', 'To enhance body and aroma of dark beers, such as Pilsner and Bavarian Dark. Based on its strong flavor and the characteristic color, this malt is mainly used for producing dark beers. Golden orange hue with an intensly malty flavor.', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Wheat malt', 'GRAIN', 5, 75.0, 13, 'Sekado', 'Czech Republic', 'Base for production of wheat beers, added during the production of both barley lager and top fermented beers.', 6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Caramel malt light', 'GRAIN', 120, 75.0, 0.0, 'Sekado', 'Czech Republic', 'Is best used from light to medium colored lagers. Primarily to improve mouth-feel and head retention.', 6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Caramel malt dark', 'GRAIN', 220, 75.0, 0.0, 'Sekado', 'Czech Republic', 'Perfectly suited for Pilsner, light beer, lager, reduced-alcohol beer, special beer as well as for other dark beers.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Caramel extra dark', 'GRAIN', 460, 75.0, 0.0, 'Sekado', 'Czech Republic', 'Is great for use in dark beers type such as Amber Ale, Stout, Porter etc..', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Chocolate malt', 'GRAIN', 1000, 75.0, 0.0, 'Sekado', 'Czech Republic', 'For production of dark and half-dark Munich beers, and also in baking and confectionery industry', 4.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Coloured malt', 'GRAIN', 1500, 75.0, 0.0, 'Sekado', 'Czech Republic', 'For production of dark Munich beers and in baking industry as well. Black Malt with a standard colour of 1300° EBC is obviously of primary use for its colouring value. It is historically the key ingredient in Porter and enjoying a revival in many breweries, as a distinctive and flavoursome speciality beer.', 4.5, 0.0, 0.0, 0.0);
