INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pilot Pilsner', 'GRAIN', 3.5, 75.0, 10.2, 'Skagit Valley Malting', 'US', 'Pilot base malts present an opportunity to explore new variations on wort flavor, with the potential to improve beer attenuation, particularly with higher-gravity brews. Beta Amylase in Pilot remains stable at higher temperatures, and is not denatured as quickly during a single temperature infusion mash between 150 and 160 degrees F. Pilot base malts are well-suited to all styles of beer. ', 4.9, 411, 160, 64);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pilot Pale', 'GRAIN', 4.1, 75.0, 10.1, 'Skagit Valley Malting', 'US', 'Pilot base malts present an opportunity to explore new variations on wort flavor, with the potential to improve beer attenuation, particularly with higher-gravity brews. Beta Amylase in Pilot remains stable at higher temperatures, and is not denatured as quickly during a single temperature infusion mash between 150 and 160 degrees F. Pilot base malts are well-suited to all styles of beer. ', 4.3, 358.5, 162, 58);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pilot Pale', 'GRAIN', 13.5, 75.0, 11, 'Skagit Valley Malting', 'US', 'Pilot base malts present an opportunity to explore new variations on wort flavor, with the potential to improve beer attenuation, particularly with higher-gravity brews. Beta Amylase in Pilot remains stable at higher temperatures, and is not denatured as quickly during a single temperature infusion mash between 150 and 160 degrees F. Pilot base malts are well-suited to all styles of beer. ', 3.6, 222, 139, 71);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Fritz Pilsner', 'GRAIN', 3.9, 75.0, 9.9, 'Skagit Valley Malting', 'US', 'Fritz base malts present an opportunity to explore uncommon variations on wort flavor, while also addressing the challenge of longer-term beer clarity. Fritz was bred to have naturally low levels of Proanthrocyanidins (a naturally occurring compound that is associated with both chill and permanent haze). Fritz base malts are well-suited to all beer styles, especially those for which longer aging and shelf stability are desired. ', 5, 274.5, 121, 197);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Fritz Pale', 'GRAIN', 3.8, 75.0, 10.1, 'Skagit Valley Malting', 'US', 'Fritz base malts present an opportunity to explore uncommon variations on wort flavor, while also addressing the challenge of longer-term beer clarity. Fritz was bred to have naturally low levels of Proanthrocyanidins (a naturally occurring compound that is associated with both chill and permanent haze). Fritz base malts are well-suited to all beer styles, especially those for which longer aging and shelf stability are desired. ', 4.5, 323.5, 126, 192);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Fritz Ale', 'GRAIN', 4, 75.0, 9.6, 'Skagit Valley Malting', 'US', 'Fritz base malts present an opportunity to explore uncommon variations on wort flavor, while also addressing the challenge of longer-term beer clarity. Fritz was bred to have naturally low levels of Proanthrocyanidins (a naturally occurring compound that is associated with both chill and permanent haze). Fritz base malts are well-suited to all beer styles, especially those for which longer aging and shelf stability are desired. ', 4.1, 260.5, 115, 147);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Skagit Copeland Pilsner ', 'GRAIN', 3.6, 75.0, 9.6, 'Skagit Valley Malting', 'US', 'Skagit Copeland presents an opportunity to explore a local, lower-protein rendition of a North American favorite. Skagit-grown Copeland base malts demonstrate excellent brewhouse performance, with high extract and moderate levels of diastatic power (DP) and Alpha Amylase. These malts are well-suited to brewing all styles of beers. ', 4.2, 400.5, 199, 81);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Skagit Copeland Pale', 'GRAIN', 4.3, 75.0, 10, 'Skagit Valley Malting', 'US', 'Skagit Copeland presents an opportunity to explore a local, lower-protein rendition of a North American favorite. Skagit-grown Copeland base malts demonstrate excellent brewhouse performance, with high extract and moderate levels of diastatic power (DP) and Alpha Amylase. These malts are well-suited to brewing all styles of beers. ', 4.4, 365.5, 201, 89);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Skagit Copeland Ale', 'GRAIN', 5.3, 75.0, 9.5, 'Skagit Valley Malting', 'US', 'Skagit Copeland presents an opportunity to explore a local, lower-protein rendition of a North American favorite. Skagit-grown Copeland base malts demonstrate excellent brewhouse performance, with high extract and moderate levels of diastatic power (DP) and Alpha Amylase. These malts are well-suited to brewing all styles of beers. ', 3.6, 362, 196, 102);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Skagit White Club Wheat', 'GRAIN', 5.4, 75.0, 12, 'Skagit Valley Malting', 'US', 'Soft Club White Wheat is a variety that grows especially well in the Skagit Valley. Our White Wheat has a higher potential extract than traditional wheats due to lower proteins contributed by our growing climate. It has a clean flavor profile that makes it suitable for any style beer where wheat is a contributing ingredient.', 6.9, 316.5, 76, 94);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Talisman Pilsner', 'GRAIN', 3.1, 75.0, 10.2, 'Skagit Valley Malting', 'US', 'Skagit-grown Talisman winter barley exhibits our signature UK low-protein profile, as well as high extract, low levels of Beta Glucans and moderate levels of FAN and diastatic power (DP). Talisman base malts are well-suited to moderate gravity ales in both English and American style categories.', 5.6, 428.5, 104, 147);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Talisman True British Ale', 'GRAIN', 3.8, 75.0, 10.4, 'Skagit Valley Malting', 'US', 'Skagit-grown Talisman winter barley exhibits our signature UK low-protein profile, as well as high extract, low levels of Beta Glucans and moderate levels of FAN and diastatic power (DP). Talisman base malts are well-suited to moderate gravity ales in both English and American style categories.', 3.3, 239.5, 107, 127);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Obsidian Malt', 'GRAIN', 5.6, 75.0, 0.0, 'Skagit Valley Malting', 'US', 'Obsidian is our series of purple barley varieties that have been carefully selected by our maltster and growers for their uniqueness. From Ancient Egypt to the Himalayan mountains, Mediterranean, and beyond, this exploration of flavors is offered as a Pale base malt. Obsidian is an excellent addition to brett beers, saisons, and other beers that need a twist of rustic flavor.', 2.4, 190.5, 110, 990);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Francin Bohemian Pilsner', 'GRAIN', 3.7, 75.0, 11.2, 'Skagit Valley Malting', 'US', 'Francin was bred for all malt Czech-style brewing in the Czech Republic. Malt breeding in the Czech Republic selects for higher functionality for Czech beer brewing styles, not necessarily on higher extract. Due to this, we offer it as both a traditional step-mash decoction Pilsner and a Bohemian Pilsner that has a higher kiln, which brings out more flavor. This malt performs well in styles where distinct malt flavors are desired to balance out hoppiness.', 4.7, 400.5, 142, 156);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Buckwheat', 'GRAIN', 7.5, 75.0, 0.0, 'Skagit Valley Malting', 'US', 'Washington-grown Buckwheat offers a unique contribution to beers where residual sweetness and body are important. Due to higher gelatinization temperatures compared to barley, Buckwheat functions as a foam stability contributor, similarly to a dextrin malt. Use less than 10% of grist for best results.', 3.4, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Vienna', 'GRAIN', 6.8, 75.0, 9.6, 'Skagit Valley Malting', 'US', 'Our Vienna malt showcases an intense toasted flavor with a hint of caramel. It can be used up to 100% in a grist due to its higher level of enzymatic power. It is also a great substitute for lighter caramel malts or blended with pale malts across all styles of beers.', 3.3, 320, 191, 68);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Munich', 'GRAIN', 13.2, 75.0, 9.8, 'Skagit Valley Malting', 'US', 'Our Munich malts are high-kilned to develop a more intense Munich flavor while maintaining enough enzymatic power to be used up to 100% in a grist. Traditionally used in pilsners and other lagers, Munich malts can be used as a replacement for lighter caramel malts in modern IPAs.', 3.7, 218.5, 181, 65);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Super Vienna', 'GRAIN', 17, 75.0, 10.7, 'Skagit Valley Malting', 'US', 'Originally a custom malt project, our Super Vienna is the product of pushing the upper limits on a traditional Vienna malt . By increasing the color target of the final kiln step, we are able to create a darker Vienna malt that maintains enzymatic power, allowing it to be used up to 100% in a grist. This malt is outstanding in Octoberfests or other dark lagers and allows for a dryer finish without unfermentable sugars from caramel malts.', 4.2, 208, 161, 83);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Caramel 15', 'GRAIN', 33.3, 75.0, 0.0, 'Skagit Valley Malting', 'US', 'Caramel -15 is our medium high kilned caramel. It brings a richer intensity of honey like sweetness with raisiny and fruit leather flavors and aromas. ', 6.1, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Caramel 30', 'GRAIN', 48.5, 75.0, 0.0, 'Skagit Valley Malting', 'US', 'Caramel -30 is our dark caramel in the series of low color range caramel malts. Notable for its dark honey-like sweetness with very intense raisin and fruit leather notes, this malt imparts dark reddish tones, and can make a strong impact on flavor and color.', 6.6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Millet', 'GRAIN', 4.3, 75.0, 0.0, 'Skagit Valley Malting', 'US', 'Our current Prosso Millet is imported from Colorado and malted in our machines to bring out a big cracker and subtle grainy flavor. Low DP, so a cereal mash or enzymes will help get a better extract.', 3.1, 64.5, 109, 34);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pilsner malt', 'GRAIN', 5, 75.0, 0.0, 'Mälzerei Gebr. Steinbach', 'Germany', NULL, 0.0, 0.0, 0.0, 0.0);
