INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Okefenokee Pale ', 'GRAIN', 5.3, 75.0, 12, 'Two Track Malting Company', 'US', 'This malt was made from Copeland 2-Row Barley that was planted on May 5th, 2018 and harvested on August 7th, 2018 by Stober Farms. The Stober Farm is a 6th generation family farm located in Goodrich, ND and has been producing the highest quality grains for over 100 years.', 4.1, 376.7, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Badlands Sunset', 'GRAIN', 3.7, 75.0, 11.9, 'Two Track Malting Company', 'US', 'This malt was made from Copeland 2-Row Barley that was planted on May 5th, 2018 and harvested on August 7th, 2018 by Stober Farms. The Stober Farm is a 6th generation family farm located in Goodrich, ND and has been producing the highest quality grains for over 100 years.', 5.2, 447.05, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pronghorn – Brewski Pale', 'GRAIN', 3.5, 75.0, 11.55, 'Two Track Malting Company', 'US', 'This malt was made from an exclusive two row barley developed by North Dakota State University designed with the brewer in mind. Two Track Malting was able be the first to commercially malt this and we are excited to be the only ones growing and malting this special barley. Arrow K Farms grew this barley in Belfield, ND and is in Pronghorn country where this malt got its name. Arrow K Farms is a seed farm and crops are grown with quality as a top priority. ', 3.25, 300.75, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Dakota', 'GRAIN', 10.4, 75.0, 11.7, 'Two Track Malting Company', 'US', 'This malt was made from Copeland 2-Row Barley that was planted on May 5th, 2018 and harvested on August 7th, 2018 by Stober Farms. The Stober Farm is a 6th generation family farm located in Goodrich, ND and has been producing the highest quality grains for over 100 years.', 3.2, 344.5, 0.0, 0.0);
