INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Astro White Wheat', 'GRAIN', 4.6, 75.0, 15.9, 'Two Track Malting Company', 'US', 'AKF-Astro is a hard white spring wheat developed for malting by Arrow K Farms. Arrow K Farms is based in southwestern North Dakota on the edge of the Badlands in Billings County. Since it is a seed farm, crops are grown with quality as a top priority. Arrow K is a diversified operation owned by Greg & Stacey Kessel.', 4.7, 383, 0.0, 0.0);
