INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Wheat Malt', 'GRAIN', 6.5, 75.0, 13, 'Viking Malt', 'Denmark', 'Wheat Malt is used mainly for wheat beers and some other top fermented beers. Wheat Malt is also used for lager beers for flavor enrichment and to improve foam stability. Typical rate of usage is around 50% of the grist for wheat beers and appr. 20% for the premium lagers.', 6, 250, 150, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Pale Ale Malt', 'GRAIN', 7, 75.0, 11.5, 'Viking Malt', 'Denmark', 'For all kind of beers or whiskies. The colour of the pale ale malt is rather low.', 5, 0.0, 130, 200);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Pilsner Malt', 'GRAIN', 4.3, 75.0, 11.5, 'Viking Malt', 'Denmark', 'For all kind of beers or whiskies. The color of the Pilsner Malt is low.', 5, 250, 170, 200);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Vienna Malt', 'GRAIN', 10, 75.0, 12, 'Viking Malt', 'Denmark', 'Vienna Malt is well suited for relatively pale colored beers. Typical application is to enhance color and aroma of light beers. Vienna also has its own beer type, Vienna lager, which is famous for its deep golden color and malty taste.', 5, 0.0, 130, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Oat Malt', 'GRAIN', 7, 75.0, 0.0, 'Viking Malt', 'Denmark', 'For all kind of beers.', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking CaraBody Malt', 'GRAIN', 8, 75.0, 0.0, 'Viking Malt', 'Denmark', 'For all kind of beers.', 7, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Red Active Malt', 'GRAIN', 40, 75.0, 12.5, 'Viking Malt', 'Denmark', 'Viking Red Active Malt is ideal malt for any ales, dark lagers, festival beers and bocks for underlining malty flavors and full bodied taste, but also boosting up the red tinted colors. The strong enzyme activity gives good potential for developing recipes with adjuncts or non active malts. With this malt if you are heading to strong reddish color you do not need to dilute color down with pale malts. Dosage up to 100%.', 4.5, 230, 140, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Dextrin Malt', 'GRAIN', 16, 75.0, 10, 'Viking Malt', 'Denmark', 'Viking Dextrin Malt can be used in grists for ales and lagers to give fullness and sweetness in overall taste, supporting good head retention. As Dextrin Malt is light colored with not too overwhelming taste', 6.5, 180, 180, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Golden Ale Malt', 'GRAIN', 14, 75.0, 12, 'Viking Malt', 'Denmark', 'For all kind of beers but specially golden color ales and lagers. ', 5, 0.0, 130, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Rye Malt', 'GRAIN', 10, 75.0, 0.0, 'Viking Malt', 'Denmark', 'Viking Rye Malt can be used in breweries specialty rye beers, Rye Lager, Rye Ale. Gives golden color and typical rye flavor.', 6, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Roasted Barley', 'GRAIN', 1200, 75.0, 0.0, 'Viking Malt', 'Denmark', 'Roasted Barley is used in dark beers like stouts and porters, mainly for its strong coloring ability. Roasted barley will impart a dry flavor and substantial color.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Chocolate Light Malt', 'GRAIN', 450, 75.0, 0.0, 'Viking Malt', 'Denmark', 'Chocolate Malt is mainly included in for Porters and Stouts, but it can also be used for any other dark colored beers like Dark Ales due to its strong coloring value. Chocolate Malt contributes roasted flavors and aromas with hints of dark chocolate and coffee in any beer. Already with rather low dosage portions a remarkable increase in color can be found together with changes in flavor and aroma. Typical dosage rate of Chocolate Malt is normally under 5–10%.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Pearled Black Malt', 'GRAIN', 1000, 75.0, 0.0, 'Viking Malt', 'Denmark', 'Pearled Black Malt is used in dark beers like stouts and porters, mainly for its strong coloring ability. Normally portions 1–2% give a remarkable increase in color without significant change in flavor. By raising the percentage of Pearled Black Malt in malt bill the changes in taste can be found quickly, but slower than for typical Black Malt. ', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Viking Caramel 30', 'GRAIN', 30, 75.0, 0.0, 'Viking Malt', 'Denmark', 'Caramel Malts are well suited for winter beers, ale-type beers and other aromatic beers like dark lagers and stouts. Small amounts can be used for color adjustment and flavor enrichment of pale lagers as well.', 7, 0.0, 0.0, 0.0);
