INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Colorado Select', 'GRAIN', 4.9, 75.0, 11.5, 'Malteurop', 'US', 'Malteurop Colorado Select is produced from two-row barley grown on the plains of Colorado at the base of the Rocky Mountains. Colorado Select uses the finest two-row barley varieties and is a wonderfully balanced base malt in any beer style. This malt provides sweet, malty aromas and very subtle nutty flavors while imparting a light gold hue.', 4.5, 491.5, 200, 140);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Montana Select', 'GRAIN', 4.5, 75.0, 12.5, 'Malteurop', 'US', 'Malteurop Montana Select is grown and malted in Big Sky country. It’s produced from two-row barley grown on the plains of Montana and malted in our Great Falls, Montana malt house. This malt provides sweet, malty aromas and very subtle nutty flavors while imparting a light gold hue good for any beer style.', 4.5, 561.5, 230, 130);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Wisconsin Select', 'GRAIN', 5.5, 75.0, 11.5, 'Malteurop', 'US', 'Malteurop Wisconsin Select is grown and malted in Wisconsin, a state known for its long-standing brewing heritage. It’s produced from two-row barley grown on the plains of northern Wisconsin and malted in our Milwaukee, Wisconsin malthouse. This malt provides sweet, malty aromas and very subtle nutty flavors while imparting a light gold hue good for any beer style.', 4.5, 456.5, 190, 200);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('2-Row', 'GRAIN', 4.7, 75.0, 12.2, 'Malteurop', 'US', 'Malteurop 2-Row is our flagship two-row base malt. It is produced using the finest North American two-row barley varieties, and is a wonderfully balanced base malt in any beer style. This malt provides sweet, malty aromas and very subtle nutty flavors while imparting a light gold hue.', 4.5, 596.5, 170, 140);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Munich', 'GRAIN', 23.6, 75.0, 12, 'Malteurop', 'US', 'Malteurop Munich Malt is a highly kilned malt, produced using the finest North American spring barley. Our specialized kilning process creates a clean but intense malt flavor and aroma, and deep gold to orange hues in the final beer. This malt is best used as 5% - 50% of the grain bill in any beer style to increase malt characteristics.', 4.5, 509, 180, 200);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pale Ale Malt', 'GRAIN', 6.7, 75.0, 11.5, 'Malteurop', 'US', 'Malteurop Pale Ale Malt is a two-row malt produced using a specialized kilning process in order to create a fully modified malt with a robust enzyme package and high extract potential, appropriate for use as a base malt in any beer style. Our Pale Ale malt imparts subtle nutty and biscuit flavors while contributing a rich golden hue. Use up to 100% in all beer styles.', 4.8, 509, 230, 120);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Pilsen Malt ', 'GRAIN', 3.9, 75.0, 12, 'Malteurop', 'US', 'The lightest of our two-row base malts, Malteurop Pilsen malt imparts a sweet and subtle malt flavor and a straw yellow to light golden color. It can be used up to 100% in all beer styles and provides a perfect canvas for other specialty malts.', 4.8, 526.5, 190, 130);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Vienna Malt', 'GRAIN', 7.1, 75.0, 12, 'Malteurop', 'US', 'Vienna Malt is a versatile two-row malt. A specialized kilning process increases the malt sweetness and aroma, and imparts a subtle biscuit flavor. It contributes rich, dark golden hues in the final beer. It has enough diastatic power to be used as a base malt up to 80% in certain beer styles, and it can be used as a specialty malt to intensify malt flavor.', 4.8, 614, 250, 130);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Wheat Malt', 'GRAIN', 7.5, 75.0, 12.5, 'Malteurop', 'US', 'Malteurop Wheat Malt is a versatile base malt made using soft white wheat. It provides a sweet, malty and characteristic bread dough wheat malt flavor and aroma while also improving head retention and mouthfeel. It can be used as a primary base malt in beers such as German Weizen or Belgian Wit beers or as a specialty malt in many other beer styles.', 5.5, 614, 140, 100);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Dextrin Malt', 'GRAIN', 3.9, 75.0, 13, 'Malteurop', 'US', 'As a beer body builder, Dextrin provides fullness of mouthfeel and enhances head retention and beer stability', 6.5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Kilned C60 Malt', 'GRAIN', 128.1, 75.0, 0.0, 'Malteurop', 'US', 'Non-crystalized, colored malt for augmenting base malt color and flavor in many brewing styles.', 5, 0.0, 0.0, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Steamed C3.5', 'GRAIN', 9.5, 75.0, 13, 'Malteurop', 'US', 'Pale, steam-crystallized kilned malt. Crafted by a special process of injecting live steam into the kiln bed, resulting in a unique flavor profile.', 5.5, 0.0, 170, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Steamed C40', 'GRAIN', 88.7, 75.0, 12, 'Malteurop', 'US', 'Richly colored steam-crystallized kilned malt. Provides toffee flavor notes and color.', 5, 0.0, 160, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('Bavarian Pilsen', 'GRAIN', 4.3, 75.0, 11.5, 'Malteurop', 'US', 'Malteurop Bavarian Pilsen malt is a high-quality German lager style base malt produced from select 2-Row spring barley. The barley is grown and malted in Bavaria, a history-rich barley growing region of Germany. Mild, malty and pale straw in color, this malt lends itself to a wide variety of beer styles or creating special German heritage recipes.', 5.5, 474, 170, 0.0);
INSERT INTO fermentables (name, type, color_ebc, yield_percentage, protein, producer, origin, notes, moisture, diastatic_power, fan, beta_glucan) VALUES ('French Pilsen', 'GRAIN', 4.3, 75.0, 11.5, 'Malteurop', 'US', 'Mention the word "Champagne" and it brings to mind world-famous sparkling wines. Our French Pilsen malt is made from local 2-row spring barley, which is grown in the Champagne region and malted in our nearby malthouses. The region is the premier barley-growing region of France with a unique microclimate influenced both by the Atlantic Ocean and the surrounding countryside.', 5.5, 474, 170, 0.0);
