INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('AURORA', 76, 86, 'KVEIK', 23.0769, 'Bootleg Biology', 'BBAUR', 'MEDIUM', 24, 37, 'The perfect yeast for homebrewers with no temperature control! Use AURORA for worry-free fermentations. Just pitch it and ditch it! AURORA creates pleasant orange and citrus esters that perfectly complement beers like IPAs made with fruit-forward hops. Easily produce rounded, complex beers at temperatures as high as 98F (37C) without being phenolic or having noticeable off flavors. At the high end of fermentation temperature, beers can finish attenuating in as little as three days!', 'IPA, Pale Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Classic American', 73, 78, 'ALE', 11, 'Bootleg Biology', 'BBUSA1', 'MEDIUM', 18, 22, 'Professional brewers fondly refer to this culture as Chico. This is THE yeast for recreating authentic hop-forward beer styles like American Pale Ales, West Coast IPAs, East Coast IPAs, Brut IPAs, & Black IPAs. Reliably produces no-nonsense Blonde Ales, American Porters and Stouts. Ideal for fermenting quick sours due to its low pH tolerance. Classic American will delightfully emphasize malt character, the stickiness of hops and the refreshing qualities of bitterness. This culture will not make a pillowy beer.', 'American Pale Ales, West Coast IPAs, East Coast IPAs, Brut IPAs, Black IPAs, Stouts');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Classic English', 72, 76, 'ALE', 23.0769, 'Bootleg Biology', 'BBXELG', 'LOW', 17, 22, 'Classic English produces soft, juicy, and tropical fruit flavors when fermenting beers made with citrusy hops. This culture has become the de facto standard for making hazy New England-style IPAs in addition to the Classic New England culture. Ideal for fermenting Milkshake IPA, Brut IPA and other IPA sub-styles. Traditionally used for making ester-drive Porters, Stouts, Pale Ales, Bitters, and most English-style ales.', 'IPA, Pale Ales, Brut IPA, Bitters, Porters, Stouts');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Funk Weapon #1', 80, 95, 'ALE', 23.0769, 'Bootleg Biology', 'BB0034A', 'LOW', 18, 24, 'This rare, and commercially unavailable yeast isolate, produces pungent horse blanket and fresh leather aromas. Perfect for breaking out the funk in farmhouse-style beers.Funk Weapon #1 is featured in the Trinity & Epic Brewing collaboration Wild Apple Saison, and Trinity''s Magical Brettanomyces Tour #4.', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Funk Weapon #2 ', 80, 95, 'ALE', 23.0769, 'Bootleg Biology', 'BB0035C', 'MEDIUM_LOW', 18, 24, 'This rare, and commercially unavailable yeast isolate is perfect for 100% Brettanomyces fermentations, especially Brett IPAs. Amplifies citrus and tropical fruit-forward hop flavors and aromas into a punchy ripeness. With extended time under CO2 pressure, pineapple and tropical fruit aromas will be more pronounced. Great for maintaining the nuance of hops in beer with better keeping qualities than a Brewer''s Yeast fermentation.', 'Brett IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Funk Weapon #3', 80, 95, 'ALE', 23.0769, 'Bootleg Biology', 'BB0022', 'MEDIUM', 18, 24, 'Funk Weapon #3 is a versatile culture that creates wildly different flavor and aroma profiles depending on the age of fermentation. Young fermentations produce mild musty funk and ripe tropical fruit, while older and bottle conditioned ferments show off unique flavors and aromas of strawberry, cherry and tropical candy. This commercially unavailable yeast isolate is ideal for 100% Brettanomyces fermentations or as a secondary strain along with a phenolic Brewer''s Yeast culture.', 'Sours, Bretts');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('NEEPAH Blend', 75, 82, 'ALE', 7.69231, 'Bootleg Biology', 'BBXNPA', 'LOW', 19, 21, 'The NEEPAH IPA Blend is our secret weapon for delivering the juiciest, tropical fruit bomb you''ve ever made. Carefully cultivated from a special blend of fruit-forward yeast strains, the NEEPAH Blend is here to amplify the gorgeous rainbow of flavors in your New England-Style IPAs by providing an extra punch of danky goodness. Now you can spend less money on expensive hops and spend more time drinking the best made hazy pale in town. Looking for a versatile culture that''ll deliver a new take on flavorful English Ales? The NEEPAH Blend creates decadent beers that out class those made with tired ESB strains. This blend works especially well for Brut IPAs, emphasizing the fruity hop character and reducing the perception of bitterness in dry beers.', 'IPA, Hazy IPA, Pale Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('OSLO', 76, 86, 'KVEIK', 23.0769, 'Bootleg Biology', 'BBOSL', 'MEDIUM', 24, 37, 'OSLO is a modern take on traditional Norwegian farmhouse brewing cultures. OSLO can comfortably produce beautifully clean, lager-like beers at temperatures as high as 98F (37C) without noticeable off flavors. At the high end of fermentation temperature, beers can finish attenuating in as little as three days! This culture''s versatility and neutral flavor profile allows you to effortlessly produce most beer styles. Bootleg is the first yeast lab to release this unique Kveik-family culture sourced from a raw beer made by our good friends at Eik & Tid in Oslo, Norway.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('S. arlingtonesis™', 88, 93, 'ALE', 23.0769, 'Bootleg Biology', 'BB22204', 'HIGH', 13, 20, 'This culture ferments extremely clean in the 50''sF (lagers) & 60''sF (Kolsch and Lager hybrids), and has subtle fruity/citrus esters in the higher end of the Ale fermentation range (wheat-centric beers). May produce sulfur aromas during primary fermentation, but those will be eliminated within a couple weeks (allow longer aging if fermenting at lower temperatures). S. arlingtonesis is a higher attenuator than most ale strains, so adjustments made need to be made to grain bills or mash temperatures if a drier beer is not preferred.', 'Ales, Kolsch, Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison Parfait™: New World Saison Blend', 90, 100, 'ALE', 23.0769, 'Bootleg Biology', 'BBX0104', 'MEDIUM_LOW', 18, 29, 'Saison Parfait pairs classic pepper & spice saison phenolics with prominent juicy fruit esters that evoke citrus and lemon peel, and a touch of banana for complexity. Even more unique, it finishes with a balanced, full-bodied and silky mouthfeel despite its high attenuation. Saison Parfait means the “Perfect Season”, and is our ode to the fall harvest season. A time for hard work and also celebration. The peasants of rural Flanders and Wallonia created the Saison, and what we now call Farmhouse beers, to drink for sustenance and merriment. Bruegel likely depicted the drinking of Saison beer in his classic paintings of rural country life, “The Harvesters” and “Peasant Wedding”.', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Sour Solera Blend', 96, 100, 'ALE', 23.0769, 'Bootleg Biology', 'BBXSS', 'MEDIUM', 18, 24, 'Sour Solera Blend contains a unique and complex collection of Saccharomyces, Brettanomyces, Lactobacillus, Pediococcus and other funky yeast and souring bacteria pulled from an active fermentation. This blend can sour in a matter of months at 70ºF or higher, or if you prefer a more prolonged fermentation, use large amounts of aged hops and/or ferment and hold at temperatures below 70ºF. This blend is available seasonally, and will always be changing and evolving due to the nature of solera fermentations. Warning: No two Sour Solera Blend releases will be the same, and neither will their fermentations.', 'Sours');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Sour Weapon L', 0.0, 0.0, 'BACTERIA', 7.69231, 'Bootleg Biology', 'BBXSWL', 'LOW', 29, 37, 'If you''re looking to drop the pH of wort as quickly and low as possible, Sour Weapon L is your go to Lacto blend. At 98F, we''ve had trial batches drop the pH of wort to 3.0 after just 24 hours. When pitched at 84F, pH should reach 3.5 in 24 hours. This is the ideal bacteria blend to use for acidifying wort for quick/kettle sours, and is also very effective when co-pitched with a yeast strain. As with any Lactobacillus culture, we recommend only using in wort with zero IBUs as even small amounts of hops may prevent significant souring.', 'Sours');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Sour Weapon P', 0.0, 0.0, 'BACTERIA', 23.0769, 'Bootleg Biology', 'BBX0089', 'LOW', 29, 37, 'We''re excited to release our first 100% Lactic Acid Bacteria souring blend! We chose this specific blend because of its ability to sour quickly and cleanly at a range of temperatures, and due to its mild hop tolerance. While not “yeast”, this culture blend of two unique strains of Pediococcus pentosaceus is part of our LYP collection because it was sourced entirely from the wild: an anaerobic malt starter, and flowers from Murfreesboro, TN given to us by our good friend Art Whitaker. Perfect for quickly acidifying unhopped wort for kettle/”quick” sours or co-pitching with yeast.', 'Sours');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('The Mad Fermentationist Saison Blend', 90, 100, 'ALE', 23.0769, 'Bootleg Biology', 'BBXMAD1', 'MEDIUM', 20, 27, 'Fine tuned over two years, this blend morphed over time to become an elegant powerhouse of classic Saison spice, stone-fruit Brett, lactic tartness and a dry but well-rounded body. The final master blend consists of Saison yeast, wild Saccharomyces, rare Brettanomyces and an opportunistic Lactobacillus culture. At temperatures as low as 68F (20C) The Mad Fermentationist Saison Blend exhibits a relatively clean primary fermentation profile and high attenuation. Traditional saison temperatures (around 80F/27C) bring out citrus and elevated phenols (pepper and clove). The Brett character shifts depending on wort composition, as maltier beers emphasize cherry and stone fruit qualities. This blend integrates beautifully with fruity and tropical hops, with the unique Brett culture keeping hop aromatics crisp and bright for an extended time. For best results use a highly fermentable wort, dry hopping during the tail of active fermentation, and carbonating naturally.', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Berliner blend ', 0.0, 0.0, 'ALE', 0.0, 'East Coast Yeast', 'ECY06', 'MEDIUM', 0.0, 0.0, 'Kolsch yeast and Lactobacillus blend.', 'Berliner Weiss');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BugFarm', 0.0, 0.0, 'ALE', 0.0, 'East Coast Yeast', 'ECY01', 'MEDIUM', 0.0, 0.0, 'A large complex blend of cultures to emulate sour beers such as lambic style ales. Over time displays a citrus sourness and large barnyard profile. Contains yeast (S. cerevisiae and S. fermentati), several Brettanomyces strains, Lactobacillus and Pediococcus. The BugFarm blend changes every year and can be added at any stage of fermentation.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Farmhouse ', 80, 0.0, 'ALE', 0.0, 'East Coast Yeast', 'ECY03B', 'MEDIUM', 26, 28, 'Saison brasserie blend (ECY08) with a pure Brettanomyces isolate from a small but fascinating producer of Saison. Produces a fruity and funky profile with some acidity gradually increasing over time.', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Flemish Ale', 0.0, 0.0, 'ALE', 0.0, 'East Coast Yeast', 'ECY02', 'MEDIUM', 0.0, 0.0, 'A unique blend of yeast and bacterial cultures. Produces dry beers with sourness and notes of leather, fruit, and cherry stone.', 'Sour Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Kellerbier', 74, 76, 'LAGER', 0.0, 'East Coast Yeast', 'ECY28', 'MEDIUM', 8, 12, 'This yeast exhibits a clean, crisp lager in traditional northern German character. Use in German Pilsners including Kellerbier.', 'German Pilsners, Kellerbier');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Kölschbier', 75, 78, 'ALE', 0.0, 'East Coast Yeast', 'ECY21', 'MEDIUM', 14, 19, 'Produces a clean lager-like profile at ale temperatures. Smooth mineral and malt characters come through with a clean, lightly yeasty flavor and aroma in the finish', 'Kolsch');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Nordic Farmhouse', 78, 83, 'KVEIK', 0.0, 'East Coast Yeast', 'ECY43', 'MEDIUM', 32, 41, 'igmund strain of Kveik yeast (Saccharomyces cerevisiae). Traditionally used in the production of Norwegian Farmhouse Ale yielding spicy orange peel flavor, particularly if underpitched.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Old Newark Ale', 76, 78, 'ALE', 0.0, 'East Coast Yeast', 'ECY10', 'HIGH', 16, 20, 'Sourced from a now defunct east coast brewery, this pure strain was identified as their ale pitching yeast. Good for all styles of American and English ales. Top fermenting, high flocculation with a solid sedimentation. Suggested fermentation temp: 60-68°F. Apparent Attenuation: 68-72% Resurrected from a freezed-dried deposit library, this pure strain of S. cerevisae is NOT the rumored Chico strain.  Rumored to be Ballantine.', 'American Ales, English Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison Brasserie', 80, 0.0, 'ALE', 0.0, 'East Coast Yeast', 'ECY08', 'MEDIUM', 24, 29, 'A combination of several Saison yeasts for both fruity and spicy characteristics accompanied by dryness. Apparent Attenuation: up to 80%. Suggested fermentation temp: 75-85° F.', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Scottish Heavy', 77, 80, 'ALE', 0.0, 'East Coast Yeast', 'ECY07', 'MEDIUM', 16, 20, 'Leaves a fruity profile with woody, oak esters reminiscent of malt whiskey. Well suited for 90/shilling or heavier ales including old ales and barleywines due to level of attenuation (77-80%) - recommend a dextrinous wort. Suggested fermentation temp: 60-68°F.', 'Scottish Ales, Stouts, Old Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Abbaye', 74, 76, 'ALE', 0.0, 'East Coast Yeast', 'ECY09', 'MEDIUM', 19, 25, 'This yeast produces classic Belgian ales – robust, estery with large notes of clove and fruit. Rated highly in sensory tests described in "Brew Like A Monk" for complexity and low production of higher alcohols. Apparent attenuation 74-76%. Suggested fermentation temp: 66 - 72° F. ', 'Belgian Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Abbaye 2', 74, 76, 'ALE', 0.0, 'East Coast Yeast', 'ECY13', 'MEDIUM', 24, 27, 'Traditional Abbey yeast with a complex, dry, fruity malt profile. Rated highly in sensory tests described in "Brew Like A Monk" for complexity and low production of higher alcohols. Apparent Attenuation: 74-76%. Suggested fermentation temp: 66-72° F.', 'Belgian Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison', 76, 78, 'ALE', 0.0, 'East Coast Yeast', '​ECY14', 'MEDIUM', 24, 28, 'This pure strain leaves a smooth, full character with mild esters reminiscent of apple pie spice. Apparent attenuation 76-78%. Suggested fermentation temp: 75 - 82° F. ', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Dour Saison', 77, 83, 'ALE', 0.0, 'East Coast Yeast', '​ECY41', 'MEDIUM', 25, 26, 'Dry, peppery, and complex earthy notes. Saccharomyces cerevisiae var. diastaticus. Fermentation Temp 77-80°F. Attenuation: 77-83%.  ', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('American Ale', 72, 76, 'ALE', 38.4615, 'Escarpment Labs', NULL, 'MEDIUM', 16, 22, 'Excellent performance, and somewhat lower attenuation than Cali Ale. Suitable for nearly any clean style. Much like Cali Ale, exhibits clean fermentation at a wide temperature range, and accentuates hop character.', 'Americal Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Anchorman Ale', 75, 85, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'HIGH', 18, 20, 'Clean fermentation profile, with slightly faster attenuation and flocculation than Cali Ale Yeast. Suitable for production of clean West Coast style ales.', 'IPA, Pale Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Ardennes Belgian Ale', 72, 80, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM_HIGH', 18, 25, 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Arset Kveik Blend', 70, 80, 'KVEIK', 53.8462, 'Escarpment Labs', NULL, 'HIGH', 20, 37, 'This kveik yeast was sourced from Jakob Årset, on the farm Årset in Eidsdal, Norway. The overall flavour profile is similar to the Hornindal Kveik Blend, but this blend shows a higher degree of hop biotransformation. This blend also exhibits a broad temperature range (we have heard of sub-15ºC) and tolerates acidic wort quite well.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Sour Blend', 80, 0.0, 'ALE', 7.69231, 'Escarpment Labs', NULL, 'LOW', 20, 25, 'A blend of 5 Brettanomyces strains isolated from Belgian Lambic beers, alongside 4 strains of Lactobacillus and 2 strains of Pediococcus, for the production of mixed fermentation sour ales. For best results, we recommend using this blend in beer with less than 7 IBUs initially. Subsequent generations can use increasing IBUs. This is supplied at secondary fermentation pitch rates, and is intended to be used in secondary or as a copitch, alongside a primary fermentation strain of your choice.', 'Sours');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Berliner Brett Blend', 0.0, 0.0, 'ALE', 0.0, 'Escarpment Labs', NULL, 'MEDIUM', 0.0, 0.0, 'A blend of Berliner Brett 1 (Brettanomyces anomalus) and Berliner Brett 2 (Brettanomyces bruxellensis) for balanced, subtle Brett character in traditional Berliner Weisse and beyond. Flavour profile includes citrus, white wine, and peach. Secondary pitch rates only. ', NULL);
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Berliner Brett I', 57, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM_LOW', 18, 24, 'A Brettanomyces anomalus strain from a ~40 year old bottle of Hochschule Berliner Weisse. Works well in traditional style Berliners, and anywhere subtle, refined Brett character is desired. The fruit profile tends toward citrus and white wine. This strain is sold in secondary pitch rates only.', 'Traditional Berliners, subtly funky beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Berliner Brett II', 57, 0.0, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'LOW', 18, 24, 'Brettanomyces bruxellensis from an old bottle of Schultheiss Berliner Weisse. Funkier than Berliner Brett I, with notes of peach, pineapple, and pear.', 'Traditional Berliners, subtly funky beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Biergarten Lager', 70, 75, 'LAGER', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM', 9, 13, 'This strain offers low diacetyl production and a crisp flavour profile that is highly suited for German Pilsner, Helles, Festbier or other Munich-style lagers.', 'For German-style Helles, Pilsner, etc.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brett B', 80, 0.0, 'ALE', 38.4615, 'Escarpment Labs', NULL, 'LOW', 22, 27, 'A classic Brettanomyces bruxellensis strain, isolated from a classic abbey beer, is typically used in secondary fermentations where balanced Brett character (fruit, funk) is desired.', 'Barrel aged ales and Orval clones');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brett D', 80, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'LOW', 20, 25, 'This strain of Brettanomyces bruxellensis is noted for very prominent pineapple esters alongside a good dose of funk. Suited to primary or secondary fermentation.', 'Hoppy beers, Saisons, Sours');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brett M', 80, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'LOW', 22, 27, 'A house favourite Brettanomyces bruxellensis strain, which develops funky and fruity flavours quickly. Great in mixed fermentation saisons and funky Belgian styles.', 'Balanced funky beers. Great in Saisons');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brett Q', 80, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM_HIGH', 20, 25, 'This unique Brettanomyces bruxellensis strain was originally isolated from a barrel-aged sour beer from Quebec. Tasting notes include ripe strawberry, pear, apple, with underlying funk.', 'Barrel aged ales and funk bombs');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brussels Brett', 80, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'LOW', 22, 27, 'This Brettanomyces bruxellensis strain displays a balanced selection of fruity characteristics, with tasters noting plum, red berry, citrus, and red apple, alongside subtle acidity and elevated funk. It shines in secondary fermentation with extended aging where it displays prominent funky flavours.', 'Intensely aromatic funky beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brut Ale', 80, 0.0, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'LOW', 14, 22, 'Originally labelled a Kölsch strain, this yeast is non phenolic but diastatic, which makes it suitable for producing very dry, clean ales.', 'Dry and crushable ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Cali Ale', 75, 80, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM', 16, 22, 'An exceptionally versatile ale yeast that provides clean fermentation and accentuates hop character, suitable for nearly any style.', 'Clean, focused American ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Cerberus', 70, 80, 'ALE', 38.4615, 'Escarpment Labs', NULL, 'LOW', 22, 28, 'This enigmatic strain has proven itself in many breweries who use it alone or paired with Vermont Ale to produce fruit-forward, hoppy beers. Produces and enhances tropical fruit flavours. If used alone, we recommend a highly fermentable wort.', 'Fruity and hop-forward beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Classic Witbier', 72, 78, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM_LOW', 19, 24, 'A genre-defining Witbier strain, famous for balanced phenol and ester character with slight tartness that emphasizes wheat flavour. Rapid fermentation!', 'The palest of Belgian beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Copenhagen Lager', 71, 77, 'LAGER', 38.4615, 'Escarpment Labs', NULL, 'MEDIUM_LOW', 8, 13, 'One of the most widely-used lager strains in the world, and a great choice for accentuating hops and/or more mineral-rich water profiles.', 'For all types of lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Czech Lager', 70, 78, 'LAGER', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM', 9, 13, 'This traditional Czech Pilsner yeast rewards patience with a clean, crisp profile and accentuates subtleties in selected malt and hops.', 'Czech Pilsners');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Dry Belgian Ale', 85, 0.0, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM_LOW', 22, 26, 'One of our favourite Belgian-style isolates obtained from an American producer of Belgian-style beers. Classic Belgian flavours and aggressive primary fermentation. We especially like this strain for Strong Golden, Tripel, and other strong Belgian styles.', 'ale Belgians - Blond, Tripel, etc');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Ebbegarden Kveik Blend', 70, 80, 'KVEIK', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM', 22, 27, 'This blend displays prominent tropical guava and mango esters, lending well to modern aromatic styles like NEIPA. Note that this blend does accentuate hop bitterness and so less (or no) bittering hops are needed.', 'From clean beers to fruity IPAs');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('English Ale I', 63, 71, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'VERY_HIGH', 18, 22, 'A classic English ale yeast which ferments and flocculates quickly, leaving some residual sugars. However, it is highly responsive to wort fermentability and can attenuate well with very fermentable worts.', 'Traditional English ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('English Ale II', 72, 80, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'VERY_HIGH', 18, 22, 'Very flocculant, suited for English ales and is also great as a house yeast strain for most English/American beer styles.', 'Traditional English ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('English Ale III', 72, 80, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM', 18, 22, 'Suited for English ales and is also great as a house yeast strain for most English/American beer styles. Does not flocculate quite as hard as English I or II, making it easier to crop.', 'Balanced and clean ales.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Foggy London Ale', 71, 78, 'ALE', 38.4615, 'Escarpment Labs', NULL, 'MEDIUM', 18, 23, 'Displays a balanced fruity flavour profile, and accentuates malt and hop flavours. It is especially suited for the production of fruity, hop-forward New England-style IPAs.', 'Modern fruity hop-forward styles and English ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('French Saison', 90, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'LOW', 22, 30, 'This is an extremely versatile Saison strain that can be used in the production of a broad array of beer styles. It performs best when fermented warm, however can tolerate lower temperatures. At lower temperatures expect light esters and citrus notes, though when fermented much warmer (23°C or higher) one can expect pepper, spice, and an explosion of esters. This strain is very attenuative and will result in dry beers but will still result in a very pleasing mouthfeel.', 'Saison, Witbier, French Table Beer');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Fruity Wit', 70, 75, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM_LOW', 20, 26, 'A Witbier strain that produces tons of complex fruity esters while still prominently displaying classic Witbier character. Medium-low flocculation helps ensure classic Witbier haze.', 'The palest of Belgian beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Fruit Bomb Saison Blend', 85, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'LOW', 22, 27, 'This high-character blend contains a Saison strain with balanced ester and spice aromas, an enigmatic Brettanomyces anomala strain with tropical characteristics, and a complex and fruity Brettanomyces bruxellensis strain. Highly suited to aroma hop or fruit-forward farmhouse ales/saisons.', 'Funk and fruit-forward Saisons');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hornindal Kveik Blend', 70, 80, 'KVEIK', 53.8462, 'Escarpment Labs', NULL, 'HIGH', 15, 35, 'This blend is highly flocculant and displays mixed fruity character. It can also be used to produce haze in hoppy beers.', 'IPA, Pale Ales, Hazy IPAs');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Irish Ale', 70, 75, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM_HIGH', 18, 22, 'Irish ale yeast from a classic brewery, producing slight fruitiness and caramel notes. Great for Irish stouts, porters, red ales, and pale ales.', 'Stouts, Pale Ales, Porters');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Jötunn', 80, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM_HIGH', 22, 35, 'We bred a Saison strain and a Norwegian Kveik to produce this all-consuming giant of a yeast. A rare combination of diastatic and flocculent, making it a Saison yeast that is easy to crop and repitch. Expressive fruitiness but low banana ester. ', 'Saison, Table Beer');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Isar Lager', 72, 82, 'LAGER', 38.4615, 'Escarpment Labs', NULL, 'MEDIUM_HIGH', 10, 15, 'Accentuates malt character with a reliable fermentation profile, good flocculation and diacetyl reduction.', 'For all types of lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Kolsch', 72, 78, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM', 15, 22, 'This balanced and clean ale yeast is of course great for Altbier and Kölsch production, but also for a wide range of beers anywhere a clean fermentation is desired.', 'Clean and crisp ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Krispy', 70, 82, 'KVEIK', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM_HIGH', 18, 30, 'KRISPY is a special blend of kveik yeasts selected by our lab wizards for optimal crispiness and crushability in beer. It can be used to make clean, lager-like beers in a fraction of the time since fermentations can be performed in the 20-30ºC range.', 'Clean ales and pseudo-lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Lactobacillus Blend', 0.0, 0.0, 'ALE', 0.0, 'Escarpment Labs', NULL, 'MEDIUM', 30, 40, 'A blend of two Lactobacillus species, L. brevis and L. plantarum. This blend is designed to be usable at a wide range of temperatures and is especially suited for kettle souring/sour worting.', 'Quick-turnaround sour beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Lactobacillus Blend 2.0', 0.0, 0.0, 'ALE', 0.0, 'Escarpment Labs', NULL, 'MEDIUM', 30, 40, 'A blend of our main L. plantarum strain and a strain of L. rhamnosus, which enhances fruit flavours in the finished beer with tasters noting red fruit and guava aromas. It is intended for kettle/quick souring but can also be used in 0 IBU wort.', 'Quick-turnaround, fruity sour beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Lactobacillus brevis', 0.0, 0.0, 'ALE', 0.0, 'Escarpment Labs', NULL, 'MEDIUM', 30, 40, 'A single strain of L. brevis that performs well in kettle souring/sour worting where fast and clean lactic acidity is desired.', 'Quick-turnaround sour beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Lactobacillus Delbrueckii', 0.0, 0.0, 'ALE', 0.0, 'Escarpment Labs', NULL, 'MEDIUM', 30, 40, 'A single strain of L. delbrueckii often used for quick souring. This strain can produce mixed berry and citrus aromatics.', 'Quick-turnaround sour beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Laerdal Kveik', 68, 78, 'KVEIK', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM_HIGH', 20, 35, 'This single-strain isolate from the Lærdal Kveik (sourced from Dagfinn Wendelbo) ferments fast (like most kveik), flocculates well, and adds pineapple and orchard fruit aroma to beer. Ferments fast and is suited to hazy IPAs or English ales. ', 'Pale Ale, IPA, Blond Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Mexican Lager', 70, 70, 'LAGER', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM', 10, 14, 'A reliable North American lager strain that produces clean and crisp beers. Not just limited to light lager styles!', 'For crisp and clean North American Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Mothership Brett Blend', 80, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'LOW', 22, 27, 'A funky grab bag of our favourite Brett strains! This blend typically contains 10 individual strains. The character is highly dependent on fermentation conditions, but tends toward balanced, medium to high intensity Brett character.', 'Brett Beer');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('New World Saison Blend', 85, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'LOW', 22, 27, 'A new world Saison blend containing Saccharomyces and Brettanomyces to produce a fruity, funky beer with rustic charm.', 'Funk-forward Saisons');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Northwest Ale', 72, 78, 'ALE', 38.4615, 'Escarpment Labs', NULL, 'MEDIUM', 16, 22, 'A versatile American ale strain which leaves a clean flavour profile. Smooths hop bitterness, leading to balanced beers. This yeast is not as aggressively attenuative as Cali Ale or Anchorman Ale.', 'Crisp American Ales and subtle British styles');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Old World Saison Blend', 85, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'LOW', 22, 27, 'A characterful blend of two classic Saison strains that produces complex fruit and black pepper notes along with a reliable, fast and high degree of attenuation.', 'Balanced and clean Saisons');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Ontario Farmhouse Ale Blend', 80, 0.0, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'LOW', 22, 27, 'A combination of a rustic, fruity Saccharomyces strain we isolated from Ontario strawberries and two subtly fruity and funky Brettanomyces strains isolated from Ontario wine barrels. A true expression of terroir.', 'Saisons and wild ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Pine Tree Wit', 72, 82, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM_LOW', 19, 24, 'Hailing from the Northeast USA, this Wit strain produces balanced esters and delicate phenols. Attenuation by this strain is responsive to mash temp and it is a great platform to lets the other ingredients shine through. Attenuation: 72-82% // Optimum Temp: 19-24ºC (66-75.2°F) // Alcohol tolerance: 10% // Flocculation: Medium-Low', 'The palest of Belgian beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Premium Pils', 0.0, 0.0, 'LAGER', 0.0, 'Escarpment Labs', NULL, 'MEDIUM', 0.0, 0.0, 'Premium Pils is a Czech-derived lager strain with high fermentation rate and clean flavours. While its use is not limited to Czech style beers, we do think that it shines in these styles.', NULL);
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison Maison', 80, 0.0, 'ALE', 38.4615, 'Escarpment Labs', NULL, 'MEDIUM_LOW', 22, 27, 'This is a non-diastatic yeast isolated from a Belgian Saison. This is quite unique in the saison yeast world, as most saison yeasts contain the STA1 glucoamylase gene, resulting in extremely dry beers.  This yeast is suitable for breweries who want to produce authentic Saisons but who are put off by the risk of diastatic yeasts. Saison Maison attenuates in a manner similar to many workhorse ale strains like Cali Ale.  To produce an ultra-dry beer, amyloglucosidase enzyme products are recommended as an addition mid-ferment. We also recommend fermenting hot (up to 35ºC) and dosing additional oxygen. ', 'Saisons, Belgian Golden Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison Nouveau', 80, 0.0, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM', 20, 25, 'A new world Saison strain to produce a balanced Saison base - clean, lightly fruity, peppery. This is the Saccharomyces strain from our New World Saision Blend (that blend contains Brett). This saison yeast contains the STA1 gene, meaning it is a diastatic yeast. Many Saison yeasts are diastatic, due to the desire for very high attenuation levels. However extra care must be taken to ensure these yeasts do not cross-contaminate non-diastatic yeasts. ', 'North American-style Saisons');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('St. Remy Abbey Ale', 72, 80, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'MEDIUM', 18, 24, 'A Belgian abbey strain which produces mixed fruity esters, while also highlighting malt aroma. A rare non-phenolic Belgian ale strain. Recommended for Dubbel and Quad styles.', 'Malty Belgian styles - non phenolic');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('St. Lucifer', 75, 80, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM', 20, 28, 'A high-character Belgian ale strain able to produce high gravity beers with strong fruity and medium phenolic character. We recommend highly fermentable wort and a free rise fermentation for this strain. Fermentation can be slow to finish. We like this strain for pale Belgian beer styles.', 'Pale Belgians - Blond, Tripel, etc.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Stirling Ale', 70, 85, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM', 14, 22, 'This versatile strain can ferment colder than many ale strains, yielding exceptionally clean ales.', 'Clean, focused ales of all kinds');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('The Kveik Ring: Midtbust', 77, 0.0, 'KVEIK', 0.0, 'Escarpment Labs', NULL, 'MEDIUM', 0.0, 0.0, 'Hailing from Stordal, the Midtbust Kveik is well suited to a variety of beer styles. Here, we''ve blended 5 isolates from the original farmhouse culture. Like most kveik, the temperature can be pushed high to obtain more aroma expression or dialled down for a more neutral result.  We think Midtbust will work well in dark winter brews such as stouts, porters, and barleywines.', NULL);
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Uberweizen', 72, 80, 'ALE', 38.4615, 'Escarpment Labs', NULL, 'MEDIUM_LOW', 18, 24, 'A slightly more attenuative German Hefeweizen strain compared to Weizen I, which still displays prominent banana and clove profile.', 'All the weizens');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Vermont Ale', 73, 83, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM', 19, 22, 'A high-character ale yeast that produces hop-accentuating fruity esters, supporting stone fruit and citrus character.', 'Modern fruity hop-forward styles and English ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Voss Kveik ', 70, 75, 'KVEIK', 53.8462, 'Escarpment Labs', NULL, 'HIGH', 25, 42, 'This yeast can ferment at up to 42ºC, with clean flavours and a prominent citrus aroma.', 'From clean beers to fruity IPAs');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Weizen I', 70, 75, 'ALE', 38.4615, 'Escarpment Labs', NULL, 'LOW', 18, 24, 'The classic German Hefeweizen strain. Banana ester (isoamyl acetate) character can be emphasized by slightly underpitching, creating a more fermentable wort, and/or using a higher fermentation temperature.', 'All the weizens');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('West Abbey Ale', 74, 86, 'ALE', 53.8462, 'Escarpment Labs', NULL, 'MEDIUM', 20, 25, 'This strain produces balanced intensity of fruity esters and phenolics, and can be used for high gravity ferments.', 'Balanced Belgian styles');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Wild Thing', 75, 85, 'ALE', 23.0769, 'Escarpment Labs', NULL, 'LOW', 25, 25, 'This wild Ontario ale yeast was isolated from an apple in a local orchard. Wild Thing produces distinct clove, spice, and subtle banana and apple fruit aroma. The taste is dry, spicy and clean. This yeast is most comparable to Belgian-style ale yeasts.', 'Saisons, Dry Belgian style ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafAle BE-134', 89, 93, 'ALE', 10, 'Fermentis', 'BE-134', 'LOW', 18, 28, 'This typical brewer''s yeast strain is recommended for well-attenuated beers, produces fruity, floral and phenolic notes and a dry character. Produces highly refreshing beers, it is ideal for Belgian-Saison style.', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafAle BE-256', 82, 86, 'ALE', 10, 'Fermentis', 'BE-256', 'HIGH', 15, 20, 'Active dry brewer''s yeast recommended to ferment a diversity of Belgian type beers such as abbey style known for its fruitiness and high alcohol content. It ferments very fast and reveals strong fermentation aromas. To maintain the aromatic profile at the end of the fermentation, we do recommend to crop this yeast as soon as possible after fermentation', 'Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafAle F-2', 0.0, 0.0, 'ALE', 10, 'Fermentis', 'F-2', 'MEDIUM', 15, 25, 'SafAle™ F-2 brewing yeast has been selected specifically for secondary fermentation in bottle and in cask. This yeast assimilates very little amount of maltotriose but assimilates basic sugars (glucose, fructose, saccharose, maltose). It is characterized by a neutral aroma profile respecting the base beer character and settles very homogeneously at the end of fermentation.', 'Cask');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafAle K-97', 80, 84, 'ALE', 10, 'Fermentis', 'K-97', 'LOW', 15, 20, 'German ale brewer''s yeast producing subtle fermentation character. Depending on the conditions tend to present floral and balanced fruity character. Ideal for delicate beers such as German Kolsch beers, Belgian Wits and some versions of Session Beers. Suitable for heavily hopped beers and has ability to form a large firm head when fermenting.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafAle S-04', 74, 82, 'ALE', 10, 'Fermentis', 'S-04', 'MEDIUM_HIGH', 18, 21, 'English ale brewer''s yeast selected for its fast fermentation profile. Produces balanced fruity and floral notes. Due to its flocculation power, tends to produce beers with higher clarity. Ideal for a large range of American and English Ales - including highly hopped beers - and is specially adapted to cask-conditioned and beers fermented in cylindro-conical tanks.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafAle S-33', 68, 72, 'ALE', 10, 'Fermentis', 'S-33', 'MEDIUM', 15, 20, 'Fruity driven strain, gives a high mouthfeel and body to the beer. Ideal for Belgian Ales (Blond, Dubbel, Tripel, Quadrupel Styles) and strong English ales (ex. Imperial Stouts). It is also ideal for New England IPA''s. Yeast with a medium sedimentation: forms no clumps but a powdery haze when resuspended in the beer.', 'Blond, Dubbel, Tripel, Quadrupel Styles, Imperial Stouts');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafAle T-58', 66.6667, 0.0, 'ALE', 11.5, 'Fermentis', 'T-58', 'MEDIUM', 15, 24, 'Specialty brewer''s yeast selected for its strong fermentation character, intense fruity and phenolic flavors - especially banana, clove and peppery notes. Suitable for a great variety of wheat-base beers and fruity-spicy oriented styles. Yeast with a medium sedimentation: forms no clumps but a powdery haze when resuspended in the beer.', 'Hefeweizen, Weissbier, Witbier');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafAle US-05', 72, 78, 'ALE', 10, 'Fermentis', 'US-05', 'MEDIUM_LOW', 15, 20, 'American ale brewer''s yeast producing neutral and well-balanced ales, clean and crispy. Forms a firm foam head and presents a very good ability to stay in suspension during fermentation. Ideal for American beer types and highly hopped beers.', 'Ales, Pale Ale, IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafAle WB-06', 86, 90, 'ALE', 10, 'Fermentis', 'WB-06', 'LOW', 18, 24, 'Brewer''s yeast providing fruity and phenolic character, varying with the fermentation conditions. Produces well-attenuated beers and it is ideal for wheat base beers, such as Belgian and German Styles (Ex. Wit Beers and Weizen Beers). Produces typical phenolic notes of wheat beers. Allows to brew beer with a high drinkability profile and presents a very good ability to suspend during fermentation.', 'Hefeweizen, Weissbier, Witbier');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafBrew DA-16', 98, 102, 'ALE', 16, 'Fermentis', 'DA-16', 'MEDIUM', 20, 32, 'SafBrew DA-16 is a powerful solution (consisting of Active Dry Yeast and enzymes) for the production of very dry and flavorful beers, particularly fruity and hoppy ones such as Brut IPAs. SafBrew™ DA-16 is also recommended for very high gravity wort, allowing a level of alcohol up to 16% ABV.', 'Brut IPA, IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafBrew HA-18', 98, 102, 'ALE', 18, 'Fermentis', 'HA-18', 'LOW', 25, 35, 'SafBrew HA-18 is a powerful solution (consisting of POF+ Active Dry Brewer''s Yeast and enzymes) for the production of high-gravity and particularly high alcoholic beers - such as strong ales, barley wines and barrel aged beers with very high density. It has a very good resistance to osmotic pressure and high fermentation temperatures (thermotolerant yeast).', 'Strong Ales, Barleywine');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafBrew LA-01', 15, 0.0, 'ALE', 0.0, 'Fermentis', 'LA-01', 'MEDIUM', 0.0, 0.0, 'SafBrew LA-01, is a Saccharomyces cerevisiae var. chevalieri that has been specifically selected for the production of low and/or non-alcoholic beverages (<0.5ABV). This yeast does not assimilate maltose and maltotriose but assimilates simple sugars (glucose, fructose and sucrose) and is characterized by a subtle aroma profile. Yeast with a medium sedimentation: forms no clumps but a powdery haze when resuspended in the beer.', 'Non-Alcoholic');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafLager S-189', 80, 84, 'LAGER', 10, 'Fermentis', 'S-189', 'HIGH', 12, 15, 'Originating from the Hürlimann brewery in Switzerland. This lager yeast strain''s profile allows to brew fairly neutral flavor beers with a high drinkability. Depending on the conditions, it tends to present noticeable herbal and floral notes to lager beers.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafLager S-23', 80, 84, 'LAGER', 10, 'Fermentis', 'S-23', 'HIGH', 12, 15, 'Bottom fermenting brewer’s yeast originating from Berlin in Germany. It’s recommended for the production of fruitier and more estery lagers. Its profile gives beers with a good length on the palate.', 'Lagers, Märzen');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafLager W-34/70', 80, 84, 'LAGER', 10, 'Fermentis', 'W-34/70', 'HIGH', 12, 15, 'This famous brewer''s yeast strain from Weihenstephan in Germany is used world-wide within the brewing industry. SafLager W-34/70 allows the brewing of beers with a good balance of floral and fruity aromas and gives clean flavors and high drinkable beers.', 'Lagers, Märzen');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SafSour LP 652', 0.0, 0.0, 'BACTERIA', 0.0, 'Fermentis', 'LP 652', 'MEDIUM', 0.0, 0.0, '#tropical  #citrus  #fruity', 'Sours');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('A Touch Of Spice Belgian Ale', 81, 84, 'ALE', 0.0, 'GigaYeast', 'GY003', 'MEDIUM_LOW', 20, 25, 'Abbey style yeast from the Belgian Ardennes. Spicy clove like notes and a hint of fruity esters. Medium flocculation means a clearer beer than most Belgian yeast.', 'Belgian Ale, Dubbel, Belgian Strong, Tripel, Biere De Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Altstadt Ale', 77, 81, 'ALE', 0.0, 'GigaYeast', 'GY016', 'LOW', 13, 20, 'An ale yeast that ferments at cold temperatures and produces a lager like ale style. Used in traditional Alt and Kolsch styles. Leaves a nice, residual maltiness.', 'Kolsch, California Common, Altbier, Biere De Garde, Cream Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('American Lager', 79, 83, 'LAGER', 0.0, 'GigaYeast', 'GY030', 'MEDIUM', 9, 16, 'Think you don''t like American Lager? Think again. This lager yeast is a powerful attenuator that leaves a dry beer with a slightly fruity finish. Awesome.', 'Lager, Black Lager, Pilsner, Schwarzbier, Imperial Pilsner');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bavarian Hefe', 77, 81, 'ALE', 23.0769, 'GigaYeast', 'GY017', 'VERY_LOW', 18, 27, 'A traditional hefe yeast from one of Bavaria’s oldest breweries. Robust attenuator that works over a broad range of temperatures and produces the classic banana and clove notes of the German wheat beer style. Moderate sulfide producer (will dissipate with conditioning).', 'Dunkelweizen, Gose, Hefeweizen, Weizenbock');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Abbey Ale', 79, 81, 'ALE', 0.0, 'GigaYeast', 'GY014', 'LOW', 18, 27, 'Classic Belgian yeast. A fragrant yeast that produces delicious fruity aroma and virtually no phenolics. Good choice for high gravity beers. Generally, the warmer this yeast is fermented the higher the level of fruit aromas produced.', 'Belgian Ale, Dubbel, Belgian Strong, Tripel, Biere De Garde, Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Mix', 79, 81, 'ALE', 0.0, 'GigaYeast', 'GY007', 'LOW', 19, 25, 'A blend of Belgian Ale Yeast combine to create robust attenuation and a complex flavor profile. Spicy and fruity, this blend is slightly more flocculent than many Belgians. Good choice for High Gravity beers.', 'Belgian Ale, Dubbel, Belgian Strong, Tripel, Biere De Garde, Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Tripel', 74, 76, 'ALE', 0.0, 'GigaYeast', 'GY015', 'LOW', 19, 23, 'Belgian Ale yeast from the mother of all Tripels. A balance of fruit and spice with a good malty finish provides a perfect complement for Belgian Ales, Dubbels and Tripels. Perfect for malt forward Belgians. Less esters and phenolics than GY003 and GY014.', 'Belgian Ale, Dubbel, Belgian Strong, Tripel, Biere De Garde, Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Wit', 76, 79, 'ALE', 0.0, 'GigaYeast', 'GY028', 'VERY_LOW', 18, 27, 'Traditional Belgian Wit yeast from one of the classic producers of the style. Creates a delicious spicy nose and a somewhat tart beer. Attenuates dry and leaves a slightly cloudy beer— very low flocculation.', 'Belgian Witbier, Saison, Belgian Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Berliner Blend', 89, 0.0, 'ALE', 0.0, 'GigaYeast', 'GB122', 'MEDIUM', 21, 27, 'A blend of neutral ale yeast and lactic acid bacteria. Lactic Acid Bacteria are inhibited by hops, high gravity and low temperatures. You can adjust sourness by increasing or decreasing these variables. More than 7 IBU, gravity above 1050 or temps below 65 F will increase the time to sour or lead to reduced overall souring.  10 days at 71 F in 1045 sweet wort, pH 5.6', 'Sour Beer, Gose, Berliner Weisse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('British Ale #1', 75, 79, 'ALE', 0.0, 'GigaYeast', 'GY011', 'HIGH', 18, 25, 'Versatile house strain from a traditional UK brewery. Strong attenuation over a broad temperature range and low esters make this yeast perfect for a wide variety of styles. GY011 is a strong flocculator that creates a clear beer.', 'British Ales, Pale/Amber Ale, Barley Wine, Scotch Ale, Bitter, Stout, India Pale Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('British Ale #2', 80, 82, 'ALE', 0.0, 'GigaYeast', 'GY031', 'HIGH', 18, 24, 'From a traditional British brewery. Very flocculent— produces clear beer. GY031 leaves a slightly sweet malty flavor. Flavor profile is nearly neutral at lower fermentation temps. Slight banana/fruit notes appear at higher temps. Perfect for English style pale ales, stouts, porters, bitters browns etc.', 'British Ales, Pale/Amber Ale, Barley Wine, Scotch Ale, Bitter, Stout, India Pale Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brussels Bruxellensis', 58, 0.0, 'ALE', 10, 'GigaYeast', 'GB001', 'LOW', 20, 27, 'Brettanomyces Bruxellensis This yeast is highly attenuative when left for long periods of time but tends to ferment slowly. Typically best used in combination with faster fermenting yeast in the primary or added to the secondary to add complexity while aging.', 'Saison, Brett Beer, Sour Beer');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brux Blend', 79, 0.0, 'ALE', 0.0, 'GigaYeast', 'GB156', 'MEDIUM', 20, 27, 'A blend of Brettanomyces yeast that produces stone fruit esters and a hint of barnyard. Creates a moderate amount of acid that adds a tart complexity to the brew. This blend is highly attenuative if left for long periods of time but ferments more slowly than a typical ale yeast. Use GB156 in a primary if fermented for 2-3 weeks or for conditioning a fermented beer during aging.', 'Saison, Sour Beer, Lambic');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Czech Pilsner', 75, 79, 'LAGER', 0.0, 'GigaYeast', 'GY002', 'MEDIUM_HIGH', 9, 13, 'Bottom fermenting yeast from a world famous Czech pilsner. Produces a dry, clean beer. Perfect for pilsner and other lager styles. This yeast is flocculent and produces a very clear beer. Robust attenuation in beer up to 16-17˚ Plato. Moderate to poor attenuation in very high gravity beers (over 20˚ Plato).', 'Pilsners, Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Farmhouse Sour', 89, 0.0, 'ALE', 0.0, 'GigaYeast', 'GB121', 'MEDIUM', 20, 27, 'Blend of Belgian Ale Yeast, Brettanomyces and Lactic Acid Bacteria Lactic Acid Bacteria are inhibited by hops, high gravity and low temperatures. You can adjust sourness by increasing or decreasing these variables. More than 7 IBU, gravity above 1050 or temps below 65 F will increase the time to sour or lead to reduced overall souring. Warmer fermentation temps will typically increase the esters and spicy phenolics of the saison ale yeast in this blend.', 'Saison, Sour Beer, Lambic');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('German Ale Yeast', 75, 77, 'ALE', 0.0, 'GigaYeast', 'GY094', 'MEDIUM', 18, 22, 'Ale yeast from a traditional Dusseldorf brewery famous for malty, balanced alt-style brews. This yeast creates a lush, malt forward beer with subtle esters of honey, pear and apple. Perfect for Sticke, Dopplesticke and Alt beers but also makes a great choice for any malt forward beer with generous mouthfeel. ', 'Alt, Sticke, Dopplesticke, malt forward beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('German Lager', 74, 78, 'LAGER', 0.0, 'GigaYeast', 'GY045', 'MEDIUM_LOW', 10, 16, 'Bottom fermenting German yeast used in commercial breweries around the world. Produces a slightly sweeter but clean beer with a malty finish. Perfect for pilsners, märzen, Festbier etc . May require a diacetyl rest after fermentation.  ', 'Lagers, Keller Bier, Marzen, Schwarz Bier, Bock, Pilsner');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Gigayeast Lacto', 15, 40, 'BACTERIA', 0.0, 'GigaYeast', 'GB110', 'MEDIUM', 20, 37, 'Lactobacillus Sp. Lactic Acid Bacteria are inhibited by hops, high gravity and low temperatures. You can adjust sourness by increasing or decreasing these variables. More than 7 IBU, gravity above 1050 or temps below 65 F will increase the time to sour or lead to reduced overall souring. We recommend brewing with GB110 in one of three ways. I) “Hot Start”: Pitch GB110 to wort at 98 F with little or no hops for 48-72 hrs. Wort may be soured before kettle boil or after. If soured before kettle boil, boil with hop additions as usual. If soured after kettle boil cool wort and pitch yeast. II) “Co-Pitch”: Pitch GB110 into a primary with yeast of your choice at 68-72 F. Wort that is less than 1050 and 7 IBU will typically be very sour in 2-3 weeks. III) “Secondary”: Pitch GB110 after primary fermentation for an aged sour. Souring by this method typically requires several months. Adding simple sugars or fruit etc. will enhance souring in the secondary.', 'Saison, Sour Beer, Lambic');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Golden Gate Lager', 79, 83, 'LAGER', 0.0, 'GigaYeast', 'GY005', 'MEDIUM', 13, 21, 'Lager yeast used to create the California Common beer style. Ferments unusually high for a lager strain and still retains a lager sensibility (up to 68˚F). This yeast leaves a slightly sweeter beer than our other lager yeast— perfect for creating a subtle, malty undertone against a clean lager background. Creates a moderate amount of sulfide under some conditions that will dissipate with a short rest. Fermentations at traditional lager temperatures may be slow. Recommended 55˚- 68˚F.', 'California Common, Cream Ale, Stout');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Golden Pear Belgian', 83, 85, 'ALE', 0.0, 'GigaYeast', 'GY048', 'LOW', 18, 27, 'Traditional yeast from the originator of the Belgian Golden Strong Ale style. Robust attenuation makes this yeast an excellent choice for low or high gravity belgian and farmhouse style ales. Leaves a dry, slightly tart finish with an estery profile reminiscent of apple and pear with a subdued level of spicy phenolics. This yeast produces a moderate amount of sulfide that will dissipate quickly with conditioning.', 'Belgian Golden Strong Ale, Farmhouse Ale, Tripel, Saison, Dubbel, Biere De Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hornindal Kveik #5', 72, 75, 'KVEIK', 13, 'GigaYeast', 'GY135', 'MEDIUM_HIGH', 21, 38, 'A traditional Norwegian Kveik yeast that can be fermented at 85-100 F for fast fermentation and no off flavors. We have found a 15 P wort attenuates to 75%-78% in as little as 4 days at 90F. Subtle notes of tropical fruit make this yeast an excellent choice for clean hop-forward IPAs and Pale Ales. ', 'Pale Ale, IPA, NEIPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Irish Stout', 82, 86, 'ALE', 0.0, 'GigaYeast', 'GY080', 'MEDIUM', 18, 22, 'From one of the most famous stouts in the world. Creates a crisp, dry beer with a subtle fruity profile and a slightly tangy finish. Makes an amazing stout or porter but is also great for red, amber and even pale ales. This ale yeast is a robust fermenter perfect for high gravity brews and settles out well enough to create a relatively clear beer.', 'Stout, Porter, Imperial Stout, Amber/Red Ale, English Pale Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Kolsch Bier', 79, 83, 'ALE', 0.0, 'GigaYeast', 'GY021', 'MEDIUM_HIGH', 16, 22, ' From one of the oldest Kölsch breweries in Köln. Fermenting under 65˚F produces a very clean, crisp beer with a touch of ester. Perfect for Kölsch or any style where a dry, clean profile is desired. GY021 produces a moderate amount of sulfide that will dissipate completely.', 'Kolsch, Pale Ale, Alt, India Pale Ale, Cream Ale, Amber');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Kveik #1', 74, 78, 'KVEIK', 0.0, 'GigaYeast', 'GY134', 'MEDIUM', 27, 38, 'A traditional Norwegian Kviek yeast that can be fermented at 85-100 F for fast fermentations and no off flavors. We have found a 15 P wort attenuates to 74% - 78% in as little as 48 hours at 90F. Subtle notes of citrus fruit make this yeast an excellent choice for clean hop-forward IPAs and Pale Ales with citrus hop additions ', 'Pale Ale, IPA, NEIPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Norcal Ale #1', 76, 80, 'ALE', 11, 'GigaYeast', 'GY001', 'MEDIUM', 18, 25, 'Clean Fermenting, versatile strain from one of the most famous California Pale Ales. Neutral flavor profile creates a crisp beer and allows hops to shine. Strong attenuator and good flocculation perfectly suited for a large variety of styles. Good choice for high gravity beers.', 'Barley Wine, Pale Ale, Bitter, Scotch Ale, India Pale Ale, Stout');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Norcal Ale #5', 69, 73, 'ALE', 0.0, 'GigaYeast', 'GY029', 'MEDIUM_HIGH', 19, 24, 'More flocculent and less attenuative than GY001. Ferments more slowly and leaves a clear beer with residual sweetness and a slight fruity nose. Excellent for full bodied, malt forward beers.', 'Brown, Porter, Amber, Pale, Stout');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Portland Hefe', 76, 80, 'ALE', 23.0769, 'GigaYeast', 'GY020', 'VERY_LOW', 18, 23, 'Used to make a famous American Wheat Beer. Creates a clean tasting crisp brew with just a hint of banana and spice. Very low flocculation means a hazy beer true to the hefe style.', 'American Wheat Beer, Weizenbock, Dunkelweizen, Hefeweizen');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Quebec Abbey Ale', 79, 83, 'ALE', 0.0, 'GigaYeast', 'GY077', 'MEDIUM', 20, 27, 'From one of the first breweries in North America to create a successful line of traditional Abbey style ales. This Belgian ale yeast creates a malt forward beer with subtle fruity esters and a very small amount of clove notes. Robust attenuation makes this yeast an excellent choice for low or high gravity beers where a slightly sweet malty finish is desired. Perfect for the Belgian Dubbel and Tripel styles.', 'Belgian Ale, Dubbel, Belgian Strong, Tripel, Biere De Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison #1', 81, 83, 'ALE', 0.0, 'GigaYeast', 'GY018', 'LOW', 18, 27, 'Traditional Saison yeast from a French craft brewery. Produces fragrant beer with pepper and fruit notes. Warmer fermentations create more intense flavors. Perfect for accentuating citrus and fruit flavors. High attenuation rates make a dryer beer than Saison #2.', 'Saison, Farmhouse Ale, Belgian Ale, Biere De Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison #2', 79, 83, 'ALE', 0.0, 'GigaYeast', 'GY027', 'LOW', 18, 27, 'rom a traditional farmhouse Saison. Creates the fruity/spicy aroma traditional to the style. Warmer fermentation temps result in more intense flavor. Produces a tartness not found in most of our yeast and a slightly sweeter beer than GY018 (Saison #1).', 'Saison, Farmhouse Ale, Belgian Ale, Biere De Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison Blend', 80, 83, 'ALE', 0.0, 'GigaYeast', 'GY047', 'LOW', 18, 27, 'A blend of Saison yeast. This Blend is a super robust attenuator that produces a complex flavor profile of fruit and spice.', 'Belgian, Witbier, Belgian Pale Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison Sour', 78, 0.0, 'ALE', 0.0, 'GigaYeast', 'GB124', 'MEDIUM', 20, 27, 'Blend of Saison Ale Yeast and Lactic Acid Bacteria  14 days at 71 F in 1045 sweet wort, pH 5.6. Lactic Acid Bacteria are inhibited by hops, high gravity, and low temperatures. You can adjust sourness by increasing or decreasing these variables. More than 7 IBUs, gravity about 1050, or temps below 65 F, will increase the time to sour ro lead to reduced overall souring. Warmer fermentation temps will typically increase the esters and spicy phenolics of the saison ale yeast in this blend.', 'Sour Beer, Saison, Wild Specialty Beer, Flanders Red Ale, Oud Bruin, Lambic, Gueze, Fruit Lambic');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Scotch Ale #1', 80, 82, 'ALE', 0.0, 'GigaYeast', 'GY044', 'MEDIUM_LOW', 18, 24, 'This is one sweet yeast. Neutral flavors emphasize the malt. Leaves a slight residual sweetness and body in high gravity beers perfect for malt forward styles like scotch ales, wee heavy, stouts and porters.', 'Scotch Ale, Pale, Wee Beavy, Brown, Porter, Stout');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Sour Cherry Funk', 51, 89, 'ALE', 0.0, 'GigaYeast', 'GB150', 'MEDIUM', 20, 27, 'Blend of 3 Brett strains and Lactic Acid Bacteria This blend creates an amazing complex, sour beer with fruity cherry esters. Fermenting in the presence of 7-10 IBUs will cause the fermentation to complete much more quickly but will slow the souring — expect to wait 3-4 months for significant souring. Fermenting with zero or less than 5 IBUs will allow souring to happen much faster (within two weeks) but will cause the fermentation to take up to 4 weeks to complete.', 'Saison, Sour Beer, Brett Beer');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Sour Plum Belgian', 77, 0.0, 'ALE', 0.0, 'GigaYeast', 'GB123', 'MEDIUM', 20, 27, 'Belgian ale yeast and lactic acid bacteria. Cleaner than GB121. Creates a beer with stone fruit/plum esters and sour notes.', 'Saison, Sour Beer, Lambic');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Sweet Flemish Brett', 84, 85, 'ALE', 10, 'GigaYeast', 'GY144', 'LOW', 20, 24, 'Brew with GB144 on its own in a primary fermentation or in a secondary to add character during aging.  **7 days at 71 F in 1045 sweet wort, Ph 5.5: **  Apparent Attenuation–83%', 'Saison, Brett Beer, Sour Beer, IPAs and NEIPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Tart Cherry Brett', 70, 85, 'ALE', 10, 'GigaYeast', 'GB002', 'LOW', 20, 27, 'Brettanomyces Bruxellensis This yeast is highly attenuative but tends to ferment about ½ as fast as a typical ale strain. Although it attenuates faster than GB001, it is typically best used in combination with faster fermenting yeast in the primary or added to the secondary to add complexity while aging.', 'Saison, Sour Beer, Lambic');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Vermont Ipa', 78, 82, 'ALE', 11, 'GigaYeast', 'GY054', 'MEDIUM_LOW', 17, 24, 'From one of the best examples of an east coast IPA. This yeast attenuates slightly less than NorCal Ale #1 and leaves a beer with more body and a slight fruity ester that is amazing with aromatic hops. Good choice for high gravity beers and hoppy styles. Broad temperature range and moderate flocculation make this yeast a versatile house strain.', 'Imperial Pale Ale, American Wheat Beer, Pale Ale, Bitter, West Coast Amber, ESB');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Barbarian', 73, 74, 'ALE', 10, 'Imperial Yeast', 'A04', 'MEDIUM', 17, 21, 'Excellent yeast strain for any hop forward beers. Wonderfully suited for juicy, hazy New England IPAs. Commonly referred to as the conan yeast strain, it''s ready to attack your IPA. Barbarian produces stone fruit esters that work great when paired with citrus hops. Barbarian will give you what you need for an exceptionally balanced IPA, leaving a nice round and full bodied mouthfeel.', 'American Pale Ale, Black IPA, White IPA, Imperial IPA, American Pale Ale, English IPA, Red IPA, Robust Porter, American Stout, Winter Seasonal Beer, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, Cream Ale, American Wheat Beer, Blonde Ale, American Amber Ale, American Brown Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bartleby', 75, 85, 'KVEIK', 10, 'Imperial Yeast', 'A46', 'HIGH', 20, 37, 'Bartleby is a hornindal Kveik strain that is a great choice for anything from a traditional Norwegian farmhouse ale to a hazy IPA. When used on the high end of the temperature range, Bartleby will produce a lot of pineapple, apricot and peach aromas. The ability to run this yeast at higher fermentation temperatures along with its high flocculation properties make it a great strain for fast turnaround times. This strain is not a part of our core availability line up, please call or email for lead time and specifics.', 'IPA, Pale Ale, Stout, Porter, English Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Cablecar', 71, 75, 'LAGER', 10, 'Imperial Yeast', 'L05', 'MEDIUM_HIGH', 13, 18, 'The classic strain for California Common style beers. Cablecar can produce clean pseudo lagers at ale temperatures but is also willing to work as a traditional lager strain down to the mid-50s. Not just limited to steam beers/California commons, this strain works well in a variety of fermentations, keeping flavor profiles clean and crisp.', 'California Common, Pre-Prohibition Lager, Bière de Garde, Cream Ale, Blonde Ale, American Lager, American Amber Lager, Helles, Vienna Lager, Schwarzbier, Baltic Porter, Czech Amber Lager, Czech Dark Lager, Mexican Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Citrus', 74, 78, 'ALE', 10, 'Imperial Yeast', 'A20', 'LOW', 19, 27, 'Wild saccharomyces yeast strain known to produce a huge citrus fruit ester profile. Citrus cranks out orange and lemon aromas along with some tropical fruit. Use this strain at high temps for big ester production. A wild saccharomyces strain, it will get a bit funky without the worries of a brettanomyces strain. Keep an eye on your fermentations, it does like to hit a false terminal and then slowly finish out the rest of fermentation. This strain tests positive for the STA1 gene via PCR analysis and is therefore considered to be Saccharomyces cerevisiae var. diastaticus', 'Hazy IPA, American Pale Ale, Imperial IPA, Red IPA, White IPA, Red Ale, American Wheat Beer, Black IPA, Robust Porter, American Stout, Winter Seasonal Beer, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, Cream Ale, Blonde Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Darkness', 71, 75, 'ALE', 12, 'Imperial Yeast', 'A10', 'MEDIUM', 17, 22, 'Brewers love this yeast strain for dark beers. Its high alcohol tolerance make it a go-to for big beers. A beautiful strain for stout, porter, brown, and amber ales. Darkness produces a unique character that matches up perfectly with roasted and caramel malts. This strain is alcohol tolerant, so don''t hesitate to throw high gravity worts its way.', 'Stout, Irish Dry, American Stout, American Barleywine, Black IPA, American Brown Ale, Robust Porter, Winter Seasonal Beer, Imperial Stout, American Strong Ale, Brown Porter, Stout, Sweet, Stout, Oatmeal, Stout, Foreign Extra, Stout, Tropical, British Strong Ale, Wee Heavy, Irish Red Ale, Red IPA, Red Ale, Wheatwine, English Mild, Extra Special Bitter, Bitter, English IPA, Scottish Ale, English Barleywine, Old Ale, American IPA, American Pale Ale, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Dieter', 73, 77, 'ALE', 10, 'Imperial Yeast', 'G03', 'MEDIUM', 16, 21, 'Traditional Kolsch yeast strain, fairly flocculent and versatile. Dieter is a clean, crisp, traditional German Kolsch strain. A very low ester profile makes this strain perfect for Kolsch, Alt and other light colored delicate beers. Dieter has better flocculation characteristics than most Kolsch strains which allow brewers to produce clean, bright beers in a shorter amount of time.', 'Kolsch, Altbier, Gose, Bière de Garde, American IPA, Cream Ale, American Pale Ale, Berliner Weisse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Dry Hop', 74, 78, 'ALE', 10, 'Imperial Yeast', 'A24', 'MEDIUM', 18, 23, 'A blend of two highly popular yeast strains, well suited for hop forward beers. Dry Hop is a blend of A20 Citrus and A04 Barbarian. When this blend goes to work on your hoppy beer, the hop aroma blows up. The combination of these strains produces amazing aromas of citrus, peach, and apricot that will accentuate your IPA, pale ale, and any other hop-driven beer. This blend contains a strain that tests positive for the STA1 gene via PCR analysis and is therefore considered to be Saccharomyces cerevisiae var. diastaticus.', 'Hazy IPA, American IPA, American Pale Ale, Imperial IPA, White IPA, Red IPA, Red Ale, Pale Ale, English IPA, Black IPA, Robust Porter, American Stout, Winter Seasonal Beer, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, Cream Ale, American Wheat Beer, Blonde Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Flagship', 73, 77, 'ALE', 12, 'Imperial Yeast', 'A07', 'MEDIUM_LOW', 16, 22, 'Commonly referred to as chico" this yeast is a craft brewing standard. This strain is the go-to for craft brewers, highly popular- this strain performs well at standard ale temperatures but can be used in the low 60s to produce exceptionally crisp ales. Flocculation is in the middle of the road and will typically require filtration or fining to achieve crystal clear beers.', 'American IPA, American Pale Ale, American Stout, Stout, Tropical, Cream Ale, American Wheat Beer, Imperial IPA, Blonde Ale, American Amber Ale, American Brown Ale, California Common, Black IPA, Irish Red Ale, Wee Heavy, Hazy IPA, British Strong Ale, Red IPA, English Barleywine, White IPA, Red Ale, Robust Porter, Winter Seasonal Beer, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, Berliner Weisse, Gose, Pale Ale, Stout, Irish Dry, Brown Porter, English IPA, Scottish Ale, Stout, Sweet, Stout, Oatmeal, Old Ale, Stout, Foreign Extra, Bière de Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Global', 73, 77, 'LAGER', 10, 'Imperial Yeast', 'L13', 'MEDIUM_LOW', 8, 13, 'Wildly popular lager strain, produces a classic lager profile. The world''s most popular lager strain is ready for you. Global is an all-around solid lager strain that produces clean, bright and crispy lager beers with a very low ester profile. This strain is extremely powdery, so long lagering times or filtration is required for bright beer.', 'German Pils, Pre-Prohibition Lager, Dortmunder Export, Helles, Vienna Lager, American Amber Lager, Schwarzbier, Rauchbier, Maibock, Marzen, Doppelbock, Eisbock, American Lager, Czech Pilsner, Czech Amber Lager, Czech Dark Lager, Dunkels, Bock, Baltic Porter, Bière de Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Gnome', 74, 78, 'ALE', 12, 'Imperial Yeast', 'B45', 'MEDIUM', 18, 25, 'Versatile and unique Belgian ale yeast, excellent choice for Belgian pale ales or IPAs. Gnome is the yeast for brewing Belgian inspired beers in a hurry. This strain is extremely flocculent and drops out of the beer quickly after fermentation. Gnome produces a nice phenolic character that plays nicely with hops, as well as with caramel and toffee malt flavors. Great for Belgian ales that need to be crystal clear without filtration. Highly versatile, use Gnome in an array of Belgian beers.', 'Belgian IPA, Belgian Pale Ale, Blonde Ale, Trappist Single, Witbier, Bière de Garde, Saison, Belgian Golden Strong Ale, Belgian Dark Strong Ale, Belgian Dubbel, Belgian Tripel, Belgian Quad');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Harvest', 70, 74, 'LAGER', 10, 'Imperial Yeast', 'L17', 'MEDIUM', 10, 16, 'Brewers love this lager yeast strain for its versatility; it will impress you with it''s ability to ferment pretty much any lager style you throw at it. This great lager strain combines good flocculation characteristics with low sulfur and low diacetyl. Clean fermentations produce amazing bock, Helles, pilsner, dunkles, and just about any other lager style you throw its way. Fantastic choice for a house lager strain.', 'Helles, Dunkels, Bock, Vienna Lager, Doppelbock, German Pils, Pre-Prohibition Lager, Schwarzbier, Rauchbier, Dortmunder Export, Maibock, Marzen, American Amber Lager, Eisbock, American Lager, Czech Pilsner, Czech Amber Lager, Czech Dark Lager, Mexican Lager, Baltic Porter, Bière de Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('House', 73, 75, 'ALE', 10, 'Imperial Yeast', 'A01', 'HIGH', 17, 21, 'Extremely versatile English ale strain, allowing both malt and hops to shine. The best of both worlds, House is clean and allows malt and hops to shine. This strain is extremely versatile and flocculent enough to drop out of the beer quickly. Best strain choice for any and all English inspired recipes however, does extremely well in hopped up American styles too. House is clean at cold temperatures with increased esters as fermentation temperatures rise.', 'English IPA, Extra Special Bitter, Pale Ale, English Mild, Bitter, Stout, Sweet, Brown Porter, Irish Red Ale, Stout, Oatmeal, Stout, Tropical, British Strong Ale, English Barleywine, Old Ale, Stout, Foreign Extra, American IPA, Black IPA, American Pale Ale, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, Imperial IPA, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, Stout, Irish Dry, Scottish Ale, Wee Heavy, Cream Ale, American Wheat Beer, Blonde Ale, American Amber Ale, American Brown Ale, Hazy IPA, White IPA, California Common');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Independence', 72, 76, 'ALE', 12, 'Imperial Yeast', 'A15', 'MEDIUM', 16, 22, 'American ale yeast strain, slightly ester forward and loves to play with hops. Independence is the strain for bringing some new character into your hop-driven beers. Higher in esters than Flagship, this yeast will give some fruit character that will take your hoppy beers to a new level. While it shines in pale ales and IPAs, Independence is a great all-around strain and will also work well in stouts and English ales.', 'American IPA, American Pale Ale, Blonde Ale, Stout, Sweet, Stout, Oatmeal, Cream Ale, California Common, American Amber Ale, American Brown Ale, Black IPA, Hazy IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, Imperial IPA, American Barleywine, Irish Red Ale, Imperial Stout, American Strong Ale, Wheatwine, English Mild, Extra Special Bitter, Bitter, Pale Ale, Stout, Irish Dry, Brown Porter, English IPA, Scottish Ale, Stout, Tropical, British Strong Ale, English Barleywine, Old Ale, Stout, Foreign Extra, Wee Heavy, American Wheat Beer, White IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Joystick', 73, 77, 'ALE', 12, 'Imperial Yeast', 'A18', 'MEDIUM_HIGH', 16, 21, 'Clean American brewing yeast strain. Excellent choice for big, high alcohol, hoppy beers. This strain is a fast mover and can be used at the low end of the ale fermentation spectrum to keep it clean. Joystick is a great choice for big, high alcohol, malt forward beers but will shine just as well in a hoppy double IPA.', 'American Barleywine, American Strong Ale, Robust Porter, Imperial Stout, American Stout, American Amber Ale, American Brown Ale, Black IPA, Red Ale, Winter Seasonal Beer, California Common, Wheatwine, English Mild, Extra Special Bitter, American Pale Ale, Stout, Irish Dry, Cream Ale, American Wheat Beer, Blonde Ale, American IPA, Hazy IPA, Red IPA, Imperial IPA, Altbier');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Juice', 72, 76, 'ALE', 10, 'Imperial Yeast', 'A38', 'MEDIUM', 18, 23, 'The go-to for juicy, hazy, NE IPAs. Hardly a one-trick pony, it can also be a great choice as a house ale strain. Juicy. Fruity. Juice is the go-to strain for hazy, juicy New England style IPAs. The ester profile of Juice brings out the aromas and flavors of the new school hops and creates a beer that is greater than the sum of its parts. Resulting in a beer that is at once round in mouthfeel but retains a nice sharp citrus edge. Keep an eye on this strain, it likes to move to the top of fermentation and will climb out the fermenter if too full. This strain has demonstrated the need for higher wort dissolved oxygen (DO) levels than most ale strains. Target 20-25 ppm DO or set the oxygen regulator flow to 50 higher than normal.', 'Hazy IPA, American IPA, American Stout, English IPA, Extra Special Bitter, Bitter, Pale Ale, Stout, Irish Dry, Brown Porter, Stout, Oatmeal, Black IPA, Red IPA, White IPA, American Pale Ale, Red Ale, Robust Porter, Winter Seasonal Beer, Imperial IPA, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, English Mild, Irish Red Ale, Stout, Tropical, Cream Ale, American Wheat Beer, Blonde Ale, California Common, American Amber Ale, American Brown Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Kaiser', 73, 77, 'ALE', 10, 'Imperial Yeast', 'G02', 'LOW', 13, 18, 'Traditional Alt yeast strain however, this German ale strain can do just about anything. Kaiser is ready to produce an array of German-style beers. It will keep the beer clean and allow the delicate malt flavors and aromas to shine through. Characteristics of this strain make it a good choice for traditional Berliner Weisse fermentations. Kaiser is a low flocking strain, so expect long clarification times, but very low diacetyl levels.', 'Altbier, Kolsch, Berliner Weisse, Gose, Bière de Garde, Blonde Ale, Pale Ale, American IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Kveiking', 75, 85, 'KVEIK', 12, 'Imperial Yeast', 'A44', 'LOW', 24, 36, 'Blend of 3 kveik strains conquers wort, leaving tropical fruit flavors in its wake. Kveiking [Kuh-vahy-king] noun: A blend of three Kveik strains that can produce an insane amount of pineapple, guava and other exotic tropical fruit aromas. verb: Hopefully not an Old Norse term for an activity we should not be promoting. The Kveiking blend thrives in hot fermentations when big complex ester profiles are desired. A low pitch rate can be used to drive these aromatics even higher but the brewer should ensure this low pitch rate can be combined with a continuously high fermentation temperature. If the temperature drops too low, the corresponding level of attenuation can be low, with high terminal gravities. This blend contains flocculent and non-flocculent yeast strains, therefore the clarity of the final beers produced can be variable. Use this blend for anything from new school hazy IPAs to traditional Norwegian farmhouse brews. The Kveiking blend also works well when fermenting kettle soured worts for a strong tropical fruit character.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Loki', 75, 85, 'KVEIK', 10, 'Imperial Yeast', 'A43', 'MEDIUM_HIGH', 18, 38, 'Norwegian Voss Kveik Strain. Highly versatile, can be used in a wide variety of beer styles. A traditional Norwegian Kveik strain that has an extremely wide fermentation temperature range. This strain has been traditionally used in Norwegian farmhouse style beers however, due to it''s fermentation temp range can be used in a variety of beers from pseudo lagers, Belgian inspired, and hop forward beers. The possibilities seem endless when fermenting with Loki. On the cool end of the range Loki is super clean; producing little to no esters. On the high end of the fermentation range, 85-95F, it tends to produce a huge fruit ester profile.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Napoleon', 77, 83, 'ALE', 12, 'Imperial Yeast', 'B64', 'LOW', 18, 26, 'Classic strain to produce French Saison where a balance of fruit esters and spicy phenols are necessary. This yeast is an insane wort attenuator. Napoleon will destroy the sugars in your saison and farmhouse beers - even the ones in which most brewer''s strains have no interest. When all is said and done, Napoleon produces very dry, crisp beers with nice citrus aromas balanced by subtle black pepper phenols. Yeast settling times can be long, usually requiring filtration for bright beers. This strain tests positive for the STA1 gene via PCR analysis and is therefore considered to be Saccharomyces cerevisiae var. diastaticus', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('POG', 75, 85, 'KVEIK', 10, 'Imperial Yeast', 'A37', 'HIGH', 29, 38, 'Single isolate kveik known to produce huge tropical ester profile. After years of surviving in cold climates, this Kveik yeast is ready for the tropical lifestyle. When used at high temperatures, POG produces an extreme amount of tropical fruit aromas including pineapple and guava. At the lower end of the range, more delicate citrus, peach and kiwi aromas are noticeable. The beer style options are expansive for this yeast. Use it in a hazy/juicy IPA to complement the hops or use it in a sour fruited beer to maximize the extreme aromatics. POG likes to work fast at high fermentation temperatures. It is also strongly flocculent, which makes it great for a fast turnaround. This strain has demonstrated the need for higher wort dissolved oxygen (DO) levels than most ale strains. Target 20 ppm DO or set the oxygen regulator flow to ~50 higher than normal.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Pub', 64, 70, 'ALE', 10, 'Imperial Yeast', 'A09', 'VERY_HIGH', 21, 23, 'Beloved and highly flocculent British ale strain. Well suited for a variety of beer styles. Brewers swear by this strain to achieve super bright ales in a short amount of time. One of the most flocculent brewer''s strains around, Pub will rip through fermentation and then drop out of the beer quickly. Pub produces higher levels of esters than most domestic ale strains, making it an excellent choice for when balance between malt and yeast derived esters is necessary. Be sure to give beers made with Pub a sufficient diacetyl rest.', 'Extra Special Bitter, English IPA, English Mild, Bitter, Old Ale, Winter Seasonal Beer, American Pale Ale, Stout, Irish Dry, Brown Porter, Irish Red Ale, Stout, Oatmeal, British Strong Ale, English Barleywine, Cream Ale, American Wheat Beer, Blonde Ale, California Common, American Amber Ale, American Brown Ale, American IPA, Black IPA, Hazy IPA, Red Ale, American Pale Ale, Robust Porter, American Stout, Winter Seasonal Beer, Imperial IPA, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Rustic', 72, 76, 'ALE', 12, 'Imperial Yeast', 'B56', 'MEDIUM', 20, 27, 'Fantastic choice for a Belgian saison or farmhouse beer. This unique yeast can be used in your saison, farmhouse ale, or other Belgian styles where high ester levels are important. Rustic typically produces a lot of bubblegum and fruity/juicy aromas that compliment complex maltiness. Balanced by a light clove phenol profile, Rustic produces lovely flavor profiles indicative of those classic Belgain styles known and loved. This strain tests positive for the STA1 gene via PCR analysis and is therefore considered to be Saccharomyces cerevisiae var. diastaticus', 'Saison, Blonde Ale, Bière de Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Sour Batch Kidz', 80, 95, 'ALE', 12, 'Imperial Yeast', 'F08', 'LOW', 20, 24, 'An exclusive funky blend containing a low attenuating Belgian saison yeast, Lacto, and three Brett yeast strains. This blend is great for emulating lambics, Flanders reds, sour farmhouse ales and any other brew you would like to funk up. Keep your IBU''s under 3 to allow the lacto to work. Considering the components of this blend, allow for a long conditioning period of at least 6 months to really let the brett strains to shine. This blend contains a strain that tests positive for the STA1 gene via PCR analysis and is therefore considered to be Saccharomyces cerevisiae var. diastaticus.', 'Flanders Red Ale, Lambic, Oud Bruin, Gueuze');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Stefon', 73, 77, 'ALE', 10, 'Imperial Yeast', 'G01', 'LOW', 17, 23, 'Brewers love this traditional hefeweizen strain for any of their weizen beer needs! This is a traditional German hefeweizen strain used to produce world-class Weizen beers. Balanced with mild clove and prominent banana esters, this strain will produce amazing beers. Stefon produces a slightly higher level of acidity to give your beer a super crisp finish. Slightly underpitching will help increase the banana character.', 'Hefeweize, Weissbier, Weizenbock, Roggenbier');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Suburban Brett', 75, 80, 'BRETT', 12, 'Imperial Yeast', 'W15', 'LOW', 18, 23, 'Proprietary to Imperial, this brettanomyces strain produces lovely pie cherry and tropical aromas. Suburban Brett really shines when used in wood barrels and will produce complex and balanced aromas of sour cherry, dried fruit and balanced by a unique tropical fruit profile. It can be used for as a primary strain for brett only beers as well as a secondary aging strain. Maturation times tend to be on the quicker side for brett fermentations.', 'Brett Beer, Flanders Red Ale, Lambic, Gueuze, Oud Bruin, Old Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Tartan', 70, 75, 'ALE', 10, 'Imperial Yeast', 'A31', 'MEDIUM', 18, 21, 'Traditional Scottish brewers yeast strain, well suited for malt forward beers. Tartan is a traditional strain that accentuates the malt character of Scottish and other malt forward styles. But don''t put it in a corner, it can also be used for other styles and works well in IPAs due to its clean fermentation character. For a higher ester profile, use this ale yeast at the top end of the temperature range.', 'Wee Heavy, Red Ale, American Brown Ale, Cream Ale, American Wheat Beer, Blonde Ale, Black IPA, Robust Porter, American Stout, Winter Seasonal Beer, American Barleywine, Imperial Stout, American Strong Ale, Wheatwine, English Mild, Bitter, Extra Special Bitter, Pale Ale, Stout, Irish Dry, English IPA, Stout, Oatmeal, Stout, Tropical, British Strong Ale, English Barleywine, Old Ale, Stout, Foreign Extra, California Common, American Amber Ale, American IPA, Red IPA, American Pale Ale, Imperial IPA, Altbier');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Triple Double', 74, 78, 'ALE', 12, 'Imperial Yeast', 'B48', 'MEDIUM', 18, 25, 'Classic high gravity Belgain strain for Trappist-style ales. The perfect strain for your classic abbey ales. Triple Double produces moderate esters with low to no phenolic characteristics. This strain is tried and true and works perfectly in a production environment. Keep an eye on Triple Double, it likes to sit on top of the wort throughout fermentation which may result in a slower than normal fermentation. This strain is very alcohol tolerant, so don''t be afraid to throw high gravity worts its way.', 'Belgian Tripel, Belgian Golden Strong Ale, Belgian Dubbel, Belgian Quad, Trappist Single, Belgian Dark Strong Ale, Blonde Ale, Belgian Pale Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Urkel', 71, 75, 'LAGER', 10, 'Imperial Yeast', 'L28', 'MEDIUM', 11, 14, 'Excellent choice for your Czech lager fermentations. Urkel allows for a nice balance between hops and malt. This strain can be slightly sulphery during fermentation, but it cleans up during lagering. Fermentation at the higher end of the range will produce a beer with minimal sulfur and a light ester profile with that classic Czech edge you are looking for.', 'Czech Pilsner, Czech Amber Lager, Czech Dark Lager, American Lager, Pre-Prohibition Lager, Schwarzbier, American Lager, German Pils, Dunkels, Helles, Mexican Lager, Vienna Lager, Rauchbier, Dortmunder Export, Maibock, Bock, Marzen, Baltic Porter, Doppelbock, Eisbock, Bière de Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Whiteout', 72, 76, 'ALE', 10, 'Imperial Yeast', 'B44', 'MEDIUM_LOW', 17, 22, 'The go-to brewing yeast strain for wit beers. Whiteout produces an excellent balance of spicy phenolic character and esters. Along with the necessary aromatics, this strain produces a significant amount of acidity which is perfect for wits and other light colored Belgian ales. Whiteout can be flocculent during fermentation, then become non-flocculent at the end. This may lead to slower than normal fermentation.', 'Hefeweizen, Witbier, Belgian IPA, Trappist Single, Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Voyager', 0.0, 0.0, 'ALE', 0.0, 'Imperial Yeast', 'A05', 'MEDIUM', 0.0, 0.0, NULL, NULL);
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Julius', 0.0, 0.0, 'ALE', 0.0, 'Imperial Yeast', 'A34', 'MEDIUM', 0.0, 0.0, NULL, NULL);
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew Abbaye', 74.7127, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'MEDIUM_HIGH', 17, 25, 'LalBrew Abbaye is an ale yeast of Belgian origin. Selected for its ability to ferment Belgian style beers ranging from low to high alcohol, LalBrew Abbaye produces the spiciness and fruitiness typical of Belgian and Trappist style ales. When fermented at higher temperatures, typical flavors and aromas include tropical, spicy and banana. At lower temperatures, LalBrew Abbaye produces darker fruit aromas and flavors of raisin, date, and fig.', 'Belgian White, Belgian Blonde, Belgian Golden, Dubbel, Tripel, Quad');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew Belle Saison', 74.7127, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'LOW', 15, 35, 'LalBrew Belle Saison is a Belgian-style ale yeast selected specifically for its ability to create Saison-style beers. Belle Saison is a diastaticus strain that allows the brewers to achieve the high attenuation characteristic of this classic style. Designed for warm-temperature fermentation true to traditional Farmhouse production methods, beers brewed with LalBrew Belle Saison are fruity, spicy and refreshing.', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew BRY-97', 68.9655, 0.0, 'ALE', 11, 'Lallemand', 'BRY-97', 'HIGH', 15, 22, 'LalBrew BRY-97 is an American West Coast-style ale yeast that was selected from the Siebel Institute Culture Collection for its ability to produce high quality ales. LalBrew BRY-97 is a neutral strain with a high flocculation ability that can be used to make a wide variety of American-style beers. Through expression of a beta-glucosidase enzyme, LalBrew BRY-97 can promote hop biotransformation and accentuate hop flavor and aroma.', 'Cream Ale, American Wheat, Scotch Ale, American Pale Ale, American Amber, American Brown, American IPA, American Stout, Russian Imperial Stout, Imperial IPA, Roggen/Rye, Old Ale, American Barleywine');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew CBC-1', 0.0, 0.0, 'ALE', 0.0, 'Lallemand', 'CBC-1', 'MEDIUM', 15, 25, 'LalBrew CBC-1 has been specifically selected from the Lallemand Yeast Culture Collection for its refermentation properties and is recommended for Cask and Bottle Conditioning. LalBrew CBC-1 referments beer efficiently due to its high resistance to alcohol and pressure. The flavor is neutral, therefore the original character of the beer is preserved. The yeast will settle and form a tight mat at the end of refermentation. LalBrew CBC-1 can also be used for primary fermentation of dry ciders or mead. Maltotriose is not metabolized during primary fermentation of beer, so LalBrew CBC-1 is well suited for sweeter fruit beers or fullbodied, malty ales.', 'fruit beers, dry cider, mead');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew Diamond Lager', 74.7127, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'HIGH', 10, 15, 'LalBrew Diamond Lager yeast is a true lager strain originating in Germany. Chosen for its robust character, LalBrew Diamond Lager yeast delivers excellent fermentation performance, and has the ability to  produce clean, authentic lagers.', 'Munich Helles, Dortmunder Export, German Pilsner, Bohemian Pilsner, American Pilsner,  Vienna Lager, Oktoberfest/Marzen, Dark American Lager, Munich Dunkel, Schwarzbier, Traditional Bock, Doppelbock, Eisbock, California Common');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew Koln', 66.6667, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'MEDIUM_HIGH', 12, 20, 'LalBrew Koln is ideal for brewing traditional Kolsch-style beers and other neutral ales.  The neutral character of this strain accentuates delicate hop aromas while imparting subtle fruity esters.  Through expression of a beta-glucosidase enzyme LalBrew Koln can promote hop biotransformation and accentuate hop flavor and aroma. Colder fermentations will be more neutral in character, while warmer fermentations will have more fruit-forward ester profile.', 'Kolsch, IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew London', 74.7127, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'LOW', 18, 22, 'LalBrew London is a true English ale strain selected for reliable fermentation performance and moderate  ester production that lets the flavors and aromas of malt and hops shine through. LalBrew London was  selected from the Lallemand yeast culture library, and is an excellent choice for brewing authentic heritage UK styles.', 'Pale Ale, Bitters, Mild Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew Munich Classic', 68.9655, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'LOW', 17, 22, 'LalBrew Munich Classic is a Bavarian wheat beer strain that can easily express the spicy and estery aroma profile typical to German wheat beer styles. This strain is simple to use over a wide range of recipe variations and fermentation conditions, making it a great choice for a number of traditional styles of wheat beer. A true top cropping yeast, LalBrew Munich Classic yeast can be skimmed off the top of classic open fermentation vessels in the traditional manner.', 'Weizen/Weissbier, Dunkelweizen, Weizenbock');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew New England', 66.6667, 0.0, 'ALE', 11, 'Lallemand', 'LB-NE', 'MEDIUM', 15, 22, 'LalBrew New England is an ale strain selected specifically for its ability to produce a unique fruit forward ester profile desired in East Coast styles of beer. A typical fermentation with LalBrew  New England will produce tropical and fruity esters, notably stone fruits like peach. Through expression of a β-glucosidase enzyme, LalBrew New England can promote hop biotransformation and accentuate hop flavor and aroma. LalBrew New England exhibits medium to high attenuation with medium flocculation, making it a perfect choice for East Coast style ales.', 'Hazy IPAs, Pale Ales, IPAs');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew Nottingham', 74.7127, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'HIGH', 10, 22, 'LalBrew Nottingham is an English style ale yeast selected for its high performance and versatility for a wide variety of styles and fermentation conditions. Traditional styles brewed with this yeast include but are not limited to Pale Ales, Ambers, Porters, Stouts and Barleywines. LalBrew Nottingham is a relatively neutral ale strain that is stress tolerant making it a good choice for high gravity, sour and other challenging fermentation conditions.', 'Golden Ale, Kolsch, Lagers, IPA, Imperial Stout, Pale Ales, Ambers, Porters, Stouts, Barleywines');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew Voss', 68.9655, 0.0, 'KVEIK', 0.0, 'Lallemand', NULL, 'VERY_HIGH', 25, 40, 'Kveik is a Norwegian word meaning yeast. In the Norwegian farmhouse tradition, kveik was preserved by drying and passed from generation to generation. Kveik is the original, traditional dried yeast! The LalBrew Voss strain was obtained from Sigmund Gjernes (Voss, Norway), who has maintained this culture using traditional methods since the 1980s and generously shared it with the wider brewing community. LalBrew Voss supports a wide range of fermentation temperatures between 25-40°C (77-104°F) with a very high optimal range of 35-40°C (95-104°F). Very fast fermentations are achieved within the optimal temperature range with full attenuation typically achieved within 2-3 days. The flavor profile is consistent across the entire temperature range: neutral with subtle fruity notes of orange and citrus. Flocculation is very high producing clear beers without filtration or use of process aids.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew Windsor', 66.6667, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'LOW', 15, 22, 'LalBrew Windsor ale yeast is a true English strain that produces a balanced fruity aroma and imparts a slight fresh yeasty flavor. Beers created with Windsor are usually described as full-bodied, fruity English ales. Brewers choose LalBrew Windsor to produce beers that range from Pale Ale to Porter with moderate alcohol levels and the flavor and aroma characteristics of the best traditional ales.', 'Pale Ale, Milds, Bitters, Irish Reds, English Brown Ales, Porters, Sweet Stouts');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LalBrew Wit', 57.4713, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'MEDIUM_HIGH', 17, 22, 'LalBrew Wit yeast is a relatively neutral strain which can be used to produce a wide variety of wheat beer styles. Ester and phenol production is lower than for traditional hefeweizen strains such as Munich Classic. LalBrew Wit provides a baseline profile of banana and spice aromas, but leaves space for the brewer to showcase other spice additions typical of Belgian style beers.', 'Belgian Witbier, American Wheat, Berliner Weiss, Gose, Hefeweizen, Dunkelweis, Weizenbock');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Prise de Mousse Wine Yeast', 74.7127, 0.0, 'ALE', 18, 'Lallemand', 'EC-1118', 'MEDIUM_HIGH', 10, 30, 'Lalvin EC-1118 is the perfect yeast for sparkling, fruity wines or to make cider. Ideal for low temperature fermentation and fast fermentation. Lalvin EC-1118 (AKA Prise de Mousse / Saccharomyces bayanus) Champagne yeast is a low foaming, vigorous and fast fermenter good for both reds and whites. It is also ideal for ciders and sparkling wines. A very competitive yeast that will inhibit wild yeasts. It will restart stuck fermentations because of good alcohol and sulfite tolerance. EC-1118 yeast is a very neutral strain that will have very little effect on the varietal character of the grape. A popular strain that ferments fully and flocculates well producing compact lees. Good for cooler fermentations. Champagne, dry reds, whites, ciders and sparkling.', 'Wine, Cider, Champagne');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Sourvisiae', 68.9655, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'MEDIUM_HIGH', 15, 22, 'Sourvisiae is a bioengineered ale yeast strain (Saccharomyces cerevisiae) capable of producing lactic acid during fermentation to provide brewers with an easy, reproducible, and mono-culture product for sour-style beer production. Sourvisiae contains a single genetic modification, a lactate dehydrogenase gene from a food microorganism, which enables the yeast to produce high levels of lactic acid, the main compound that gives sour beers their flavor. Sourvisiae allows the brewer to ferment and sour the beer in one simple step, reducing cross-contamination risks, lowering costs, cutting total process time, and allowing brewers to obtain a consistent product. The brewing process is conducted without any modifications; Sourvisiae is pitched just like conventional yeast and ferments in a normal fermentation time. Sourvisiae does not produce other flavor compounds associated with Brettanomyces, Lachancea, or Lactic Acid Bacteria, providing a cleaner and more reproducible souring process, with much shorter fermentation times.', 'Brett, Sour, Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('WildBrew Philly Sour', 74.7127, 0.0, 'ALE', 0.0, 'Lallemand', NULL, 'HIGH', 20, 25, 'WildBrew Philly Sour is a unique species of Lachancea selected from nature by University of the Sciences in Philadelphia, PA, USA. Philly Sour produces moderate amounts of lactic acid in addition to ethanol in one simple fermentation step. This first yeast in the WildBrew series is a great choice for innovative, sessionable sour beers with refreshing acidity and notes of stone fruit. With high attenuation, high flocculation and good head retention, WildBrew Philly Sour has resistance to hops which make it perfect for Sour IPA''s.', 'Berliner Weiss, Gose, American Lambic Style, American Wild Ales, Sour IPAs');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bavarian Wheat', 70, 75, 'ALE', 23.0769, 'Mangrove Jack', 'M20', 'LOW', 15, 30, 'Deliciously smooth, light golden in colour, full bodied aromas of vanilla and banana and a lingering aftertaste. This yeast produces a silky mouth feel and rich body.', 'Hefeweizen, Kristal Weizen, Dunkel Weizen and more');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Ale', 82, 88, 'ALE', 0.0, 'Mangrove Jack', 'M41', 'MEDIUM', 18, 28, 'Spicy and phenolic, this yeast emulates the intensity and complexity of some of the best monastic breweries in Belgium, high attenuation and alcohol tolerance allows you to brew a huge range of Belgian beers. Beers fermented with this yeast exhibit excellent classic Belgian ale flavour, clove hints with a multitude of fruit esters, alcohol and banana character.', 'Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Wit', 70, 75, 'ALE', 0.0, 'Mangrove Jack', 'M21', 'MEDIUM_LOW', 18, 25, 'A traditional, top-fermenting yeast that has a good balance between fruity esters, and warming spice phenolics. The yeast will leave some sweetness, and will drop bright if left long enough. This yeast has a slightly suppressed Belgian character presenting as phenolic and dry, fruity and very complex character. The mouthfeel is smooth, light, dry and crisp', 'Witbier, Spiced Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bohemian Lager', 72, 76, 'ALE', 0.0, 'Mangrove Jack', 'M84', 'HIGH', 10, 15, 'A bottom-fermenting lager yeast characterised by its dry and clean palate typical of traditional Czech brewing. Produces soft, delicate and well balanced beers.  Hop and malt character will be enhanced and supported by moderate to full body. In wort with simple malt bills, delicate malt flavours will survive. Beer fermented with this strain is generally rich and chewy without being heavy at all. Light and delicately balanced beers call for this strain. Lagering periods as short as 4 weeks may produce acceptable beer but allowing it to lager for 6-8 weeks, will result in beer that is richer and smoother with a more refined aroma and flavour.', 'German Pilsners, Porters, American Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('California Lager', 77, 82, 'ALE', 0.0, 'Mangrove Jack', 'M54', 'HIGH', 18, 20, 'California Lager yeast produces clean and crisp lagers, this yeast is excellent for producing anything from a hoppy pilsner to a helles, allowing excellent malt and hop character to be expressed. California Lager yeast produces a clean lager aroma without the associated sulphur, this yeast is perfect for most kinds of lager.', 'Lagers, California Common');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Empire Ale', 70, 75, 'ALE', 0.0, 'Mangrove Jack', 'M15', 'HIGH', 18, 22, 'A top-fermenting ale yeast suitable for a variety of full bodied ales, with exceptional depth. Ferments with full, rich dark fruit flavors.', 'Scottish Heavy Ales, American Amber Ales, Sweet Stouts');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('French Saison Ale', 85, 90, 'ALE', 14, 'Mangrove Jack', 'M29', 'MEDIUM', 26, 32, 'French Saison yeast is an exceptional, highly attenuative top-fermenting ale yeast, creating distinctive beers with spicy, fruity and peppery notes. Ideal for fermentation of farmhouse style beer. This is a highly characterful yeast strain that will dominate all but the highest hopping rates and complex malt bills. Beers fermented with this yeast will tend to be dry in finish, often with a slight drying acidity and peppery notes, aiding drinkability at higher alcohol levels. Higher alcohol beers may have an increased ester production and warming alcohol notes.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Liberty Bell Ale', 74, 78, 'ALE', 0.0, 'Mangrove Jack', 'M36', 'HIGH', 18, 23, 'A top fermenting ale yeast suitable for a wide variety of hoppy and distinctive style beers. This strain produces light, delicate fruity esters and helps to develop malt character.', 'Pale Ales, Extra Special Bitters, Golden Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('New World Strong Ale', 77, 82, 'ALE', 0.0, 'Mangrove Jack', 'M42', 'VERY_HIGH', 16, 22, 'A top-fermenting ale strain suitable for many types of ales of all strengths. Ferments with a neutral yeast aroma to ensure the full character of the malts and hops are prominent in each beer.', 'IPA, Porters, Russian Imperial Stouts');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('US West Coast', 74.7127, 0.0, 'ALE', 11, 'Mangrove Jack', 'M44', 'HIGH', 15, 23, 'A top fermenting ale strain suitable for American style ales. This yeast produces an exceptionally clean flavor, ideal for when you want the hop character to really punch through. Beers fermented with this strain will finish dry, and very light beers will not be thin or watery. Acidity will be low, and mouthfeel will be light and soft on the palate with a smooth non-astringent texture. As this strain is highly flocculant and resilient and not prone to autolysis, it is excellent for cask or bottle conditioning.', 'Americal Pale Ale, Double IPA, American Imperial Stout');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Workhorse', 74.7127, 0.0, 'ALE', 0.0, 'Mangrove Jack', 'M10', 'MEDIUM', 15, 32, 'A top fermenting yeast which produces a clean, crisp flavour suitable for a wide variety of styles with different fermenting temperatures. This versatile yeast is well suited to making cask or bottle conditioned beer.', 'Lager, Baltic Porter');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Muntons Premium Gold', 72, 75, 'ALE', 8, 'Muntons', NULL, 'MEDIUM', 18, 21, 'Muntons Premium Gold brewer''s yeast has proved itself for many years as a particular favorite for brewers of all malt beer recipes or recipes that call for a high percentage of malt in the grist formulation. It has the ability to resist ‘sticking'' a problem often experienced with all malt recipe beers. And it has excellent crusting characteristics; the yeast residue sticks to the bottom of the fermenter, bottle or pressure barrel in a firm mass, resisting disturbance, meaning you get more beer, less waste.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Muntons Standard Ale', 72, 75, 'ALE', 8, 'Muntons', NULL, 'MEDIUM', 18, 21, 'Muntons brewer''s yeast has been a popular favourite for many years amongst the homebrew community worldwide, gaining an enviable reputation for its consistent healthy performance, its hardy nature and its clean finish. Muntons brewer''s yeast is a dried brewer''s yeast that produces a powdery flocculation with an apparent attenuation of 70%. Ideal fermentation temperature is between 64° - 70°F to produce an alcohol tolerance of 8% ABV. It provides low ester formation but with relatively high residual sugar giving good body and mouth feel.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('ABBEY ALE C', 74, 78, 'ALE', 12, 'Omega Yeast', 'OYL-018', 'MEDIUM_LOW', 20, 26, 'The Abbey Ale C''s Trappist origin is best coupled with a little monastic patience: a notably low-flocculator, it is highly attenuating, with a fruity profile and lightly perceptible spiciness, as well as often significant banana character.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('ALL THE BRETTS', 85, 0.0, 'ALE', 11, 'Omega Yeast', 'OYL-218', 'LOW', 20, 29, 'An evolving blend of many of the Brett strains in the Omega collection. Use this yeast in the secondary and expect high attenuation and a fruity and funky complexity that continues to develop over time.', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('ALT', 73, 77, 'ALE', 11, 'Omega Yeast', 'OYL-001', 'LOW', 13, 20, 'An enthusiastic top cropper from Düsseldorf. This strain ferments at low temperatures with a clean, low ester profile. Light fruit emerges at higher temperatures. Features quick maturation. Yeast stays in suspension. Little to no diacetyl. Try also Kolsch II (OYL-044) or even West Coast Ale I (OYL-004)', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('AMERICAN LAGER', 73, 77, 'ALE', 9, 'Omega Yeast', 'OYL-103', 'MEDIUM', 9, 14, 'This strain is thought to be from one of the US''s oldest family-owned breweries in Minnesota. More flocculent and complex in flavor than many of its lager peers, including American Pilsner (OYL-102).', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('AMERICAN PILSNER', 71, 75, 'ALE', 9, 'Omega Yeast', 'OYL-102', 'MEDIUM', 9, 13, 'Thought to be from the most popular beer in America. A mild, neutral, smooth lager strain, dry and clean with good malt and very slight apple characteristics.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('AMERICAN WHEAT', 74, 78, 'ALE', 10, 'Omega Yeast', 'OYL-002', 'LOW', 14, 23, 'Energetically top cropping, this powerful fermenter leaves behind a light, tart and refreshing, crisp character. Fairly clean and lightly dry, it excels particularly at American styles. The small amount of sulfur produced during fermentation conditions out.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bavarian Wheat I', 72, 78, 'ALE', 10, 'Omega Yeast', 'OYL-025', 'LOW', 19, 22, 'A spicier alternative to Hefeweizen Ale I (OYL-021) for the production of German wheat beers, Bavarian Wheat I imparts a more phenolic profile with predominant notes of clove and pepper.', 'Hefeweizen, Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bavarian Wheat II', 70, 76, 'ALE', 10, 'Omega Yeast', 'OYL-034', 'LOW', 18, 24, 'A big top cropper and a low flocculator, with banana, light pear, apple/plum, clove and vanilla. Another great wheat beer option with a more complex aroma relative to Hefeweizen Ale I (OYL-021). Up the esters with higher temperatures, wort density and lower pitch rate, or keep muted at lower temperatures to show clove. Sulfur conditions out.', 'Hefeweizen, Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BAYERN LAGER', 72, 76, 'ALE', 9, 'Omega Yeast', 'OYL-114', 'MEDIUM', 11, 17, 'Thought to come from Munich''s oldest, traditional and vintage-vibed brewery. This clean, crisp, lager strain ferments well at a wide range, has good flocculation, and has both low sulfur and low diacetyl production.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BELGIAN ALE A', 72, 85, 'ALE', 12, 'Omega Yeast', 'OYL-024', 'HIGH', 18, 26, 'As one of the few highly flocculent Belgian ale strains, this strain makes a great Belgian house strain. It is brewery friendly, crops easily and has a well-rounded flavor profile with balanced fruitiness and phenolics. Esters increase with upward temperatures.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BELGIAN ALE D', 74, 78, 'ALE', 11, 'Omega Yeast', 'OYL-019', 'LOW', 18, 27, 'This devil of a strain is thought to be from the famous strong golden ale brewer. The bargain is classic sacrifice for pay off: tricky fermentation kinetics for rich flavor profile and aroma complexity. If tempted by this flavorful but low flocculating stop-and-starter, let us know and we can help with a tip or two. Belgian Golden Strong (OYL-056) is a great alternative with a similar flavor profile, but more reliable fermentation performance.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BELGIAN ALE DK', 73, 80, 'ALE', 10, 'Omega Yeast', 'OYL-049', 'MEDIUM', 19, 21, 'A mild Belgian-charactered ale yeast with light toasty or biscuit-like aromatic maltiness. Can produce a touch of lagery sulfur', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BELGIAN ALE O', 74, 80, 'ALE', 12, 'Omega Yeast', 'OYL-046', 'MEDIUM', 19, 22, 'With balanced fruit and phenolics, this Trappist ale yeast''s clean and dry profile carries a signature sharp tasting, slightly acidic finish that the thought-to-be brewery of origin describes as acidulous. Welcomes high gravity. Belgian profile is toned down compared to Abbey Ale C (OYL-018) and Belgian Ale W (OYL-028).', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BELGIAN ALE R', 73, 82, 'ALE', 12, 'Omega Yeast', 'OYL-020', 'MEDIUM', 18, 24, 'This has low phenolics for a Belgian strain, with stone fruit and light, floral or rose-like aromas. Sulfur produced dissipates with conditioning. Accentuated flavors and aromas occur at higher temps, and in a high gravity environment.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BELGIAN ALE W', 74, 78, 'ALE', 11, 'Omega Yeast', 'OYL-028', 'MEDIUM', 18, 26, 'An eruptive top cropper displaying nice fruit and rustic phenolics. This reliable Belgian strain is a good flocculator with a wide temperature range. Three famous brewers ferment this on vastly different schedules, showing the varied outcomes available.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BELGIAN GOLDEN STRONG', 90, 95, 'ALE', 14, 'Omega Yeast', 'OYL-056', 'LOW', 20, 24, 'Perfectly suited for the production of high-gravity Belgian ales where a dry finish is desired. A mellow phenolic character is balanced by an ester profile of pear and light banana, while high levels of glycerol production ensure a round mouthfeel even at very low finishing gravity. Consistently reaches greater than 90 apparent attenuation without sluggishness or stalling.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BELGIAN SAISON I', 76, 80, 'ALE', 12, 'Omega Yeast', 'OYL-027', 'LOW', 21, 35, 'Well regarded as a farmhouse ale strain despite fickle fermentation behavior. It has fruity complexity, good phenolics and a tart and dry finish. It''s better at warm fermentation temperatures, but is still well known to stall around 1.030. Try using an additional strain to aid attenuation, or the more reliable Saisonstein''s Monster (OYL-500), Belgian Saison II (OYL-042) or French Saison (OYL-026).', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BELGIAN SAISON II', 74, 79, 'ALE', 12, 'Omega Yeast', 'OYL-042', 'MEDIUM', 21, 29, 'Thought to originate from a small, sophisticated, Belgian brewer''s spelt saison. It is earthy, spicy, peppery, tart and dry, with tropical fruit and citrus at warm fermentation temperatures. A perfect strain for farmhouse ales and saisons. It favors pitching in the upper 60s or low 70s, and free-rising from there.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Wheat', 72, 76, 'ALE', 12, 'Omega Yeast', 'OYL-029', 'MEDIUM', 18, 23, 'This strain is great for a wheat beer with more ester complexity than Hefeweizen Ale I (OYL-021) and Hefeweizen Ale II (OYL-022). The strain features apple, bubblegum, plum, and a lightly tart and dry finish. It supports malt and hop flavors well.', 'Hefeweizen, Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BIERE DE GARDE', 74, 79, 'ALE', 9, 'Omega Yeast', 'OYL-039', 'LOW', 21, 29, 'Lightly phenolic, fruity, dry, delicately tart and a very low flocculator, this presents much like a saison strain. Try this for Bière de Garde, or a Belgian or French farmhouse ale. In fact, a clean-bodied Bière de Garde can be achieved with any lager strain here at the warm end of its temperature range. For farmhouse, try also French Saison (OYL-026) or Belgian Saison II (OYL-042)', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRETT BLEND #1 WHERE DA FUNK?', 78, 88, 'ALE', 11, 'Omega Yeast', 'OYL-210', 'VERY_LOW', 20, 27, 'One Brett-famous Colorado brewery strain plus two uniquely funky Sacch strains result in huge tropical fruit aroma (fades a bit during conditioning) with a wide temperature range. Very dry (consider flaked oats for body). Develops mild funk and low acid even with extended aging. Pairs well with fruity aroma hops for a unique pale ale.', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRETT BLEND #2 BIT O''FUNK', 85, 0.0, 'ALE', 11, 'Omega Yeast', 'OYL-211', 'VERY_LOW', 20, 27, 'This blend contains the two Saccharomyces strains from Brett Blend #1 for primary fermentation and is spiked with Brettanomyces Bruxellensis (OYL-202) for development of moderate funk during a secondary fermentation. The bit ‘o funkiness will take extended time (3+ months) to develop.', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRETT BLEND #3 BRING ON DA FUNK', 85, 0.0, 'ALE', 11, 'Omega Yeast', 'OYL-212', 'VERY_LOW', 20, 27, 'Two Sacch strains from Brett Blend #1 (OYL-210) spiked with both brux and lambicus, plus two additional Brett isolates from a Brett-famous Colorado brewery, plus two Brett isolates from an intense Belgian source equals a funky, fruity, complex, 8-strain composition. Brett character develops over time (as will acid production if exposed to oxygen)', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRETTANOMYCES BRUXELLENSIS', 70, 85, 'ALE', 10, 'Omega Yeast', 'OYL-202', 'LOW', 29, 18, 'First classified in 1904, Bretts are crucial in secondary fermentation for Belgian styles, consuming sugars that Sacchs leave behind. Brett Bruxellensis contributes medium Brett intensity with classic barnyard earthiness and a light medicinal quality. See also: Brett Claussenii (OYL-201), Brett Lambicus (OYL-203), and three Funk blends (OYL-210, 211, 212).', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRETTANOMYCES CLAUSSENII', 70, 85, 'ALE', 10, 'Omega Yeast', 'OYL-201', 'LOW', 29, 18, 'The mildest on the Brett funkiness spectrum, Brett Claussenii presents more of a leathery earthiness and some pineapple—both characteristics that are contributed in large part by the aroma alone. It does its best work as a secondary yeast. See also: Brett Bruxellensis (OYL-202), Brett Lambicus (OYL-203) and three Funk blends (OYL-210, 211, 212)', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRETTANOMYCES LAMBICUS', 70, 85, 'ALE', 10, 'Omega Yeast', 'OYL-203', 'LOW', 29, 18, 'Dive in deep with horsey, spicy, cherry pie funk in this significant Brett strain— best in secondary pitches. See also: Brett Bruxellensis (OYL-202), Brett Claussenii (OYL-201), three Funk blends (OYL-210, 211, 212), All The Bretts (OYL-218) or our farmhouse blend: C2C Farmhouse (OYL-217).', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRITISH ALE I', 70, 80, 'ALE', 10, 'Omega Yeast', 'OYL-006', 'MEDIUM_HIGH', 18, 22, 'A productive, brewery friendly, top cropper attributed to a historic London brewery whose lab once hosted Louis Pasteur. It drops fast and clear, and is clean and crisp at low temperatures with heightened esters and a lightly tart, dry finish at upper ranges. Try also British Ale II (OYL-007) for less attenuation and enhanced malts, or British VIII (OYL-016)', 'Ales, British Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRITISH ALE II', 68, 72, 'ALE', 10, 'Omega Yeast', 'OYL-007', 'MEDIUM_HIGH', 18, 24, 'Like British Ale I (OYL-006), this English brewery strain is thought to be from the historical London brewery that Louis Pasteur visited. It is a strong fermenter, brewery friendly, flexible, leaves near spotless clarity, and has more fruit-like esters and malt than British Ale I. Select for malt and fruit at higher fermentation temperatures or a clean profile at lower temperatures.', 'Ales, British Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRITISH ALE III', 67, 74, 'ALE', 10, 'Omega Yeast', 'OYL-008', 'HIGH', 18, 23, 'This is a top cropping, complex and malty strain. A shy starter, it''s slow but steady to ferment and a notorious diacetyl maker. Despite its finicky nature, its noteworthy esters match well with English style ales. It is highly flocculent and clears extremely well without filtration.', 'Ales, British Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRITISH ALE IV', 69, 76, 'ALE', 10, 'Omega Yeast', 'OYL-010', 'MEDIUM_LOW', 21, 24, 'Nuances of apple, clover honey and pear and a light mineral quality for great character presentation in English styles, particularly bitters. Not very flocculent compared to a lot of English strains. Filtration recommended.', 'Ales, British Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRITISH ALE V', 71, 75, 'ALE', 10, 'Omega Yeast', 'OYL-011', 'HIGH', 18, 23, 'A good top cropper thought to be from a famous Manchester bitters maker. Its residual sweetness pairs popularly with the signature huge, fruity hop flavor and aroma of the NEIPA. Alternately, try DIPA (OYL-052) for slightly less residual sweetness', 'Ale, British Ales, IPA, Hazy IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRITISH ALE VI', 73, 76, 'ALE', 10, 'Omega Yeast', 'OYL-013', 'HIGH', 17, 24, 'British Ale VI sports a classic British character—reserved but witty, with a rather high tolerance for alcohol. Crisp, clean, malty and with a mostly dry finish. A good flocculator.', 'Ales, British Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRITISH ALE VII', 67, 71, 'ALE', 9, 'Omega Yeast', 'OYL-014', 'HIGH', 18, 22, 'A well behaved, reasonably productive flocculator that leaves a clear bodied beer. This strain produces very clean, well balanced ales that are both significantly malty and have esters reminiscent of stone fruit with dry, nutty tones at the back end. Think compatibility with cask ales, for example.', 'Ales, British Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRITISH ALE VIII', 67, 71, 'ALE', 9, 'Omega Yeast', 'OYL-016', 'VERY_HIGH', 18, 22, 'A ridiculously thorough flocculator thought to be from a highly regarded English ESB. This strain has unique fruitiness and noticeable finishing sweetness. Drops out quickly and completely. Easy to crop, but needs a diacetyl rest. To enhance the fruit, ferment up at the recommended temperature ceiling.', 'Ales, British Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('C2C AMERICAN FARMHOUSE', 70, 85, 'ALE', 10, 'Omega Yeast', 'OYL-217', 'LOW', 20, 27, 'A coast to coast blend of one saison strain from a famous Northeast U.S. brewery and one Brett strain from a Northwest U.S. brewery. The blend results in a fast developing fruity and funky farmhouse ale.', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('CL-50 ALE', 74, 76, 'ALE', 10, 'Omega Yeast', 'OYL-041', 'LOW', 16, 21, 'Producing a notably big-body and soft texture, this versatile, well-attenuating strain''s profile is a launch pad for the gamut of malt and hop characteristics. It achieves substantial maltiness without being overly sweet.', 'Pale Ale, Brown Ale, Red Ale, IPA, Stout, Porter, Cream Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('DANISH LAGER', 73, 77, 'ALE', 9, 'Omega Yeast', 'OYL-104', 'LOW', 8, 13, 'A powdery low flocculator, this strain produces a crisp and dry, soft and round profile that''s great for supporting hop flavors. Ferments relatively cool and has low attenuation. Allow for long conditioning to help clear. Good in Dortmund lagers, Munich helles, and American lagers.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('DIPA ALE', 72, 80, 'ALE', 11, 'Omega Yeast', 'OYL-052', 'MEDIUM_LOW', 18, 22, 'A strong fermenter popularly referred to as Conan. Its peach, apricot and pineapple notes are steroids for hops, complementing modern fruity hop profiles in particular. A diacetyl rest is suggested if  fermented in the lower temperature range.', 'IPA, Double IPA, Pale Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('EAST COAST ALE', 70, 75, 'ALE', 10, 'Omega Yeast', 'OYL-032', 'MEDIUM_LOW', 20, 23, 'Thought to be the famous Bostonian strain. It is suitable for a broad range of beer styles with an American spin. Using West Coast Ale I (OYL-004) for comparison, it is a little tart and slightly muting of hop bitterness. Slightly less flocculent and attenuating, too, but every bit as versatile, carrying an overall clean and neutral flavor character.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('ESPE KVEIK', 75, 80, 'KVEIK', 12, 'Omega Yeast', 'OYL-090', 'MEDIUM', 20, 37, 'Originating from the village of Grodås in Norway, Espe offers the unique profile of lychee, pear, and tropical fruit cup. The strain bolsters the sweet aromatics of modern IPAs, but is versatile enough for your flagship pale ale or seasonal brew. Espe is most expressive when fermented at 90°F+ (32°C+), but still reveals its character at lower ale-pitching temperatures.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('FRENCH SAISON', 80, 90, 'ALE', 12, 'Omega Yeast', 'OYL-026', 'LOW', 18, 25, 'This citrusy, lightly phenolic saison strain is so attenuative and reliable in performance that people joke it could ferment a shoe. The French Saison strain results in great body consistency. It is good for any of the characteristically aromatic Belgian styles and is highly compatible with hops and spice aromas.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('GERMAN BOCK', 70, 76, 'ALE', 10, 'Omega Yeast', 'OYL-111', 'MEDIUM', 9, 13, 'Thought to be from the famous Alpine brewery in Aying, Bavaria. This is a versatile, malty-charactered lager strain that balances malt and hop flavors well. It is superb for bocks, doppelbocks, Oktoberfest lagers, helles and a favorite for American pilsners, too.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('GERMAN LAGER I', 73, 77, 'ALE', 9, 'Omega Yeast', 'OYL-106', 'MEDIUM_LOW', 7, 20, 'Versatile, crisp, malty profile, light esters and a wide fermentation range. This is thought to be the world''s most used lager strain and can produce a convincing lager at ale temperatures. Fermenting in the low temperature range (45-55), it maintains a more crisp profile. Temperatures higher in range (65-68) bring out slightly heightened esters. Rest for diacetyl.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('GERMAN LAGER II', 68, 76, 'ALE', 9, 'Omega Yeast', 'OYL-109', 'MEDIUM_HIGH', 10, 13, 'Great for Bavarian styles. A confident fermenter with good attenuation resulting in a smooth, full-bodied, malty finish and balanced aroma. Slight sulfur and low diacetyl.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('GRAND CRU', 72, 76, 'ALE', 12, 'Omega Yeast', 'OYL-023', 'LOW', 17, 24, 'Made for wits or any other Belgian ale—even sweet mead or cider—this strain''s clove phenolics, esters and tart and dry ending was historically enhanced by orange peel and coriander. The well-known Belgian wheat beer was brought back from extinction in its historic home of Hoegaarden by Pierre Celis, from which this strain is thought to come.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('GULO ALE', 85, 90, 'ALE', 12, 'Omega Yeast', 'OYL-501', 'MEDIUM', 20, 25, 'Gulo Ale is the latest creation to emerge from the curious minds of our R&D team. The progeny of Irish Ale (OYL-005) and French Saison (OYL-026), this true genetic hybrid is a beast at devouring sugars, which creates a very dry beer without any of the peppery, clove phenolics associated with saisons and Belgian ales. Expect a citrus-forward aroma with hints of peach and a clean finish. Gulo Ale excels in any style where a high level of attenuation is desired without phenolics. We love using it in an IPA (including a brut IPA), stout, or Bière de Garde. Non-phenolic.', 'Saison, Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hefeweizen Ale I', 73, 77, 'ALE', 10, 'Omega Yeast', 'OYL-021', 'LOW', 18, 24, 'A classic German wheat strain, it''s a cloudy, big top cropper. Presenting banana and clove, the esters turn up with increased temperatures, wort density and decreased pitch rate, or stay muted at lower temperatures where clove stands out. Over pitching can lessen the banana. Sulfur conditions out. See also Belgian Ale A (OYL-024) for an alternate complexity.', 'Hefeweizen, Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hefeweizen Ale II', 70, 76, 'ALE', 10, 'Omega Yeast', 'OYL-022', 'HIGH', 17, 24, 'Identical to Hefeweizen Ale I (OYL-021) except flocculent, Hefeweizen Ale II produces a crystal clear body with no additional steps and is a big top cropper. Up esters with upper fermentation temperatures, wort density and decreased pitch rate, or keep esters muted to let clove show. Turn down banana by over pitching. Sulfur conditions out.', 'Hefeweizen, Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hornindal Kveik', 75, 82, 'KVEIK', 16, 'Omega Yeast', 'OYL-091', 'HIGH', 22, 37, 'A wonderfully unique Norwegian farmstead kveik, Hornindal produces a tropical flavor and complex aroma that can present itself as stonefruit, pineapple, and dried fruit leather, which complement fruit-forward hops. Add even more dimension to C hops and increase ester intensity with a high fermentation temperature. Ferments well at 90°F+. Non-phenolic and no fusels, even at higher temperatures.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('HOTHEAD ALE', 75, 85, 'KVEIK', 11, 'Omega Yeast', 'OYL-057', 'MEDIUM_HIGH', 22, 37, 'A highly flocculent Norwegian ale strain with an astoundingly wide temperature range and little change in flavor across the range. Clean enough for both American and English styles, it has a unique honey-like aroma with overripe mango. Complementary to modern, fruity hops. Temperature control is unnecessary with this strain. Non-phenolic and no fusels, even at higher temperatures', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('IRISH ALE', 69, 75, 'ALE', 12, 'Omega Yeast', 'OYL-005', 'MEDIUM', 17, 22, 'Ireland''s storied stout is thought to be balanced by this dry, crisp, lightly fruity, versatile and powerful strain. A good fermenter with reliable, average flocculation (some diacetyl possible), and a hint of fruit at the lowest recommended temperatures, which increases in complexity at higher temperatures (64+). Successful in dark and high gravity beers. Sláinte!', 'Ales, British Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('JOVARU LITHUANIAN FARMHOUSE', 80, 85, 'ALE', 10, 'Omega Yeast', 'OYL-033', 'MEDIUM_LOW', 21, 35, 'Borne from an exclusive partnership with the famed Jovaru Brewery''s queen of Lithuanian farmhouse beer, this unique yeast complements farmhouse beers with citrusy esters and restrained phenols. The strain produces a character of lemon pith, black pepper, and a soft mouthfeel. I sveikata!', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('KOLSCH I', 73, 77, 'ALE', 10, 'Omega Yeast', 'OYL-017', 'LOW', 13, 21, 'An enthusiastically top cropping, lager-like ale strain from Koln, Kolsch I is lightly fruity, crisp and clean, and accentuates hop flavors well. This strain can be fermented colder than Kolsch II (OYL- 044), and is powdery and slow to drop clear (filtering recommended). Kolsch II (OYL-044) is a little easier to manage. Sulfur disappears with age.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('KOLSCH II', 72, 78, 'ALE', 10, 'Omega Yeast', 'OYL-044', 'MEDIUM_LOW', 18, 21, 'This Kolsch strain is warmer fermenting than Kolsch I (OYL-017), flocculates much better and clears more quickly, so is a little easier to manage. It is a lager-like ale strain that''s lightly fruity, crisp and clean with a hint of sulfur that disappears with age to leave a clean ale. Accentuates hop flavors.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LACTOBACILLUS BLEND', 0.0, 0.0, 'ALE', 0.0, 'Omega Yeast', 'OYL-605', 'MEDIUM', 20, 35, 'A Lactobacillus brevis and plantarum blend with a wide temperature range. The Lacto plantarum, isolated in collaboration with Marz Community Brewing, sours efficiently at its higher end. Do not sour above 95°F to prevent stalling. Max souring develops within 24-48 hrs. Extremely hop sensitive, even 2 IBUs can prevent souring.', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LAGER I', 71, 75, 'ALE', 9, 'Omega Yeast', 'OYL-100', 'MEDIUM_HIGH', 9, 13, 'Early inspiration for light American lager and thought to be from Budejovice, this crisp, balanced strain is lightly malty and finishes with very slight fruit notes. It is the backbone of the classic Czech Pilsner profile where the yeast character should neither dominate nor disappear among the beer''s subtle balance of malts and hops.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('LONDON ALE', 67, 77, 'ALE', 11, 'Omega Yeast', 'OYL-003', 'MEDIUM', 19, 22, 'The London Ale strain is a high attenuator that has obvious English character in its pronounced mineral and mild fruit. It performs best for dry, crisp beers, and in highlighting hop bitterness. For more neutral strains, try West Coast Ale I (OYL-004), or keep the English deportment with British Ale I (OYL-006) or British Ale VI (OYL-013).', 'Ales, British Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Lutra Kveik', 75, 82, 'KVEIK', 11, 'Omega Yeast', 'OYL-071', 'MEDIUM_HIGH', 20, 35, 'Isolated from our Hornindal Kveik (OYL-091) culture, Lutra is shockingly clean with unrivaled speed when pitched at 90°F (32°C). The strain is perfect for brewing a refreshing pseudo-lager without the lead time of a lager. Lutra is your worry-free way to navigate the evolving demand for cold ones.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('MEXICAN LAGER', 70, 78, 'ALE', 9, 'Omega Yeast', 'OYL-113', 'MEDIUM', 10, 13, 'This great lager strain is thought to originate from a well known Mexican brewery. Simply put, it is clean, crisp, bright and versatile.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('NORTHWEST FARMHOUSE BRETT', 70, 85, 'ALE', 10, 'Omega Yeast', 'OYL-216', 'LOW', 20, 27, 'Enjoy the lighter side of funkiness with this B. bruxellensis variant that hails from a Northwest U.S. brewery. It''s known for its wonderful white wine character and light funk, and develops its character rather quickly. Brett character will be apparent within a few weeks of reaching terminal gravity and will continue to develop if given additional conditioning time.', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Oktoberfest', 73, 77, 'ALE', 9, 'Omega Yeast', 'OYL-107', 'MEDIUM_HIGH', 8, 14, 'This strain is a slow fermenter but said to be worth the wait by fans of Märzenbier and Oktoberfest Lagers particularly. It facilitates a smooth, rich, balanced beer with full, malty profile. Make sure to give it a thorough diacetyl rest.', 'Lagers, Märzen');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('PACIFIC NW ALE', 67, 71, 'ALE', 10, 'Omega Yeast', 'OYL-012', 'HIGH', 18, 24, 'A strain from the Pacific NW, originally from the UK, the Pacific NW Ale strain presents a relatively neutral profile with notes of malt and light fruit that add depth of flavor. It is a healthy flocculator.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('PEDIOCOCCUS', 0.0, 0.0, 'ALE', 0.0, 'Omega Yeast', 'OYL-606', 'MEDIUM', 20, 27, 'This modestly hop tolerant Pedio strain produces a clean lactic tang over time. The strain can produce diacetyl so it is often paired with one or more Brett strains (to consume the diacetyl). While more hop tolerant than the Lacto Blend (OYL-605), IBUs over 5-10 IBU may inhibit souring. Souring time can vary depending on IBU level.', 'Farmhouse');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('PILSNER I', 72, 76, 'ALE', 9, 'Omega Yeast', 'OYL-101', 'MEDIUM_HIGH', 9, 13, 'Thought to be the H strain of the famous Plzen brewer, this lager strain has a dry and neutral taste profile and is gently malty with a lightly perceptible floral aroma. The first of the famous Czech strains inspiring America''s most famous light, brilliantly clear, golden lagers. Commonly produces sulfur during fermentation that clears during lagering. Watch out for diacetyl.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('PILSNER II', 70, 74, 'ALE', 9, 'Omega Yeast', 'OYL-108', 'MEDIUM_HIGH', 10, 14, 'Thought to be the D strain of the famous Pilsen brewer. With a dry and malty taste profile, it is the second of the famous Czech strains inspiring America''s most famous light, brilliantly clear, golden lagers.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SAISONSTEIN''S MONSTER', 80, 90, 'ALE', 11, 'Omega Yeast', 'OYL-500', 'LOW', 18, 26, 'An Omega-original, genetic hybrid of two Saison strains (French (OYL-026) and Belgian I (OYL-027)), Saisonstein''s Monster is versatile, aromatic and attenuative with a silky mouthfeel. Excels in high gravity, ferments more reliably and thoroughly than its parents, and is spicy, complex, tart, dry and crisp. Some bubblegum from the Belgian, more fruit and fewer phenolics than the French.', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('SCOTTISH ALE', 73, 76, 'ALE', 10, 'Omega Yeast', 'OYL-015', 'HIGH', 17, 24, 'The Scottish Ale strain is a flocculent, versatile and reliable house strain that produces neutral to complex and malty profiles in its fairly wide temperature range. Hop character is not muted by this strain. More esters emerge at higher fermentation temperatures.', 'Ales, British Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('TROPICAL IPA', 82, 90, 'ALE', 10, 'Omega Yeast', 'OYL-200', 'LOW', 21, 29, 'A unique Saccharomyces strain that produces delicate, tart, tropical mango and pineapple fruit characteristics with a clean finish. Try higher fermentation temperatures to really bring out the tropical aspects. It''s stubbornly nonflocculent, but the results are worth the trouble.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('VOSS KVEIK', 75, 82, 'KVEIK', 12, 'Omega Yeast', 'OYL-061', 'MEDIUM', 22, 37, 'A traditional Norwegian kveik directly from the Gjernes farmstead, Voss Kveik''s orange-citrus notes present throughout its wide temperature range. So, like the mango-honey profile of Hothead (OYL-057), Voss Kveik''s orange-citrus is relatively clean across its fermentation temperature range, and pairs well with citrusy, fruity hops. Ester intensity and fermentation speed take off at higher temperatures. Non-phenolic and no fusels, even at higher temperatures.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('West Coast Ale I', 73, 80, 'ALE', 11, 'Omega Yeast', 'OYL-004', 'MEDIUM_LOW', 16, 23, 'Chico is a reliable, versatile and popular neutral foundation for displays of malts and hops. Highly attenuating and moderately flocculating, it ferments crisp and clean with light citrus notes under 66.', 'Ales, IPA, Stouts');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('WEST COAST ALE II', 72, 76, 'ALE', 10, 'Omega Yeast', 'OYL-009', 'MEDIUM', 16, 22, 'West Coast Ale II is a consistent, well flocculating, well attenuating and easy clearing neutral strain. Slightly fruitier than West Coast Ale I (OYL-004) and clean with a lightly perceptible nuttiness, its subtle citrus character finishes slightly tart at the cool end, and more fruit character emerges as fermentation temperatures increase.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('WEST COAST ALE III', 76, 83, 'ALE', 11, 'Omega Yeast', 'OYL-043', 'MEDIUM_HIGH', 18, 20, 'Neutral and versatile, this strain is low ester-producing with balanced flavor and aroma. Highly alcohol tolerant. Similar to West Coast Ale I (OYL-004) but faster and more flocculent.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('WEST COAST ALE IV', 73, 80, 'ALE', 10, 'Omega Yeast', 'OYL-050', 'MEDIUM_HIGH', 17, 23, 'An easy to handle strain, this neutral-tasting, quick-and-good flocculator and highly productive top cropper has excellent attenuation. Any fruity esters are somewhat mild through its higher temperature range, though they do decrease at the lower end. The relatively subtle yeast-contributed flavor cedes pleasantly to hops and malts.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('WEST COAST LAGER', 67, 71, 'ALE', 9, 'Omega Yeast', 'OYL-105', 'HIGH', 14, 20, 'A lager strain that performs very well at ale temperatures, this strain is ideal for California common beer, also known as steam beer. Malty and crystal clear, it is considered by many to be best in its upper temperature range, around 65°F / 18°C.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('WIT', 72, 76, 'ALE', 11, 'Omega Yeast', 'OYL-030', 'MEDIUM', 17, 24, 'Enthusiastically top cropping, this essential Wit yeast is distinctive for the popular, refreshing, easy-drinking summer style. Spicy phenolics carry the flavoring, while at the same time being supported—but not overshadowed— by good ester character. Lightly tart and dry', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Chico Ale', 74, 81, 'ALE', 11, 'RVA Yeast Labs', 'RVA-101', 'MEDIUM', 19, 23, 'This versatile workhorse yeast will produce a clean crisp flavor profile with muted yeast character allowing hops and malt to take center stage.  The American IPA has gained international acclaim and this is the yeast that did it.', 'Pale Ale, IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Chiswick Ale', 65, 72, 'ALE', 8, 'RVA Yeast Labs', 'RVA-131', 'VERY_HIGH', 18, 21, 'This classic English strain from Fuller''s Brewery will produce a very clear beer with some residual sweetness.', 'Porter, Stout, Mild Ale, ESB');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hoptopper Ale', 75, 80, 'ALE', 11, 'RVA Yeast Labs', 'RVA-104', 'MEDIUM_LOW', 18, 24, 'Isolated from a very well regarded example of a Double IPA, this strain will produce fruity esters which serve well to complement a heavy hop load.  Great for a variety of pale ales and bitters.', 'IPA, Double IPA, Pale Ale, Bitters');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Manchester Ale', 70, 75, 'ALE', 10, 'RVA Yeast Labs', 'RVA-132', 'HIGH', 18, 22, 'Dryer than the Chiswick, this English classic will create a touch of esters and leave a hint of residual sweetness and malt backbone.', 'IPA, Brown Ale, ESB');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Oktoberfest Lager', 65, 73, 'ALE', 12, 'RVA Yeast Labs', 'RVA-303', 'MEDIUM', 11, 14, 'This is a bock-style lager yeast that accentuates maltiness.', 'Märzen, Oktoberfest, Bock, Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Pacman Ale', 74, 78, 'ALE', 12, 'RVA Yeast Labs', 'RVA-103', 'MEDIUM_HIGH', 17, 22, 'Originating from Rogue brewery in Newport, OR. Pacman is a very versatile yeast, and produces a dry, clean beer with little diacetyl and very mild esters.', 'Pale Ale, Blonde Ale, American Wheat, Altbier, Amber Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Amalgamation - Brett Super Blend', 85, 95, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4637', 'LOW', 21, 27, 'Amalgamation is the union of our six favorite Brettanomyces isolates from our microbe library. Each isolate produces a unique bouquet of bright and fruity flavors and aromas. The resulting beer will be dry with complex fruit-forward flavor and aroma of berries and citrus, accompanied by some funk on the palate.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Amalgamation II - Brett Super Blend', 82, 86, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4641', 'LOW', 21, 27, 'Amalgamation II is a blend of 5 Brettanomyces bruxellensis isolates that showcases qualities of each isolate: The balanced funk of the Beersel isolates and TYB184, the SweeTarts™ character of TYB207, and the tropical bouquet of lemon, pineapple, guava, mango and papaya esters contributed by TYB261.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Beersel Brettanomyces Blend', 82, 85, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4603', 'LOW', 21, 27, 'This blend combines Brettanomyces bruxellensis strains isolated from a lambic produced in the Beersel area in the Belgian province of Flemish Brabant, and will produce a balanced profile of fruitiness, funkiness and a crisp tartness.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brettanomyces Bruxellenis TYB261', 82, 85, 'ALE', 53.8462, 'The Yeast Bay', 'TYB261', 'LOW', 22, 28, 'This blend combines Brettanomyces bruxellensis strains isolated from a lambic produced in the Beersel area in the Belgian province of Flemish Brabant, and will produce a balanced profile of fruitiness, funkiness and a crisp tartness.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('BRETTANOMYCES BRUXELLENSIS - STRAIN TYB184', 82, 88, 'ALE', 53.8462, 'The Yeast Bay', 'TYB184', 'MEDIUM_LOW', 22, 28, 'Isolated from a rustic farmhouse style beer produced in the Northeastern United States, this single strain of Brettanomyces bruxellensis is attenuative, produces a moderate citric acidic-like character and an ester profile of lemon/pineapple, with a restrained funkiness.', 'Farmhouse Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brettanomyces Bruxellensis - Strain TYB207', 80, 82, 'ALE', 53.8462, 'The Yeast Bay', 'TYB207', 'MEDIUM_LOW', 22, 28, 'Isolated from a Belgian-inspired brewery in the Northeastern United States, this single strain of Brettanomyces bruxellensis exhibits good attenuation and produces a tart tropical fruit ester profile reminiscent of SweeTarts™.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brettanomyces Bruxellensis - Strain TYB307', 80, 84, 'ALE', 53.8462, 'The Yeast Bay', 'TYB307', 'LOW', 21, 27, 'This isolate is a single strain of Brettanomyces bruxellensis isolated from a California brewery that utilizes an extensive and diverse array of organisms in the production of their wild/sour/funky beers. This strain exhibits a lemony-tartness with hints of hay and mild barnyard funk, and has a crisp and dry finish.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brettanomyces bruxellensis - Strain TYB415', 82, 86, 'ALE', 53.8462, 'The Yeast Bay', 'TYB415', 'LOW', 21, 27, 'This isolate is a single strain of Brettanomyces bruxellensis hailing from a brewer of all things sour and wild in the Mountain West. This strain exhibits a strong profile of complex tropical fruit that is dominated by pineapple with a noticeable earthiness that adds a unique complexity and depth of character to the beer. This strain will produce a massive, thick krausen.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brussels Brettanomyces Blend', 80, 90, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4613', 'MEDIUM', 21, 27, 'Comprised of two Brettanomyces bruxellensis strains isolated from a unique lambic produced in the Brussels region of Belgium, the isolates in this blend produce a pronounced barnyard funk with mild tartness and fruitiness.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Dark Belgian Cask', 80, 85, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4653', 'MEDIUM', 20, 24, 'Dark Belgian Cask is a blend a classic Belgian Saccharomyces cerevisiae strain and our Brettanomyces bruxellensis - Strain TYB184. Together these strains produce a dry beer with a vinous quality and a flavor profile of dried dark fruit, plum, leather, and a mild earthy funk and acidity. Both strains in this blend are very alcohol tolerant (10-15%). While this blend is fairly versatile, its complexity truly shines in dark beers.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Dry Belgian Ale', 85, 100, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4025', 'HIGH', 20, 23, 'Dry Belgian Ale is single strain of STA1+ Saccharomyces cerevisiae isolated from a unique golden strong ale showcasing an ester profile of apple, pear and light citrus fruit with some mild spicy and peppery notes. This strain is highly attenuative and alcohol tolerant. It produces beers with a surprising amount of body without the use of specialty grains or adjuncts. This strain exhibits high diastatic activity.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Farmhouse Sour Ale', 80, 100, 'ALE', 38.4615, 'The Yeast Bay', 'WLP4675', 'MEDIUM_LOW', 21, 26, 'This blend contains two farmhouse STA1+ Saccharomyces cerevisiae isolates, Lactobacillus brevis, and Lactobacillus delbrueckii. The two Saccharomyces strains will combine to create a delightful ester profile of grapefruit and orange zest accompanied by a mild earthiness and spiciness, while the Lactobacillus strains will produce a balanced acid profile. This blend exhibits high diastatic activity.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Flanders Specialty Ale', 78, 82, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4001', 'MEDIUM', 20, 27, 'Flanders Specialty Ale is a single strain of Saccharomyces cerevisiae isolated from a fascinating Belgian producer of a wide array of traditional Belgian beer styles. This is a versatile yeast that will ferment fairly dry and produce a balanced flavor and aroma profile laced with a myriad of esters and phenols.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Framgarden Kveik', 78, 82, 'KVEIK', 53.8462, 'The Yeast Bay', 'WLP4051', 'MEDIUM', 27, 35, 'A single strain of Saccharomyces cerevisiae, it was isolated from source material collected from Petter Øvrebust. It exhibits a vibrant bouquet of hull melon and cantaloupe esters across a broad temperature range. This strain is well suited to any hop forward or farmhouse-inspired beers.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Franconian Dark Lager', 74, 78, 'ALE', 38.4615, 'The Yeast Bay', 'WLP4030', 'MEDIUM_LOW', 8, 11, 'Franconian Dark Lager is a single strain of Saccharomyces pastorianus that hails from the Franconia region of Germany. This yeast exhibits a short lag time and has flavor profile characteristics that complement dark, roasted malts. While the dark malt complementarity makes this yeast a perfect fit for any big malt driven dark lagers, it''s also able to produce crisp light lagers.', 'Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Funktown Pale Ale', 78, 85, 'ALE', 38.4615, 'The Yeast Bay', 'WLP4627', 'MEDIUM_LOW', 20, 23, 'Funktown Pale Ale is a blend of our Vermont Ale strain and a unique strain of STA1 + Saccharomyces cerevisiae that is well suited for primary fermentation. The combination of  citrus, peach, pineapple and mango esters produce a unique flavor and aroma profile that is fruit-forward and complements any hop-forward beer. This blend exhibits low diastatic activity.', 'Pale Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hazy Daze', 79, 83, 'ALE', 38.4615, 'The Yeast Bay', 'WLP4042', 'MEDIUM_LOW', 18, 21, 'Hazy Daze contains a proprietary blend of three Saccharomyces cerevisiae strains, all of which offer unique contributions to the production of crisp, hop forward beers. Expect this blend to throw bountiful amounts of peach, apricot, nectarine and grapefruit citrus esters and achieve good attenuation.', 'IPA, Hazy IPA, Pale Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hazy Daze II', 81, 85, 'ALE', 38.4615, 'The Yeast Bay', 'WLP4044', 'MEDIUM_LOW', 19, 22, 'Hazy Daze II is a proprietary blend of three Saccharomyces cerevisiae strains and one STA1+ Saccharomyces cerevisiae strain. It will exhibit an strong ester profile of stone fruit (peach, apricot, nectarine and), tropical fruit (mango, guava) and grapefruit citrus esters. It ferments faster and finishes slightly drier compared to our Hazy Daze. This blend exhibits low diastatic activity.', 'IPA, Hazy IPA, Pale Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hessian Pils', 73, 76, 'ALE', 7.69231, 'The Yeast Bay', 'WLP4035', 'MEDIUM', 7, 9, 'Hessian Pils is a single strain of Saccharomyces pastorianus that hails from the Hess region of Germany. It exhibits everything you want in a great Pilsner yeast: it''s a clean fermenter with low ester formation, exhibits a short lag time, ferments wort quickly and attenuates well even at the low end of the temperature range. These characteristics allow the malt and hop profile to really shine, and creates a crisp finished beer.', 'Pilsners, Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hornindal Kveik', 77, 81, 'KVEIK', 53.8462, 'The Yeast Bay', 'WLP4050', 'MEDIUM_LOW', 27, 35, 'A truly unique strain of Saccharomyces cerevisiae isolated from source material collected on Terje Raftevold’s farmstead. It exhibits a beautiful bouquet of stone fruit and tropical esters across a broad temperature range and can be used across a broad spectrum of styles, and is well suited to any hop forward beer.', 'IPA, Pale Ale, Stout, Porter, English Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Lactobacillus Blend', 57.4713, 0.0, 'BACTERIA', 0.0, 'The Yeast Bay', 'WLP4682', 'MEDIUM', 21, 32, 'The Lactobacillus Blend is comprised of three strains, one strain of Lactobacillus plantarum and two strains of Lactobacillus brevis.  One of the strains of L. brevis was isolated from an unintentionally sour hoppy blonde ale from a Mexican craft brewery, and exhibits strong hop tolerance (15-20 IBU).', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Lactobacillus brevis - Strain TYB282', 4, 0.0, 'BACTERIA', 0.0, 'The Yeast Bay', 'WLP4681', 'MEDIUM', 21, 32, 'TYB282 is a single strain of Lactobacillus brevis isolated out of an unintentionally soured golden ale produced by a Mexican craft brewery. This strain produces a nice, clean lactic acidity (down to ~pH 3.16-3.18) in unhopped wort within 36 hours at a temperature of ~72-77 °F. The higher the temperature up to 90 °F, the faster the acid production. This is a great strain for kettle souring, but really shines in souring fermented beer as a result of its hop tolerance (15-20 IBU).', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Lida Kveik', 75, 82, 'KVEIK', 53.8462, 'The Yeast Bay', 'WLP4052', 'LOW', 27, 32, 'This culture is a single strain of Saccharomyces cerevisiae isolated from Samuel Lien’s house culture, which he received from Hans Øen around 1980. It exhibits a fermentation profile of apricot, stone fruit and white wine grape esters, with a balanced malt character coming through on the finish.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Lochristi Brettanomyces Blend', 80, 88, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4623', 'MEDIUM_LOW', 21, 27, 'This blend combines Brettanomyces bruxellensis strains isolated from a unique beer produced in the Lochristi area in East Flanders. One strain provides a moderate funk and light fruitiness, while the other strain adds a more assertive fruitiness dominated by hints of strawberry.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Metschnikowia reukaufii ', 20, 25, 'ALE', 23.0769, 'The Yeast Bay', 'WLP4650', 'LOW', 16, 32, 'M. reukaufii is a nectar specialist that was isolated from flowers in the Berkeley Hills of California. Evolutionarily, these yeast likely evolved to produce a more odorous and attractive nectar for pollinators by enzymatically altering otherwise inodorous nectar compounds like glycosides.  While only attenuating to 20-25% in brewer’s wort and not utilizing maltose or maltose polymers, in co-fermentations it has been shown to drop gravity and pH of the fermentation faster, accentuate and modulate the flavor and aroma profile and soften the perceived bitterness of the finished product.  This strain MUST be used in conjunction with other yeast that can ferment brewer’s wort (capable of fermenting maltose).', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Midtbust Kveik', 76, 80, 'KVEIK', 53.8462, 'The Yeast Bay', 'WLP4053', 'LOW', 24, 35, 'This single strain of Saccharomyces cerevisiae isolated from Odd H Midtbust’s house culture exhibits a cleaner fermentation character and restrained ester profile, allowing the malt and hop character to shine. Perfect for use in any style where malt and/or hop character is at the forefront of the profile.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Midwestern Ale', 76, 80, 'ALE', 38.4615, 'The Yeast Bay', 'WLP4040', 'MEDIUM', 18, 22, 'Midwestern Ale yeast is a single strain of Saccharomyces cerevisiae isolated from a storied brewery in the heartland of America, well suited for fermentation of a broad spectrum of worts. A relatively fast fermenter with good attenuation, expect this yeast to ferment cleaner with a low ester profile at the cooler fermentation temperatures, and produce a more pronounced ester profile at warmer fermentation temperatures. This yeast is a great choice for a versatile house yeast.', 'Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Northeastern Abbey', 77, 81, 'ALE', 38.4615, 'The Yeast Bay', 'WLP4015', 'MEDIUM_LOW', 20, 24, 'Northeastern Abbey is a strain of Saccharomyces cerevisiae isolated from a beer crafted by a well-known producer of Belgian-style ales in the Northeastern United States. This yeast produces a very mild spiciness and earthy character, complemented by a magnificent array of fruity esters, including pear and citrus fruit. Expect this yeast to produce a large, thick krausen.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Pakruojis Lithuanian Farmhouse', 90, 100, 'KVEIK', 53.8462, 'The Yeast Bay', 'WLP4047', 'LOW', 24, 35, 'Pakruojis Lithuanian Farmhouse is a single strain of STA1+ Saccharomyces cerevisiae, isolated from a Lithuanian brewery. This yeast produces beer with a dry, crisp and silky mouthfeel, an ester profile of complex citrus fruit, and a balanced rustic earthiness with undertones of white peppercorn. This strain exhibits high diastatic activity.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison Blend', 78, 84, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4007', 'MEDIUM_LOW', 22, 28, 'A blend of two unique Saccharomyces cerevisiae strains (one being STA1+) isolated from beers that embody the saison style, this blend is a balance of the many classic saison flavors and aromas. One yeast strain is a good attenuator that produces a spicy and mildly tart and tangy beer with a full mouthfeel, the other a good attenuator that produces a delightful ester profile of grapefruit and orange zest. This blend exhibits very low diastatic activity.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison Blend II', 85, 100, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4021', 'MEDIUM', 20, 27, 'This blend contains two saison-style Saccharomyces cerevisiae isolates (Wallonian Farmhouse II and Wallonian Farmhouse III) and two Brettanomyces bruxellensis cultures (TYB184, TYB207).  This unique combination will produce a beer that is bursting with classic saison esters and earthiness, with a rustic kick of Brettanomyces fruitiness and funkiness.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison/Brettanomyces Blend', 80, 100, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4626', 'MEDIUM_LOW', 21, 26, 'This blend combines one of the Saccharomyces cerevisiae strains from the Saison Blend and two unique Brettanomyces isolates from our yeast library. The Saccharomyces strain is a strong attenuator that produces a delightful ester profile of grapefruit and orange zest and imparts a long, dry and earthy finish to the beer. The Brettanomyces strains are both good attenuators that produce some fruity esters and mild funk, and add a bright character to the beer. The resulting beer is dry with balanced ester and phenolic character.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison/Brettanomyces Blend II', 85, 90, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4636', 'MEDIUM_LOW', 22, 27, 'This blend contains two saison-style Saccharomyces cerevisiae isolates (Wallonian Farmhouse II and Wallonian Farmhouse III) and two Brettanomyces bruxellensis cultures (TYB184, TYB207).  This unique combination will produce a beer that is bursting with classic saison esters and earthiness, with a rustic kick of Brettanomyces fruitiness and funkiness.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Simonaitis Lithuanian Farmhouse', 76, 82, 'KVEIK', 53.8462, 'The Yeast Bay', 'WLP4046', 'HIGH', 24, 35, 'This culture is a single strain of Saccharomyces cerevisiae, isolated from a Lithuanian Farmhouse mixed culture kindly provided by Julius Simonaitis via Lars Garshol. Across a wide temperature range this culture will throw a potent mix of orange, tropical fruit and stone fruit esters that is reminiscent of POG Juice® (passionfruit, orange, guava) accompanied by distinct spicy, earthy and herbal undertones.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Transatlantic Berliner Blend', 85, 100, 'ALE', 38.4615, 'The Yeast Bay', 'WLP4645', 'MEDIUM_LOW', 19, 24, 'Transatlantic Berliner Blend is a blend of a clean Saccharomyces cerevisiae strain (Germany), a healthy dose of Lactobacillus brevis – Strain TYB282 (Mexico) isolates, and a touch of our Beersel Brettanomyces Blend (Belgium) and Brettanomyces bruxellensis - Strain TYB184 (US). This culture will ferment to a crisp dryness over time and produce the trademark Berliner Weisse lactic acid backbone, with a touch of Brettanomyces tart citrus character and funk.', 'Sours');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Vermont Ale', 78, 82, 'ALE', 38.4615, 'The Yeast Bay', 'WLP4000', 'MEDIUM_LOW', 18, 22, 'Isolated from a uniquely crafted double IPA out of the Northeastern United States and originally of British lineage, this single strain of Saccharomyces cerevisiae produces a balanced fruity ester profile of peaches and light citrus that complements any aggressively hopped beer.', 'IPA, Pale Ales, Hazy IPAs');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Wallonian Farmhouse', 81, 100, 'ALE', 23.0769, 'The Yeast Bay', 'WLP4020', 'HIGH', 20, 26, 'Isolated from a unique farmhouse-style ale that hails from the Walloon region of Belgium, this strain of STA1+ Saccharomyces cerevisiae imparts a slight earthy funk and tart character to the beer, and is a very mild producer of slightly spicy and mildly smokey flavor compounds. We recommend controlling the dryness by adding malts or adjuncts to the mash tun that will lend some body and residual sweetness to the beer. This strain exhibits high diastatic activity.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Wallonian Farmhouse II', 86, 94, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4022', 'MEDIUM_LOW', 20, 27, 'This is a single strain of Saccharomyces cerevisiae isolated from the same source as our Wallonian Farmhouse strain, a well-known brewery hailing from the Walloon region of Belgium. Slightly less attenuative and exhibiting a more restrained phenolic and expressive ester profile than Wallonian Farmhouse I, this yeast exhibits a great balance of fruitiness and rustic farmhouse character.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Wallonian III Farmhouse', 86, 94, 'ALE', 53.8462, 'The Yeast Bay', 'WLP4023', 'MEDIUM_LOW', 20, 27, 'This is a single strain of STA1+ Saccharomyces cerevisiae isolated from a well-known brewery hailing from the Walloon region of Belgium and exhibits a balanced profile of esters and phenols. This yeast is similar to a classic saison strain offered by many other yeast manufacturers, without the slow/low attenuation and stalling issues often observed in those cultures. This strain exhibits moderate-high diastatic activity.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Abbey Ale Yeast', 75, 80, 'ALE', 53.8462, 'White Labs', 'WLP530', 'MEDIUM_HIGH', 19, 22, 'This is a traditional Belgian abbey strain that produces cherry, plum and pear esters. Medium flocculationresults in a clear, drinkable beer.', 'If you cannot find Abbey Ale Yeast (WLP530) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Abbey IV Ale Yeast', 74, 82, 'ALE', 53.8462, 'White Labs', 'WLP540', 'MEDIUM', 19, 22, 'This strain produces balanced fruit aroma and flavor characters.From the Ardennes region of Belgium, this strain produces moderate levels of ester and phenolic characters,', 'If you cannot find Abbey IV Ale Yeast (WLP540) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('American Ale Yeast Blend', 72, 80, 'ALE', 38.4615, 'White Labs', 'WLP060', 'MEDIUM', 20, 22, 'This blend of three strains creates a clean and neutral fermentation character. It lends complexity to finishedbeer by exhibiting a crisp, clean lager-like character with accentuated hop flavors and bitterness.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('American Hefeweizen Ale Yeast', 70, 75, 'ALE', 23.0769, 'White Labs', 'WLP320', 'LOW', 18, 21, 'This strain ferments much cleaner than it''s hefeweizen strain counterparts. It produces very slight banana and clove notes and has low flocculation, leaving resulting beers with characteristic cloudiness.', 'American Hefeweizen');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('American Lager Yeast', 75, 80, 'ALE', 23.0769, 'White Labs', 'WLP840', 'MEDIUM', 10, 13, 'This strain makes dry and clean lagers with a light note of apple fruitiness. Sulfur and diacetyl production is minimalmaking this strain easy to work with and fitting for American-style lagers.', 'If you cannot find American Lager Yeast (WLP840) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bastogne Belgian Ale Yeast', 74, 80, 'ALE', 53.8462, 'White Labs', 'WLP510', 'MEDIUM', 19, 22, 'A high-gravity ale yeast that produces a dry beer with a slightly acidic finish. While fruit forward, this strainis mild on spice-like phenols.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bavarian Weizen Ale Yeast', 73, 77, 'ALE', 23.0769, 'White Labs', 'WLP351', 'LOW', 19, 21, 'This is former Yeast Lab W51. It produces a classic German-style wheat beer, with medium to high spicyphenolic overtones reminiscent of cloves.', 'Hefeweizen, Weissbier, Wheat');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Ale Yeast', 78, 85, 'ALE', 38.4615, 'White Labs', 'WLP550', 'MEDIUM', 20, 26, 'This very expressive strain produces phenol-forward flavors and aromas reminiscent of clove, allspiceand peppercorns.', 'If you cannot find Belgian Ale Yeast (WLP550) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Golden Ale Yeast', 73, 78, 'ALE', 53.8462, 'White Labs', 'WLP570', 'LOW', 20, 24, 'From East Flanders, this yeast is versatile in that it can produce low to high gravity Belgian beers up to12% ABV. A combination of fruitiness and phenolic characteristics dominate the flavor profile.', 'If you cannot find Belgian Golden Ale Yeast (WLP570) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Saison I Ale Yeast', 65, 75, 'ALE', 23.0769, 'White Labs', 'WLP565', 'MEDIUM', 20, 24, 'A classic saison strain sourced from the Wallonia region of Belgium. This strain makes a classic saison byproducing flavors and aromas noted as earthy, peppery and spicy.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Saison II Ale Yeast', 78, 85, 'ALE', 23.0769, 'White Labs', 'WLP566', 'MEDIUM', 20, 26, 'This strain is a moderate phenol producer with clove-like flavor and aromatic notes present in finished beer.Some fruit-forward ester production provides a balance between fruit and spice aroma and flavors.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Strong Ale Yeast', 78, 85, 'ALE', 53.8462, 'White Labs', 'WLP545', 'MEDIUM', 19, 22, 'From the Ardennes region of Belgium, this strain produces moderate levels of ester and phenolic characters, described as dried sage and black cracked pepper. High attenuation results in a dry finish ideal for high gravity beer.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Wit Ale Yeast', 74, 78, 'ALE', 23.0769, 'White Labs', 'WLP400', 'MEDIUM_LOW', 19, 23, 'High phenol production contributes an herbal aroma and flavor notes which blends well with herb and fruitadjuncts. Expect a slightly lower resulting pH than English or American ale strains creating a dry beer.', 'If you cannot find Belgian Wit Ale Yeast (WLP400) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Wit II Ale Yeast', 70, 75, 'ALE', 23.0769, 'White Labs', 'WLP410', 'MEDIUM_LOW', 19, 23, 'A fairly clean strain with medium intensity and spice-like phenol production. With up to 75% attenuation, thisstrain produces a residual malt character.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian-Style Ale Yeast Blend', 74, 80, 'ALE', 38.4615, 'White Labs', 'WLP575', 'MEDIUM', 20, 24, 'A blend of two monastery-type yeast strains and one Belgian ale-type yeast. This blend creates a versatileculture which can be used for monastery-style beers or a myriad of American-Belgian style beers.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian-Style Saison Ale Yeast Blend', 70, 80, 'ALE', 23.0769, 'White Labs', 'WLP568', 'MEDIUM', 21, 27, 'Incorporates Belgian and saison strains to produce pear-like esters backed by spicy, earthy and clove-likeflavors and aromas. Creates harmony and complexity throughout its ester and phenol production', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Brettanomyces Claussenii', 70, 85, 'ALE', 10, 'White Labs', 'WLP645', 'LOW', 29, 18, 'Originally isolated from strong English stock beer in the early 20th century, this yeast has low-intensity Brettanomyces character and is closely related to Brettanomyces anomalus. This strain produces fruity, pineapple-like aroma with an earthy hay-like background aroma and aroma note. WLP645 Brettanomyces claussenii is POF+, this strain will contribute phenolic characteristics to finished products.', 'Cider');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('British Ale Yeast', 67, 74, 'ALE', 23.0769, 'White Labs', 'WLP005', 'HIGH', 18, 21, 'Known for its use in malty English beers, this strain will push bready, grainy malt flavors while beinga mild ester producer.', 'If you cannot find British Ale Yeast (WLP005) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Burlington Ale Yeast', 73, 78, 'ALE', 38.4615, 'White Labs', 'WLP095', 'MEDIUM', 19, 21, 'Signature strain for a brewery in the Northeast U.S., making it ideal for New England-style IPAs. The estersand body blend with hop flavors and aromas while balancing bitterness.', 'Pale Ale, IPA, Double IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Burton Ale Yeast', 69, 75, 'ALE', 23.0769, 'White Labs', 'WLP023', 'MEDIUM', 20, 23, 'This strain is sourced from Burton upon Trent, England which is known for pushing IPAs into the spotlight.It produces a subtle fruity ester profile which can be described as notes of apple, clover honey and pear.', 'If you cannot find Burton Ale Yeast (WLP023) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('California Ale Yeast', 73, 80, 'ALE', 53.8462, 'White Labs', 'WLP001', 'MEDIUM', 20, 23, 'This is our best-selling yeast, famous for its clean flavors and hardy fermentations. Known for its use in hoppy beers, it accentuates hop flavors and aromas and attenuates well, even for high gravity beers.', 'Pale Ale, IPA, Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('California V Ale Yeast', 70, 75, 'ALE', 38.4615, 'White Labs', 'WLP051', 'MEDIUM_HIGH', 19, 21, 'This strain is a big ester producer, showcasing notes of cherry and apple. This strain''s characteristic lower attenuation results in a full-bodied malt forward beer.', 'If you cannot find California V Ale Yeast (WLP051) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Charlie''s Fist Bump Yeast', 66, 70, 'ALE', 23.0769, 'White Labs', 'WLP1983', 'LOW', 13, 14, 'Licensed from Charlie Papazian, this strain can ferment at both ale and lager temperatures, allowing brewers toproduce diverse beer styles.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Coastal Haze Ale Yeast Blend', 70, 75, 'ALE', 38.4615, 'White Labs', 'WLP067', 'MEDIUM_LOW', 20, 22, 'This blend of New England-style IPA strains is great for producing beers with a hazy appearance and tropical,fruit-forward esters. Producing dry, yet juicy beers, with mango and pineapple characteristics.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Copenhagen Lager Yeast', 72, 78, 'ALE', 23.0769, 'White Labs', 'WLP850', 'MEDIUM', 10, 14, 'This northern European lager strain emphasizes clean and crisp characteristics. Malt flavors tend to be secondary,promoting clean drinkability.', 'If you cannot find Copenhagen Lager Yeast (WLP850) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Cream Ale Yeast Blend', 75, 80, 'ALE', 38.4615, 'White Labs', 'WLP080', 'MEDIUM', 18, 21, 'A blend of ale and lager yeast, this strain produces a classic cream ale. The blend produces a pleasing lightfruity note with clean pilsner-like flavors, and slightly subdued hop bitterness.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Czech Budejovice Lager Yeast', 75, 80, 'ALE', 23.0769, 'White Labs', 'WLP802', 'MEDIUM', 10, 13, 'A pilsner lager yeast from southern Czech Republic, this strain produces dry and crisp lagers with low diacetylproduction. This strain will make a dry beer and showcase rounded hop bitterness.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Dry English Ale Yeast', 70, 80, 'ALE', 38.4615, 'White Labs', 'WLP007', 'MEDIUM_HIGH', 18, 21, 'This yeast is known for its high attenuation, achieving 80% even with 10% ABV beers. This eliminatesresidual sweetness, making the yeast well-suited for high gravity ales and clean, well-attenuated beer styles.', 'If you cannot find Dry English Ale Yeast (WLP007) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('East Coast Ale Yeast', 70, 75, 'ALE', 23.0769, 'White Labs', 'WLP008', 'MEDIUM_LOW', 20, 23, 'Cleaner and crisper than other haze producing strains, this strain''s attenuation leaves some mouthfeeland residual sweetness which balances hop bitterness.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Edinburgh Scottish Ale Yeast', 70, 75, 'ALE', 38.4615, 'White Labs', 'WLP028', 'MEDIUM', 18, 21, 'Produces underlying esters of pear and melon which work well with hop and malt derived notes. Can beneutral at the low end of the fermentation temperature range or provide more esters at the higher range.', 'If you cannot find Edinburgh Scottish Ale Yeast (WLP028) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('English Ale Yeast', 63, 70, 'ALE', 23.0769, 'White Labs', 'WLP002', 'VERY_HIGH', 18, 20, 'This is a classic ESB strain from one of England''s largest independent breweries. Residual sweetnessaccentuates malt character and mild fruity esters, adding complexity to the flavor and aroma of finished beers.', 'If you cannot find English Ale Yeast (WLP002) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('French Saison Ale Yeast', 73, 80, 'ALE', 23.0769, 'White Labs', 'WLP590', 'MEDIUM', 21, 24, 'One of our most popular saison strains, it produces flavors and aromas of pear, apple and cracked pepper.This strain is a high attenuator producing a very dry and drinkable finishing beer.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('German Bock Lager Yeast', 70, 76, 'ALE', 38.4615, 'White Labs', 'WLP833', 'MEDIUM', 9, 13, 'From the Alps of southern Bavaria, this yeast produces a beer that is well-balanced between malt and hop character.This yeast is characterized by a malty finish, balanced aroma and great flocculation. It is a strong fermenter which', 'If you cannot find German Bock Lager Yeast (WLP833) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('German Lager Yeast', 74, 79, 'ALE', 23.0769, 'White Labs', 'WLP830', 'MEDIUM', 10, 13, 'Our most popular lager yeast, this strain is one of the most widely used lager strains in the world. It tends to produce clean and crisp beers with some accentuation of hop characteristics.', 'Märzen, Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('German/Kolsch Ale Yeast', 72, 78, 'ALE', 23.0769, 'White Labs', 'WLP029', 'MEDIUM', 18, 21, 'Sourced from a small brewpub in Cologne, Germany, this strain is fitting for German ales. Known foraccentuating hop flavor and bitterness while creating crisp, clean lager like characters.', 'If you cannot find German/Kolsch Ale Yeast (WLP029) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hefeweizen Ale Yeast', 72, 76, 'ALE', 23.0769, 'White Labs', 'WLP300', 'LOW', 20, 22, 'This popular German strain produces a high level of isoamyl acetate, giving the resulting beer notes of banana. With balanced phenol production, this strain produces notes of clove but remains banana forward.', 'Hefeweizen, Weissbier, Weizenbock, Roggenbier');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hefeweizen IV Ale Yeast', 73, 80, 'ALE', 23.0769, 'White Labs', 'WLP380', 'LOW', 19, 21, 'Produces clove-like phenols in the aroma and flavor while keeping banana flavors and aromas to a minimum. Creates refreshing citrus and apricot notes. This strain has low flocculation and minor sulfur production.', 'Hefeweizen, Weissbier, Weizenbock, Roggenbier');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('High Pressure Lager Yeast', 73, 82, 'ALE', 23.0769, 'White Labs', 'WLP925', 'MEDIUM', 17, 20, 'Used to ferment lager beer in one week. Ferment at room temperature; 62-68°F (17-20°C) under 1.0 bar (14.7 PSI)until final gravity is obtained, lager the beer at 35°F (2°C), 15 PSI, for 3-5 days to condition. Malt-forward and clean.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hornindal Kveik', 75, 82, 'KVEIK', 12.5, 'White Labs', 'WLP521', 'HIGH', 22, 37, 'Hornindal is a Kveik strain shared with the world by Terje Raftevold from Hornindal, Norway. It produces an intense tropical flavor and aroma with notes of fresh tangerine, mango, and pineapple, ideal to be used with fruit-forward hops.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Irish Ale Yeast', 69, 74, 'ALE', 38.4615, 'White Labs', 'WLP004', 'MEDIUM_HIGH', 18, 20, 'This yeast is from one of the oldest stout-producing breweries in the world. Medium attenuation helpswith a dry finish that promotes roasty notes.', 'If you cannot find Irish Ale Yeast (WLP004) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('London Ale Yeast', 67, 75, 'ALE', 23.0769, 'White Labs', 'WLP013', 'MEDIUM', 19, 22, 'Oak ester character makes this yeast well-suited for classic British beer styles. Medium flocculationallows attenuation up to 75% leaving beer dry while adding malt complexity and pushing hop bitterness.', 'If you cannot find London Ale Yeast (WLP013) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('London Fog Ale Yeast', 75, 82, 'ALE', 38.4615, 'White Labs', 'WLP066', 'MEDIUM_LOW', 18, 22, 'This is the go-to strain for New England-style IPAs. It leaves some residual sweetness, helping accentuateboth malt and hop flavors and aromas, while retaining a velvety mouthfeel. Produces a medium ester profile.', 'IPA, Pale Ale, Hazy IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Mexican Lager Yeast', 70, 78, 'ALE', 23.0769, 'White Labs', 'WLP940', 'MEDIUM', 10, 13, 'From Mexico City, this strain produces clean lager beers with a crisp finish. It keeps drinkability on the forefrontwhile allowing malt and hop flavors and aromas to be background notes.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Monastery Ale Yeast', 75, 80, 'ALE', 53.8462, 'White Labs', 'WLP500', 'MEDIUM_LOW', 18, 22, 'Sourced from a Belgian monastery, this strain produces characteristic notes of plum and cherry with a hint of bubble gum.', 'Belgian Ales, Tripel, Dubbel, Trappist');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Oktoberfest/Märzen Lager Yeast', 65, 73, 'ALE', 38.4615, 'White Labs', 'WLP820', 'MEDIUM', 11, 14, 'This strain is ideal for producing malty lagers. Residual sweetness further helps promote malt nuances while contributing to a balanced finish. Great for lagers with a wide gravity range.', 'Märzen, Lagers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Old Bavarian Lager Yeast', 66, 73, 'ALE', 38.4615, 'White Labs', 'WLP920', 'MEDIUM', 10, 13, 'From Southern Germany, this yeast finishes malty with a slight ester profile. Use in beers such as Oktoberfests,bocks, and dark lagers.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Opshaug Kveik Ale Yeast', 70, 80, 'KVEIK', 38.4615, 'White Labs', 'WLP518', 'HIGH', 25, 35, 'It is a clean fermenting yeast and has tolerated temperatures up to 95°F (35°C) while finishing fermentationwithin three to four days . The hop-forward, clean characteristics of this strain make it ideal for IPAs and pale ales.', 'Kveik, American IPA, Hazy IPA, American Pale Ale, Black IPA, Red IPA, Red Ale, Robust Porter, American Stout, Winter Seasonal Beer, English IPA, Extra Special Bitter, Bitter, Stout, Tropical, Blonde Ale, American Strong Ale, Cream Ale, American Amber Lager, American Brown Ale, White IPA, Imperial IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Pacific Ale Yeast', 65, 70, 'ALE', 23.0769, 'White Labs', 'WLP041', 'HIGH', 18, 20, 'Hailing from the Pacific Northwest, this strain is a mild ester producer while promoting malt character.This strain is a big ester producer, showcasing notes of cherry and apple. This strain''s characteristic lower', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Pilsner Lager Yeast', 72, 77, 'ALE', 23.0769, 'White Labs', 'WLP800', 'MEDIUM_HIGH', 10, 13, 'A classic pilsner strain from the Czech Republic, this strain produces a clean, crisp beer that''s somewhat drywith a malty finish.', 'If you cannot find Pilsner Lager Yeast (WLP800) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saccharomyces Bruxellensis Trois', 85, 0.0, 'ALE', 38.4615, 'White Labs', 'WLP644', 'LOW', 21, 29, 'This Belgian strain, traditionally used for wild yeast fermentations, produces a slightly tart beer with delicate mango and pineapple characteristics.', 'If you cannot find Saccharomyces Bruxellensis Trois (WLP644) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('San Diego Super Ale Yeast', 76, 83, 'ALE', 53.8462, 'White Labs', 'WLP090', 'MEDIUM_HIGH', 18, 20, 'A low ester producing strain, it''s known for quick fermentations and producing a neutral flavor and aromaprofile. Due to high attenuation, this strain produces very dry beers with increased perceived bitterness.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('San Francisco Lager Yeast', 65, 70, 'ALE', 38.4615, 'White Labs', 'WLP810', 'HIGH', 14, 18, 'A unique lager strain because it can ferment at a wide range of temperatures while retaining lager-like characteristics.This strain is traditionally used to brew the California common or steam beer styles.', 'If you cannot find San Francisco Lager Yeast (WLP810) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Southern German Lager Yeast', 68, 76, 'ALE', 23.0769, 'White Labs', 'WLP838', 'MEDIUM_HIGH', 10, 13, 'This yeast is characterized by a malty finish, balanced aroma and great flocculation. It is a strong fermenter which produces slight sulfur and low diacetyl during fermentation. This strain benefits from a diacetyl rest and conditioning.', 'If you cannot find Southern German Lager Yeast (WLP838) anywhere, you can substitute one of the following yeasts for a similiar result.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Super High Gravity Ale Yeast', 80, 100, 'ALE', 76.9231, 'White Labs', 'WLP099', 'MEDIUM', 18, 20, 'From England, this yeast can ferment up to 25% alcohol. Produces dry beer. Ideal for beers aging forextended periods of time. Produces more esters with increasing gravity. Malt dominates at lower gravities.', 'The functional properties of brewing yeasts have a direct impact on the performance, quality and economics of the resulting beer.');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('American Ale', 73, 77, 'ALE', 11, 'Wyeast', 'WY1056', 'MEDIUM_LOW', 16, 22, 'Very clean, crisp flavor characteristics with low fruitness and mild ester production. A very versatile yeast for styles that desire dominant malt and hop character. This strain makes a wonderful "House" strain. Mild citrus notes develop with cooler 60-66F (15-19C) fermentations. Normally requires filtration for bright beers.', 'Pale Ales, Amber Ales, IPAs, Brown Ales, Double IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('American Ale II', 72, 76, 'ALE', 10, 'Wyeast', 'WY1272', 'MEDIUM', 16, 22, 'With many of the best qualities that brewers look for when brewing American styles of beer, this strain''s performance is consistent and it makes great beer. This versatile strain is a very good choice for a House strain. Expect a soft, clean profile with hints of nut, and a slightly tart finish. Ferment at warmer temperatures to accentuate hop character with an increased fruitiness. Or, ferment cool for a clean, light citrus character. It attenuates well and is reliably flocculent, producing bright beer without filtration.', 'Blonde Ale, Pale Ale, IPA, Strong Ale, Brown Ale, Porter');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('American Lager', 73, 77, 'ALE', 9, 'Wyeast', 'WY2035', 'MEDIUM', 9, 14, 'A complex and aromatic strain that can be used for a variety of lager beers. This strain is an excellent choice for Pre-Prohibition Lagers, formerly known as Classic American Pilsners.', 'American Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('American Wheat', 74, 78, 'ALE', 10, 'Wyeast', 'WY1010', 'LOW', 14, 23, 'A strong fermenting, true top cropping yeast that produces a dry, slightly tart, crisp beer. Ideal for beers where low ester profile is desirable.', 'American Hefeweizen, Wheat, Cream Ale, Kolsch, Altbier, Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bavarian Lager', 73, 77, 'ALE', 9, 'Wyeast', 'WY2206', 'MEDIUM_HIGH', 8, 14, 'Used by many German breweries to produce rich, full-bodied, malty beers, this strain is a good choice for bocks and doppelbocks. A thorough diacetyl rest is recommended after fermentation is complete.', 'German Pilsner, Munich Dunkel, Lager, Märzen');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bavarian Wheat Blend', 73, 77, 'ALE', 10, 'Wyeast', 'WY3056', 'MEDIUM', 18, 23, 'This proprietary blend of a top-fermenting neutral ale strain and a Bavarian wheat strain is a great choice when a subtle German style wheat beer is desired. The complex esters and phenolics from the wheat strain are nicely softened and balanced by the neutral ale strain.', 'Weissbier, Wheats');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Abbey Style Ale', 74, 78, 'ALE', 12, 'Wyeast', 'WY1214', 'MEDIUM_LOW', 20, 26, 'A widely used and alcohol tolerant Abbey style yeast that is suitable for a variety of Belgian style ales. This strain produces a nice ester profile as well as slightly spicy alcohol notes. It can be slow to start; however, it attenuates well.', 'Strong Ale, Belgian Tripel, Belgian Ale, Witbier, Oktoberfest, Winter Beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Abbey Style Ale II', 73, 77, 'ALE', 12, 'Wyeast', 'WY1762', 'MEDIUM', 23, 25, 'An excellent yeast strain for use in Belgian dark strong ales. This strain has a relatively clean profile which allows a rich malt and distinctive ethanol character to shine. Delicate dried fruit esters can be produced when used at higher fermentation temperatures or in a high gravity wort.', 'Belgian Ales, Barleywine, Wee Heavy, Biere de Garde');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Ardennes', 72, 76, 'ALE', 12, 'Wyeast', 'WY3522', 'HIGH', 17, 24, 'One of the great and versatile strains for the production of classic Belgian style ales. This strain produces a beautiful balance of delicate fruit esters and subtle spicy notes, with neither one dominating. Unlike many other Belgian style strains, this strain is highly flocculent and results in bright beers.', 'Belgian Ales, Belgian Tripel, Belgian IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Dark Ale', 74, 79, 'ALE', 12, 'Wyeast', 'WY3822', 'MEDIUM', 18, 27, 'This unique Belgian ale yeast is a high acid producer with balanced ester and phenol production allowing a good expression of malt profile, especially the strong flavors of darker malts and sugars. High alcohol tolerance. Spicy, tart, and dry on the palate with a very complex finish.', 'Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian High Gravity', 74, 78, 'ALE', 11, 'Wyeast', 'WY3787', 'MEDIUM', 18, 26, 'A classic strain for brewing Belgian dubbel or Belgian tripel. This Abbey strain produces a nice balance of complex fruity esters and phenolics, making it desirable for use in other Belgian style ales as well. A flocculent, true top cropping yeast (additional headspace is recommended), that will work over a broad temperature range. This strain makes a great Belgian style house strain.', 'Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Lambic Blend', 70, 80, 'ALE', 11, 'Wyeast', 'WY3278', 'MEDIUM', 17, 24, 'This blend contains yeast and bacteria cultures important to the production of spontaneously fermented beers of the Lambic region. Specific proportions of a Belgian style ale strain, a sherry strain, two Brettanomyces strains, a Lactobacillus culture, and a Pediococcus culture produce the desirable flavor components of these beers as they are brewed in Brussels. Propagation of this culture is not recommended and will result in a change of the proportions of the individual components. This blend will produce a very dry beer due to the super-attenuative nature of the mixed cultures.', 'Lambic, Flanders Red Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Saison', 76, 80, 'ALE', 12, 'Wyeast', 'WY3724', 'LOW', 21, 35, 'This strain is the classic farmhouse ale yeast. A traditional yeast that is spicy with complex aromatics, including bubble gum. It is very tart and dry on the palate with a mild fruitiness. Expect a crisp, mildly acidic finish that will benefit from elevated fermentation temperatures. This strain is notorious for a rapid and vigorous start to fermentation, only to stick around 1.035 S.G. Fermentation will finish, given time and warm temperatures. Warm fermentation temperatures, at least 90 °F (32 °C), or the use of a secondary strain can accelerate attenuation.', 'Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Schelde Ale', 73, 77, 'ALE', 11, 'Wyeast', 'WY3655', 'MEDIUM', 17, 18, 'From the East Flanders - Antwerpen region of Belgium, this unique top-fermenting yeast produces complex, classic Belgian aromas and flavors that meld well with premium quality pale and crystal malts. Well-rounded and smooth textures are exhibited with a full bodied malty profile and mouthfeel.', 'Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Stout', 70, 85, 'ALE', 12, 'Wyeast', 'WY1581', 'MEDIUM', 18, 24, 'A very versatile ale strain from Belgium. Excellent for Belgian stouts and Belgian specialty ales. Ferments to dryness and produces moderate levels of esters without significant phenolic or spicy characteristics.', 'Belgian Ales, Belgian Tripel, Saison');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Strong Ale', 74, 78, 'ALE', 12, 'Wyeast', 'WY1388', 'LOW', 18, 27, 'The classic choice for brewing golden strong ales. This alcohol tolerant strain will produce a complex ester profile balanced nicely with subtle phenolics. Malt flavors and aromas will remain even with a well attenuated dry, tart finish. This strain is prone to stalling at approximately 1.035; racking or slight aeration will encourage it to finish fermentation.', 'Belgian Tripel, Belgian Style ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Style Blend', 75, 80, 'ALE', 12, 'Wyeast', 'WY3789', 'MEDIUM', 20, 29, 'A unique blend of Belgian Saccharomyces and Brettanomyces for emulating Trappist-style beer from the Florenville region in Belgium. Phenolics, mild fruitiness and complex spicy notes develop with increased fermentation temperatures. Subdued but classic "Brett" character.', 'Belgian Ales, Bretts');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Wheat', 72, 76, 'ALE', 12, 'Wyeast', 'WY3942', 'MEDIUM', 18, 23, 'Isolated from a small Belgian brewery, this strain produces beers with moderate esters and minimal phenolics. Apple, bubblegum and plum-like aromas blend nicely with malt and hops. This strain will finish dry with a hint of tartness.', 'Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Belgian Witbier', 72, 76, 'ALE', 11, 'Wyeast', 'WY3944', 'MEDIUM', 17, 24, 'This versatile witbier yeast strain can be used in a variety of Belgian style ales. This strain produces a complex flavor profile dominated by spicy phenolics with low to moderate ester production. It is a great strain choice when you want a delicate clove profile not to be overshadowed by esters. It will ferment fairly dry with a slightly tart finish that compliments the use of oats, malted and unmalted wheat. This strain is a true top cropping yeast requiring full fermentor headspace of 33%.', 'Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Berliner Weisse Blend', 73, 77, 'ALE', 6, 'Wyeast', 'WY3191', 'LOW', 20, 22, 'This blend includes a German ale strain with low ester formation and a dry, crisp finish. The Lactobacillus included produces moderate levels of acidity, and the unique Brettanomyces strain imparts a critical earthy characteristic that is indicative of a true Berliner Weisse. When this blend is used, expect a slow start to fermentation as the yeast and bacteria in the blend is balanced to allow proper acid production. It generally requires 3-6 months of aging to fully develop flavor characteristics. Use this blend with worts containing extremely low hopping rates.', 'Berliner Weiss, Lambic, Flanders Red Ale, Gose');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Bohemian Lager', 73, 77, 'ALE', 9, 'Wyeast', 'WY2124', 'MEDIUM_LOW', 7, 20, 'This Carlsberg type yeast is the most widely used lager strain in the world. This strain produces a distinct malty profile with some ester character and a crisp finish. A versatile strain, that is great to use with lagers or Pilsners for fermentations in the 45-55°F (8-12°C) range. It may also be used for Common beer production with fermentations at 65-68°F (18-20°C). A thorough diacetyl rest is recommended after fermentation is complete.', 'German Pils, Helles, Lager, Munich Dunkel, Marzen, Bock');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('British Ale', 73, 75, 'ALE', 10, 'Wyeast', 'WY1098', 'MEDIUM', 18, 22, 'This yeast allows malt and hop character to dominate the profile. It ferments dry and crisp, producing well-balanced beers with a clean and neutral finish. Ferments well down to 64°F (18°C).', 'Porters, Brown Ales, English IPAs, Blonde Ales, Scottish Heavy, Barleywines');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('British Ale II', 73, 76, 'ALE', 10, 'Wyeast', 'WY1335', 'HIGH', 17, 24, 'A classic British ale profile with good flocculation and malty flavor characteristics. It will finish crisp, clean and fairly dry.', 'Bitters, Strong Ale, Brown Ale, Porter, Stout, English IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('British Cask Ale', 74, 77, 'ALE', 9, 'Wyeast', 'WY1026', 'MEDIUM_HIGH', 17, 22, 'A great yeast choice for any cask-conditioned British Ale and one that is especially well suited for hoppy bitters, IPAs and Australian ales. Produces a nice malt profile, and finishes crisp and slightly tart. Low to moderate fruit ester producer that clears well without filtration.', 'Bitters, Brown Ales, IPAs, Blonde Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Budvar Lager', 71, 75, 'ALE', 9, 'Wyeast', 'WY2000', 'MEDIUM_HIGH', 9, 13, 'The Budvar style strain has a nice malty nose with subtle fruit tones and a rich malt profile on the palate. It finishes malty but dry, well balanced and crisp. Hop character comes through in the finish.', 'Lager, Helles');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Burton IPA Blend', 71, 74, 'ALE', 10, 'Wyeast', 'WY1203', 'MEDIUM_HIGH', 18, 23, 'The revival of interest in historic and classic English IPA styles calls for a specialized yeast. This blend highlights hop bitterness and aroma while still allowing full expression of authentic water profiles and pale malts. Low to moderate ester level can be manipulated through fermentation temperature and pitching rate. Palate finish is typically neutral to mildly fruity with some maltiness. Good flocculation characteristics make this an excellent candidate for cask conditioning.', 'English IPA, Bitters, Porters, Stouts');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('California Lager', 67, 71, 'ALE', 9, 'Wyeast', 'WY2112', 'HIGH', 14, 20, 'This strain is particularly well suited for producing California Common-style beers. It retains lager characteristics at temperatures up to 65 °F (18 °C) and produces malty, brilliantly clear beers. This strain is not recommended for cold temperature fermentation.', 'California Common, Cream Ale, Porter, Seasonal Beers, Pale Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Canadian/Belgian Ale', 75, 79, 'ALE', 12, 'Wyeast', 'WY3864', 'MEDIUM', 18, 27, 'This alcohol-tolerant strain produces complex and well-balanced Belgian Abbey-style ales. Banana and fruit esters are complemented nicely with mild levels of phenolics and hints of acidity. Ester levels may be elevated by increasing gravity and fermentation temperatures.', 'Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Czech Pils', 70, 74, 'ALE', 9, 'Wyeast', 'WY2278', 'MEDIUM_HIGH', 10, 14, 'Originating from the home of great Pilsners in the Czech Republic, this classic strain will finish dry and malty. It is the perfect choice for Bohemian-style Pilsners. Sulfur produced during fermentation can be reduced with warmer fermentation temperatures 58 °F (14 °C) and will dissipate with conditioning.', 'Lager, Bock, Munich Dunkel');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Danish Lager', 73, 77, 'ALE', 9, 'Wyeast', 'WY2042', 'LOW', 8, 13, 'This yeast is a good choice for Dortmund-style lagers. It will ferment crisp and dry with a soft, rounded profile that accentuates hop characteristics.', 'Helles, Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Denny''s Favorite 50 Ale', 74, 76, 'ALE', 10, 'Wyeast', 'WY1450', 'LOW', 16, 21, 'This terrific all-round yeast can be used for almost any beer style, and is a mainstay of one of our local homebrewers, Mr. Denny Conn. It is unique in that it produces a big mouthfeel and accentuates the malt, caramel, or fruit character of a beer without being sweet or under-attenuated.', 'Amber Ale, Barleywine, Pale Ale, Brown Ale, Red Ale, IPA, Stout, Porter, Cream Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('English Special Bitter', 68, 72, 'ALE', 9, 'Wyeast', 'WY1768', 'HIGH', 18, 22, 'A great yeast for malt-predominate ales. Produces light fruit and ethanol aromas along with soft, nutty flavors. Exhibits a mild malt profile with a neutral finish. Bright beers are easily achieved without any filtration. It is similar to our 1968 London ESB Ale but slightly less flocculent.', 'Bitters, English IPA, Pale Ale, Brown Ale, Blonde Ale, Stout');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('European Lager', 73, 77, 'ALE', 10, 'Wyeast', 'WY2247', 'LOW', 8, 13, 'This strain exhibits a very clean and dry flavor profile often found in aggressively-hopped lagers. Produces mild aromatics and slight sulfur notes typical of classic pilsners. This yeast is a good attenuator resulting in beers with a distinctively crisp finish.', 'German Pils, Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Farmhouse Ale', 74, 79, 'ALE', 12, 'Wyeast', 'WY3726', 'MEDIUM', 21, 29, 'This strain produces complex esters balanced with earthy/spicy notes. Slightly tart and dry with a peppery finish. A perfect strain for farmhouse ales and saisons.', 'Biere de Garde, Saison, Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Flanders Golden Ale', 74, 78, 'ALE', 12, 'Wyeast', 'WY3739', 'MEDIUM_LOW', 18, 27, 'This well-balanced strain from northern Belgium will produce moderate levels of both fruity esters and spicy phenols while finishing dry with a hint of malt. 3739-PC is a robust and versatile strain that performs nicely in a broad range of Belgian styles.', 'Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Forbidden Fruit', 72, 76, 'ALE', 12, 'Wyeast', 'WY3463', 'LOW', 17, 24, 'A widely-used strain in the production of Witbier and Grand Cru. This yeast will produce spicy phenolics which are balanced nicely by a complex ester profile. The subtle fruit character and dry tart finish will complement wheat malt, orange peel and spice additions typical of Wits.', 'Witbier, White IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('French Saison', 77, 83, 'ALE', 12, 'Wyeast', 'WY3711', 'LOW', 18, 25, 'A very versatile strain that produces Saison or farmhouse style beers as well as other Belgian style beers that are highly aromatic (estery), peppery, spicy and citrusy. This strain enhances the use of spices and aroma hops, and is extremely attenuative but leaves an unexpected silky and rich mouthfeel. This strain can also be used to re-start stuck fermentations or in high gravity beers.', 'Saison, Witbier, Belgian Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Gambrinus Style Lager', 71, 75, 'ALE', 9, 'Wyeast', 'WY2002', 'MEDIUM_HIGH', 9, 13, 'Czech-style lager strain with very mild floral aroma, nice lager character in nose. Malt dominates profile with subtle floral/fruit notes. Full, complex flavor profile with full mouthfeel. Finishes soft and smooth with nice lingering maltiness.', 'Lager, Helles, Czech Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('German Ale', 73, 77, 'ALE', 11, 'Wyeast', 'WY1007', 'LOW', 13, 20, 'A true top cropping yeast with low ester formation and a broad temperature range. Fermentation at higher temperatures may produce mild fruitiness. This powdery strain results in yeast that remains in suspension post fermentation. Beers mature rapidly, even when cold fermentation is used. Low or no detectable diacetyl.', 'Wheat, Berliner Weisse, Altbier, Kolsch, Lagers, Gose');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('German Wheat', 70, 76, 'ALE', 10, 'Wyeast', 'WY3333', 'HIGH', 17, 24, 'A highly flocculent German wheat beer strain that is the perfect choice for use in Kristallweizen. This yeast strain produces a beautiful and delicate balance of banana esters and clove phenolics similar to the popular Wyeast 3068. However, this strain will sediment rapidly, resulting in bright beer without filtration. The balance can be manipulated towards ester production through increasing fermentation temperature, increasing the wort density, and decreasing the pitch rate. Over pitching can result in a near complete loss of banana character. Sulfur is commonly produced, but will dissipate with conditioning.', 'Hefeweizen, Weissbier, Wheats, Bock');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Hella Bock Lager', 70, 74, 'ALE', 12, 'Wyeast', 'WY2487', 'MEDIUM', 9, 13, 'Direct from the Austrian Alps, this strain will produce rich, full-bodied and malty beers with a complex flavor profile and a great mouth feel. Attenuates well while still leaving plenty of malt character and body. Beers fermented with this strain will benefit from a temperature rise for a diacetyl rest at the end of primary fermentation.', 'Helles, Marzen, Munich Dunkel, Bock');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Irish Ale', 71, 75, 'ALE', 12, 'Wyeast', 'WY1084', 'MEDIUM', 17, 22, 'This versatile yeast ferments extremely well in dark worts. It is a good choice for most high gravity beers. Beers fermented in the lower temperature range produce a dry, crisp profile with subtle fruitiness. Fruit and complex esters will increase when fermentation temperatures are above 64°F (18°C).', 'Stouts, Red Ales, Porters, Double IPA, Wee Heavy, Scottish Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Kolsch', 73, 77, 'ALE', 10, 'Wyeast', 'WY2565', 'LOW', 13, 21, 'This strain is a classic, true top cropping yeast strain from a traditional brewery in Cologne, Germany. Beers will exhibit some of the fruity character of an ale, with a clean lager like profile. It produces low or no detectable levels of diacetyl. This yeast may also be used to produce quick-conditioning pseudo-lager beers and ferments well at cold 55-60 °F (13-16 °C) range. This powdery strain results in yeast that remain in suspension post fermentation. It requires filtration or additional settling time to produce bright beers.', 'Kolsch, Wheat, Cream Ale, Berliner Weisse, Fruit Beer, Amber Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Kolsch II', 73, 77, 'ALE', 10, 'Wyeast', 'WY2575', 'LOW', 13, 21, 'This authentic Kӧlsch strain from one of Germany''s leading brewing schools has a rich flavor profile which accentuates a soft malt finish. It has low or no detectable diacetyl production and will also ferment well at colder temperatures for fast lager type beers.', 'Kolsch, Altbier, Amber Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('London Ale', 73, 77, 'ALE', 11, 'Wyeast', 'WY1028', 'MEDIUM_LOW', 16, 22, 'A rich mineral profile that is bold and crisp with some fruitiness. Often used for higher gravity ales and when a high level of attenuation is desired.', 'Dark Mild, Brown Ales, Porters, Stouts, IPA, Pale Ales');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('London Ale III', 71, 75, 'ALE', 10, 'Wyeast', 'WY1318', 'HIGH', 18, 23, 'Originating from a traditional London brewery, this yeast has a wonderful malt and hop profile. It is a true top cropping strain with a fruity, very light and softly balanced palate. This strain will finish slightly sweet. London Ale III has become synonymous with the production of New England IPAs, also known as juicy or hazy IPAs, and balances well with the tropical fruit qualities from late and dry hop additions.', 'Hazy IPA, IPA, Bitters, Stout, Barleywine');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('London ESB Ale', 67, 71, 'ALE', 9, 'Wyeast', 'WY1968', 'HIGH', 18, 22, 'A very good cask conditioned ale strain, this extremely flocculent yeast produces distinctly malty beers. Attenuation levels are typically less than most other yeast strains which results in a slightly sweeter finish. Ales produced with this strain tend to be fruity, increasingly so with higher fermentation temperatures of 70-74 °F (21-23 °C). A thorough diacetyl rest is recommended after fermentation is complete. Bright beers are easily achieved within days without any filtration.', 'Bitters, English IPA, Dark Mild, Brown Ale, Strong Ale, Barleywine');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Munich Lager', 70, 74, 'ALE', 9, 'Wyeast', 'WY2308', 'MEDIUM', 9, 13, 'This is a unique strain, capable of producing fine lagers. It is very smooth, well-rounded and full-bodied. A thorough diacetyl rest is recommended after fermentation is complete.', 'Lager, Festbier, Marzen, Bock, Munich Dunkel');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Munich Lager II', 72, 74, 'ALE', 10, 'Wyeast', 'WY2352', 'MEDIUM', 11, 17, 'From a famous brewery in Munich, this strain is a low diacetyl and low sulfur aroma producer. An excellent choice for malt-driven lagers.', 'Helles, Munich Dunkel, Marzen, Bock');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('North American Lager', 70, 76, 'ALE', 9, 'Wyeast', 'WY2272', 'HIGH', 11, 14, 'A traditional culture of North American and Canadian lagers, light pilsners, and adjunct beers. Mildly malty profile, medium ester profile, well balanced. Malty finish.', 'Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Northwest Ale', 67, 71, 'ALE', 10, 'Wyeast', 'WY1332', 'HIGH', 18, 24, 'One of the classic ale strains from a Northwest U.S. Brewery. It produces a malty and mildly fruity ale with good depth and complexity.', 'Pale Ale, IPA, Strong Ale, Brown Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Octoberfest Lager Blend', 73, 77, 'ALE', 9, 'Wyeast', 'WY2633', 'MEDIUM_LOW', 7, 14, 'This blend of lager strains is designed to produce a rich, malty, complex and full bodied Octoberfest style beer. It attenuates well while leaving plenty of malt character and mouthfeel. This blend is low in sulfur production.', 'Festbier, Märzen, Vienna Lager, Rauchbier');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Old Ale Blend', 75, 80, 'ALE', 14, 'Wyeast', 'WY9097', 'MEDIUM', 20, 24, 'To bring in a bit of English brewing heritage we developed the Old Ale blend. It includes an attenuative ale strain along with a small amount of Brettanomyces. The blend will ferment well in dark worts, producing fruity beers with nice complexity. The Brettanomyces adds a pie cherry-like flavor and sourness during prolonged aging.', 'Strong Ale, Barleywine, Old Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Oud Bruin Ale Blend', 70, 80, 'ALE', 10, 'Wyeast', 'WY3209', 'MEDIUM', 27, 29, 'This exclusive sour blend is built for dark, malt-accented sour styles. Like 3763 Roeselare, it will create sharp acidity, but unlike 3763 it will leave the malt character intact, creating a balanced and complex end product. Excellent base for blending fruit in secondary (especially cherries or raspberries), and makes for an interesting Saison.', 'Sour Ale, Oud Bruin, Saison, Fruit Beer,');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Pacman', 72, 78, 'ALE', 12, 'Wyeast', 'WY1764', 'MEDIUM_HIGH', 16, 22, 'A versatile yeast strain from one of Oregon’s leading craft breweries. Pacman is alcohol tolerant, flocculent, attenuates well and will produce beers with little to no diacetyl. Very mild fruit complements a dry, mineral finish making this a fairly neutral strain. Pacman’s flavor profile and performance makes it a great choice for use in many different beer styles.', 'American Pale Ale, American Amber Ale, American Brown Ale, Brown Porter, Cream Ale, Irish Red Ale, Strong Scotch Ale, Dry Stout, American Stout, Russian Imperial Stout, American IPA, Imperial IPA, American Barleywine, Fruit Beer, Spice/Herb/or Vegetable Beer, Christmas/Winter Specialty Spice Beer, Other Smoked Beer, Wood-Aged Beer');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Pilsen Lager', 71, 75, 'ALE', 9, 'Wyeast', 'WY2007', 'MEDIUM', 9, 13, 'Wyeast 2007 is the classic American lager strain. This mild, neutral strain produces beers with a nice malty character and a smooth palate. It ferments dry and crisp with minimal sulfur or diacetyl. Beers from this strain exhibit the characteristics of the most popular lager in America.', 'American Lager, Lager, German Pils, Schwarzbier');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Pilsner Urquell H-Strain', 72, 76, 'ALE', 9, 'Wyeast', 'WY2001', 'MEDIUM_HIGH', 9, 13, 'With a mild fruit and floral aroma this strain has a very dry and clean palate with a full mouthfeel and nice subtle malt character. It has a very clean and neutral finish.', 'Czech Lager');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Ringwood Ale', 68, 72, 'ALE', 10, 'Wyeast', 'WY1187', 'HIGH', 18, 23, 'A top cropping yeast strain with unique fermentation and flavor characteristics. Expect distinct fruit esters with a malty, complex profile. Flocculation is high, and the beer will clear well without filtration. A thorough diacetyl rest is recommended after fermentation is complete. This strain can be a slow starter and fermenter.', 'Porter, Brown Ale, Stout, IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Rocky Mountain Lager', 70, 74, 'ALE', 9, 'Wyeast', 'WY2105', 'MEDIUM_HIGH', 9, 13, 'A lager yeast said to be born high in the Colorado Rockies, this strain ferments well at cooler temperatures and is perfect for all North American Lagers, light pilsners, and adjunct beers. 2105-PC will create well-balanced beers with a mild malty profile, medium esters, and an emphasis on the malt finish.', 'Lager, German Pils');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Roeselare Ale Blend', 80, 0.0, 'ALE', 11, 'Wyeast', 'WY3763', 'MEDIUM', 18, 29, 'Our blend of lambic cultures produce beer with a complex, earthy profile and a distinctive pie cherry sourness. Aging up to 18 months is required for a full flavor profile and acidity to develop. Specific proportions of a Belgian style ale strain, a sherry strain, two Brettanomyces strains, a Lactobacillus culture, and a Pediococcus culture produce the desirable flavor components of these beers as they are brewed in West Flanders. Propagation of this culture is not recommended and will result in a change of the proportions of the individual components. This blend will produce a very dry beer due to the super-attenuative nature of the mixed cultures.', 'Lambic, Flanders Red Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Saison-Brett Blend', 80, 90, 'ALE', 12, 'Wyeast', 'WY3031', 'LOW', 18, 27, 'A blend of two saison strains and Brettanomyces creates a dry and complex ale. Classic earthy and spicy farmhouse character meets tropical and stone fruit esters. Aging brings elevated Brett flavor. Expect high attenuation with this blend.', 'Saison, Brett, Sour Ale, Belgian Strong Ale');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Scottish Ale', 69, 73, 'ALE', 12, 'Wyeast', 'WY1728', 'HIGH', 13, 24, 'Our Scottish ale strain is ideally suited for the strong, malty ales of Scotland. This strain is very versatile, and is often used as a House strain as it ferments neutral and clean. Higher fermentation temperatures will result in an increased ester profile.', 'Scottish Ales, Wee Heavy, Stout, Double IPA, Barleywine');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Staro Prague Lager', 70, 74, 'ALE', 11, 'Wyeast', 'WY2782', 'MEDIUM', 10, 14, 'This yeast will help create medium to full body lagers with moderate fruit and bready malt flavors. The balance is slightly toward malt sweetness and will benefit from additional hop bittering. A fantastic strain for producing classic Bohemian lagers.', 'Lager, Helles, Czech Lager, Marzen, Munich Dunkel, Bock');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Thames Valley Ale', 72, 76, 'ALE', 10, 'Wyeast', 'WY1275', 'MEDIUM_LOW', 17, 22, 'This strain produces classic British bitters with a rich, complex flavor profile. The yeast has a light malt character, low fruitiness, low esters and is clean and well balanced.', 'Bitters, Altbier, Brown Ale, Porter, Stout');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Thames Valley Ale II', 72, 78, 'ALE', 10, 'Wyeast', 'WY1882', 'HIGH', 16, 21, 'This strain was originally sourced from a now defunct brewery on the banks of the River Thames outside of Oxford, England. Thames Valley II produces crisp, dry beers with a rich malt profile and moderate stone fruit esters. This attenuative strain is also highly flocculent resulting in bright beers not requiring filtration. A thorough diacetyl rest is recommended after fermentation is complete.', 'Bitters, Brown Ale, Altbier, Porter');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Weihenstephan Weizen', 73, 77, 'ALE', 10, 'Wyeast', 'WY3068', 'LOW', 18, 24, 'The classic and most popular German wheat beer strain used worldwide. This yeast strain produces a beautiful and delicate balance of banana esters and clove phenolics. The balance can be manipulated towards ester production through increasing the fermentation temperature, increasing the wort density, and decreasing the pitch rate. Over pitching can result in a near complete loss of banana character. Decreasing the ester level will allow a higher clove character to be perceived. Sulfur is commonly produced, but will dissipate with conditioning. This strain is very powdery and will remain in suspension for an extended amount of time following attenuation. This is true top cropping yeast and requires fermentor headspace of 33%.', 'Hefeweizen, Wheats, Weissbier, Fruit Beers');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('West Coast IPA', 73, 80, 'ALE', 10, 'Wyeast', 'WY1217', 'MEDIUM_HIGH', 17, 23, 'This strain is ideally suited to the production of West Coast-style American craft beers, especially pale, IPA, red, and specialties. Thorough attenuation, temperature tolerance, and good flocculation make this an easy strain to work with. Flavor is balanced neutral with mild ester formation at warmer temperatures, allowing hops, character malts, and flavorings to show through.', 'Pale Ales, Brown Ales, IPA, Scottish Light, Double IPA');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('West Yorkshire Ale', 67, 71, 'ALE', 9, 'Wyeast', 'WY1469', 'HIGH', 18, 22, 'This strain produces ales with a full chewy malt flavor and character, but finishes dry, producing famously balanced beers. Expect moderate nutty and stone-fruit esters. Best used for the production of cask-conditioned bitters, ESB and mild ales. Reliably flocculent, producing bright beer without filtration.', 'English IPA, Stout, Bitters');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Whitbread Ale', 68, 72, 'ALE', 10, 'Wyeast', 'WY1099', 'MEDIUM_HIGH', 18, 24, 'A mildly malty and slightly fruity fermentation profile. It is less tart and dry than Wyeast 1098 British Ale. With good flocculation characteristics, this yeast clears well without filtration. Low fermentation temperatures will produce a clean finish with a very low ester profile.', 'Brown Ale, Stout, English IPA, Blonde Ale, Bitters');
INSERT INTO yeasts (name, attenuation_min, attenuation_max, type, alcohol_tolerance, producer, product_id, flocculation, temp_min, temp_max, notes, best_for) VALUES ('Wyeast Bohemian Ale Blend', 71, 75, 'ALE', 11, 'Wyeast', 'WY1087', 'MEDIUM_HIGH', 18, 22, 'Formerly known as Wyeast Ale Blend 1540-PC, this is a blend of the best ale strains to provide quick starts, good flavor, and good flocculation. The profile of these strains provides a balanced finish for British and American style ales.', 'Pale Ales, Amber Ales, Brown Ales, IPAs, Double IPAs, Stouts');